-- V8: Seed ayahs juz21_25

INSERT INTO mst_ayah (surah_id, ayah_number, text_arabic, text_simple,
                      juz_number, hizb_number, manzil_number, page_number,
                      sajda, created_at, updated_at)
VALUES
((SELECT id FROM mst_surah WHERE surah_number = 29), 46, '۞ وَلَا تُجَٰدِلُوٓا۟ أَهْلَ ٱلْكِتَٰبِ إِلَّا بِٱلَّتِى هِىَ أَحْسَنُ إِلَّا ٱلَّذِينَ ظَلَمُوا۟ مِنْهُمْ ۖ وَقُولُوٓا۟ ءَامَنَّا بِٱلَّذِىٓ أُنزِلَ إِلَيْنَا وَأُنزِلَ إِلَيْكُمْ وَإِلَٰهُنَا وَإِلَٰهُكُمْ وَٰحِدٌۭ وَنَحْنُ لَهُۥ مُسْلِمُونَ', NULL, 21, 161, 5, 402, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 47, 'وَكَذَٰلِكَ أَنزَلْنَآ إِلَيْكَ ٱلْكِتَٰبَ ۚ فَٱلَّذِينَ ءَاتَيْنَٰهُمُ ٱلْكِتَٰبَ يُؤْمِنُونَ بِهِۦ ۖ وَمِنْ هَٰٓؤُلَآءِ مَن يُؤْمِنُ بِهِۦ ۚ وَمَا يَجْحَدُ بِـَٔايَٰتِنَآ إِلَّا ٱلْكَٰفِرُونَ', NULL, 21, 161, 5, 402, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 48, 'وَمَا كُنتَ تَتْلُوا۟ مِن قَبْلِهِۦ مِن كِتَٰبٍۢ وَلَا تَخُطُّهُۥ بِيَمِينِكَ ۖ إِذًۭا لَّٱرْتَابَ ٱلْمُبْطِلُونَ', NULL, 21, 161, 5, 402, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 49, 'بَلْ هُوَ ءَايَٰتٌۢ بَيِّنَٰتٌۭ فِى صُدُورِ ٱلَّذِينَ أُوتُوا۟ ٱلْعِلْمَ ۚ وَمَا يَجْحَدُ بِـَٔايَٰتِنَآ إِلَّا ٱلظَّٰلِمُونَ', NULL, 21, 161, 5, 402, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 50, 'وَقَالُوا۟ لَوْلَآ أُنزِلَ عَلَيْهِ ءَايَٰتٌۭ مِّن رَّبِّهِۦ ۖ قُلْ إِنَّمَا ٱلْءَايَٰتُ عِندَ ٱللَّهِ وَإِنَّمَآ أَنَا۠ نَذِيرٌۭ مُّبِينٌ', NULL, 21, 161, 5, 402, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 51, 'أَوَلَمْ يَكْفِهِمْ أَنَّآ أَنزَلْنَا عَلَيْكَ ٱلْكِتَٰبَ يُتْلَىٰ عَلَيْهِمْ ۚ إِنَّ فِى ذَٰلِكَ لَرَحْمَةًۭ وَذِكْرَىٰ لِقَوْمٍۢ يُؤْمِنُونَ', NULL, 21, 161, 5, 402, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 52, 'قُلْ كَفَىٰ بِٱللَّهِ بَيْنِى وَبَيْنَكُمْ شَهِيدًۭا ۖ يَعْلَمُ مَا فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۗ وَٱلَّذِينَ ءَامَنُوا۟ بِٱلْبَٰطِلِ وَكَفَرُوا۟ بِٱللَّهِ أُو۟لَٰٓئِكَ هُمُ ٱلْخَٰسِرُونَ', NULL, 21, 161, 5, 402, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 53, 'وَيَسْتَعْجِلُونَكَ بِٱلْعَذَابِ ۚ وَلَوْلَآ أَجَلٌۭ مُّسَمًّۭى لَّجَآءَهُمُ ٱلْعَذَابُ وَلَيَأْتِيَنَّهُم بَغْتَةًۭ وَهُمْ لَا يَشْعُرُونَ', NULL, 21, 161, 5, 403, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 54, 'يَسْتَعْجِلُونَكَ بِٱلْعَذَابِ وَإِنَّ جَهَنَّمَ لَمُحِيطَةٌۢ بِٱلْكَٰفِرِينَ', NULL, 21, 161, 5, 403, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 55, 'يَوْمَ يَغْشَىٰهُمُ ٱلْعَذَابُ مِن فَوْقِهِمْ وَمِن تَحْتِ أَرْجُلِهِمْ وَيَقُولُ ذُوقُوا۟ مَا كُنتُمْ تَعْمَلُونَ', NULL, 21, 161, 5, 403, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 56, 'يَٰعِبَادِىَ ٱلَّذِينَ ءَامَنُوٓا۟ إِنَّ أَرْضِى وَٰسِعَةٌۭ فَإِيَّٰىَ فَٱعْبُدُونِ', NULL, 21, 161, 5, 403, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 57, 'كُلُّ نَفْسٍۢ ذَآئِقَةُ ٱلْمَوْتِ ۖ ثُمَّ إِلَيْنَا تُرْجَعُونَ', NULL, 21, 161, 5, 403, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 58, 'وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ لَنُبَوِّئَنَّهُم مِّنَ ٱلْجَنَّةِ غُرَفًۭا تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ خَٰلِدِينَ فِيهَا ۚ نِعْمَ أَجْرُ ٱلْعَٰمِلِينَ', NULL, 21, 161, 5, 403, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 59, 'ٱلَّذِينَ صَبَرُوا۟ وَعَلَىٰ رَبِّهِمْ يَتَوَكَّلُونَ', NULL, 21, 161, 5, 403, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 60, 'وَكَأَيِّن مِّن دَآبَّةٍۢ لَّا تَحْمِلُ رِزْقَهَا ٱللَّهُ يَرْزُقُهَا وَإِيَّاكُمْ ۚ وَهُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ', NULL, 21, 161, 5, 403, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 61, 'وَلَئِن سَأَلْتَهُم مَّنْ خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ وَسَخَّرَ ٱلشَّمْسَ وَٱلْقَمَرَ لَيَقُولُنَّ ٱللَّهُ ۖ فَأَنَّىٰ يُؤْفَكُونَ', NULL, 21, 161, 5, 403, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 62, 'ٱللَّهُ يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ مِنْ عِبَادِهِۦ وَيَقْدِرُ لَهُۥٓ ۚ إِنَّ ٱللَّهَ بِكُلِّ شَىْءٍ عَلِيمٌۭ', NULL, 21, 161, 5, 403, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 63, 'وَلَئِن سَأَلْتَهُم مَّن نَّزَّلَ مِنَ ٱلسَّمَآءِ مَآءًۭ فَأَحْيَا بِهِ ٱلْأَرْضَ مِنۢ بَعْدِ مَوْتِهَا لَيَقُولُنَّ ٱللَّهُ ۚ قُلِ ٱلْحَمْدُ لِلَّهِ ۚ بَلْ أَكْثَرُهُمْ لَا يَعْقِلُونَ', NULL, 21, 161, 5, 403, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 64, 'وَمَا هَٰذِهِ ٱلْحَيَوٰةُ ٱلدُّنْيَآ إِلَّا لَهْوٌۭ وَلَعِبٌۭ ۚ وَإِنَّ ٱلدَّارَ ٱلْءَاخِرَةَ لَهِىَ ٱلْحَيَوَانُ ۚ لَوْ كَانُوا۟ يَعْلَمُونَ', NULL, 21, 161, 5, 404, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 65, 'فَإِذَا رَكِبُوا۟ فِى ٱلْفُلْكِ دَعَوُا۟ ٱللَّهَ مُخْلِصِينَ لَهُ ٱلدِّينَ فَلَمَّا نَجَّىٰهُمْ إِلَى ٱلْبَرِّ إِذَا هُمْ يُشْرِكُونَ', NULL, 21, 161, 5, 404, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 66, 'لِيَكْفُرُوا۟ بِمَآ ءَاتَيْنَٰهُمْ وَلِيَتَمَتَّعُوا۟ ۖ فَسَوْفَ يَعْلَمُونَ', NULL, 21, 161, 5, 404, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 67, 'أَوَلَمْ يَرَوْا۟ أَنَّا جَعَلْنَا حَرَمًا ءَامِنًۭا وَيُتَخَطَّفُ ٱلنَّاسُ مِنْ حَوْلِهِمْ ۚ أَفَبِٱلْبَٰطِلِ يُؤْمِنُونَ وَبِنِعْمَةِ ٱللَّهِ يَكْفُرُونَ', NULL, 21, 161, 5, 404, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 68, 'وَمَنْ أَظْلَمُ مِمَّنِ ٱفْتَرَىٰ عَلَى ٱللَّهِ كَذِبًا أَوْ كَذَّبَ بِٱلْحَقِّ لَمَّا جَآءَهُۥٓ ۚ أَلَيْسَ فِى جَهَنَّمَ مَثْوًۭى لِّلْكَٰفِرِينَ', NULL, 21, 161, 5, 404, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 29), 69, 'وَٱلَّذِينَ جَٰهَدُوا۟ فِينَا لَنَهْدِيَنَّهُمْ سُبُلَنَا ۚ وَإِنَّ ٱللَّهَ لَمَعَ ٱلْمُحْسِنِينَ', NULL, 21, 161, 5, 404, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ الٓمٓ', NULL, 21, 162, 5, 404, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 2, 'غُلِبَتِ ٱلرُّومُ', NULL, 21, 162, 5, 404, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 3, 'فِىٓ أَدْنَى ٱلْأَرْضِ وَهُم مِّنۢ بَعْدِ غَلَبِهِمْ سَيَغْلِبُونَ', NULL, 21, 162, 5, 404, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 4, 'فِى بِضْعِ سِنِينَ ۗ لِلَّهِ ٱلْأَمْرُ مِن قَبْلُ وَمِنۢ بَعْدُ ۚ وَيَوْمَئِذٍۢ يَفْرَحُ ٱلْمُؤْمِنُونَ', NULL, 21, 162, 5, 404, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 5, 'بِنَصْرِ ٱللَّهِ ۚ يَنصُرُ مَن يَشَآءُ ۖ وَهُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ', NULL, 21, 162, 5, 404, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 6, 'وَعْدَ ٱللَّهِ ۖ لَا يُخْلِفُ ٱللَّهُ وَعْدَهُۥ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ', NULL, 21, 162, 5, 405, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 7, 'يَعْلَمُونَ ظَٰهِرًۭا مِّنَ ٱلْحَيَوٰةِ ٱلدُّنْيَا وَهُمْ عَنِ ٱلْءَاخِرَةِ هُمْ غَٰفِلُونَ', NULL, 21, 162, 5, 405, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 8, 'أَوَلَمْ يَتَفَكَّرُوا۟ فِىٓ أَنفُسِهِم ۗ مَّا خَلَقَ ٱللَّهُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ وَمَا بَيْنَهُمَآ إِلَّا بِٱلْحَقِّ وَأَجَلٍۢ مُّسَمًّۭى ۗ وَإِنَّ كَثِيرًۭا مِّنَ ٱلنَّاسِ بِلِقَآئِ رَبِّهِمْ لَكَٰفِرُونَ', NULL, 21, 162, 5, 405, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 9, 'أَوَلَمْ يَسِيرُوا۟ فِى ٱلْأَرْضِ فَيَنظُرُوا۟ كَيْفَ كَانَ عَٰقِبَةُ ٱلَّذِينَ مِن قَبْلِهِمْ ۚ كَانُوٓا۟ أَشَدَّ مِنْهُمْ قُوَّةًۭ وَأَثَارُوا۟ ٱلْأَرْضَ وَعَمَرُوهَآ أَكْثَرَ مِمَّا عَمَرُوهَا وَجَآءَتْهُمْ رُسُلُهُم بِٱلْبَيِّنَٰتِ ۖ فَمَا كَانَ ٱللَّهُ لِيَظْلِمَهُمْ وَلَٰكِن كَانُوٓا۟ أَنفُسَهُمْ يَظْلِمُونَ', NULL, 21, 162, 5, 405, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 10, 'ثُمَّ كَانَ عَٰقِبَةَ ٱلَّذِينَ أَسَٰٓـُٔوا۟ ٱلسُّوٓأَىٰٓ أَن كَذَّبُوا۟ بِـَٔايَٰتِ ٱللَّهِ وَكَانُوا۟ بِهَا يَسْتَهْزِءُونَ', NULL, 21, 162, 5, 405, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 11, 'ٱللَّهُ يَبْدَؤُا۟ ٱلْخَلْقَ ثُمَّ يُعِيدُهُۥ ثُمَّ إِلَيْهِ تُرْجَعُونَ', NULL, 21, 162, 5, 405, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 12, 'وَيَوْمَ تَقُومُ ٱلسَّاعَةُ يُبْلِسُ ٱلْمُجْرِمُونَ', NULL, 21, 162, 5, 405, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 13, 'وَلَمْ يَكُن لَّهُم مِّن شُرَكَآئِهِمْ شُفَعَٰٓؤُا۟ وَكَانُوا۟ بِشُرَكَآئِهِمْ كَٰفِرِينَ', NULL, 21, 162, 5, 405, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 14, 'وَيَوْمَ تَقُومُ ٱلسَّاعَةُ يَوْمَئِذٍۢ يَتَفَرَّقُونَ', NULL, 21, 162, 5, 405, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 15, 'فَأَمَّا ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ فَهُمْ فِى رَوْضَةٍۢ يُحْبَرُونَ', NULL, 21, 162, 5, 405, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 16, 'وَأَمَّا ٱلَّذِينَ كَفَرُوا۟ وَكَذَّبُوا۟ بِـَٔايَٰتِنَا وَلِقَآئِ ٱلْءَاخِرَةِ فَأُو۟لَٰٓئِكَ فِى ٱلْعَذَابِ مُحْضَرُونَ', NULL, 21, 162, 5, 406, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 17, 'فَسُبْحَٰنَ ٱللَّهِ حِينَ تُمْسُونَ وَحِينَ تُصْبِحُونَ', NULL, 21, 162, 5, 406, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 18, 'وَلَهُ ٱلْحَمْدُ فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَعَشِيًّۭا وَحِينَ تُظْهِرُونَ', NULL, 21, 162, 5, 406, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 19, 'يُخْرِجُ ٱلْحَىَّ مِنَ ٱلْمَيِّتِ وَيُخْرِجُ ٱلْمَيِّتَ مِنَ ٱلْحَىِّ وَيُحْىِ ٱلْأَرْضَ بَعْدَ مَوْتِهَا ۚ وَكَذَٰلِكَ تُخْرَجُونَ', NULL, 21, 162, 5, 406, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 20, 'وَمِنْ ءَايَٰتِهِۦٓ أَنْ خَلَقَكُم مِّن تُرَابٍۢ ثُمَّ إِذَآ أَنتُم بَشَرٌۭ تَنتَشِرُونَ', NULL, 21, 162, 5, 406, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 21, 'وَمِنْ ءَايَٰتِهِۦٓ أَنْ خَلَقَ لَكُم مِّنْ أَنفُسِكُمْ أَزْوَٰجًۭا لِّتَسْكُنُوٓا۟ إِلَيْهَا وَجَعَلَ بَيْنَكُم مَّوَدَّةًۭ وَرَحْمَةً ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّقَوْمٍۢ يَتَفَكَّرُونَ', NULL, 21, 162, 5, 406, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 22, 'وَمِنْ ءَايَٰتِهِۦ خَلْقُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَٱخْتِلَٰفُ أَلْسِنَتِكُمْ وَأَلْوَٰنِكُمْ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّلْعَٰلِمِينَ', NULL, 21, 162, 5, 406, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 23, 'وَمِنْ ءَايَٰتِهِۦ مَنَامُكُم بِٱلَّيْلِ وَٱلنَّهَارِ وَٱبْتِغَآؤُكُم مِّن فَضْلِهِۦٓ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّقَوْمٍۢ يَسْمَعُونَ', NULL, 21, 162, 5, 406, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 24, 'وَمِنْ ءَايَٰتِهِۦ يُرِيكُمُ ٱلْبَرْقَ خَوْفًۭا وَطَمَعًۭا وَيُنَزِّلُ مِنَ ٱلسَّمَآءِ مَآءًۭ فَيُحْىِۦ بِهِ ٱلْأَرْضَ بَعْدَ مَوْتِهَآ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّقَوْمٍۢ يَعْقِلُونَ', NULL, 21, 162, 5, 406, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 25, 'وَمِنْ ءَايَٰتِهِۦٓ أَن تَقُومَ ٱلسَّمَآءُ وَٱلْأَرْضُ بِأَمْرِهِۦ ۚ ثُمَّ إِذَا دَعَاكُمْ دَعْوَةًۭ مِّنَ ٱلْأَرْضِ إِذَآ أَنتُمْ تَخْرُجُونَ', NULL, 21, 162, 5, 407, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 26, 'وَلَهُۥ مَن فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ كُلٌّۭ لَّهُۥ قَٰنِتُونَ', NULL, 21, 162, 5, 407, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 27, 'وَهُوَ ٱلَّذِى يَبْدَؤُا۟ ٱلْخَلْقَ ثُمَّ يُعِيدُهُۥ وَهُوَ أَهْوَنُ عَلَيْهِ ۚ وَلَهُ ٱلْمَثَلُ ٱلْأَعْلَىٰ فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ', NULL, 21, 162, 5, 407, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 28, 'ضَرَبَ لَكُم مَّثَلًۭا مِّنْ أَنفُسِكُمْ ۖ هَل لَّكُم مِّن مَّا مَلَكَتْ أَيْمَٰنُكُم مِّن شُرَكَآءَ فِى مَا رَزَقْنَٰكُمْ فَأَنتُمْ فِيهِ سَوَآءٌۭ تَخَافُونَهُمْ كَخِيفَتِكُمْ أَنفُسَكُمْ ۚ كَذَٰلِكَ نُفَصِّلُ ٱلْءَايَٰتِ لِقَوْمٍۢ يَعْقِلُونَ', NULL, 21, 162, 5, 407, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 29, 'بَلِ ٱتَّبَعَ ٱلَّذِينَ ظَلَمُوٓا۟ أَهْوَآءَهُم بِغَيْرِ عِلْمٍۢ ۖ فَمَن يَهْدِى مَنْ أَضَلَّ ٱللَّهُ ۖ وَمَا لَهُم مِّن نَّٰصِرِينَ', NULL, 21, 162, 5, 407, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 30, 'فَأَقِمْ وَجْهَكَ لِلدِّينِ حَنِيفًۭا ۚ فِطْرَتَ ٱللَّهِ ٱلَّتِى فَطَرَ ٱلنَّاسَ عَلَيْهَا ۚ لَا تَبْدِيلَ لِخَلْقِ ٱللَّهِ ۚ ذَٰلِكَ ٱلدِّينُ ٱلْقَيِّمُ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ', NULL, 21, 162, 5, 407, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 31, '۞ مُنِيبِينَ إِلَيْهِ وَٱتَّقُوهُ وَأَقِيمُوا۟ ٱلصَّلَوٰةَ وَلَا تَكُونُوا۟ مِنَ ٱلْمُشْرِكِينَ', NULL, 21, 163, 5, 407, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 32, 'مِنَ ٱلَّذِينَ فَرَّقُوا۟ دِينَهُمْ وَكَانُوا۟ شِيَعًۭا ۖ كُلُّ حِزْبٍۭ بِمَا لَدَيْهِمْ فَرِحُونَ', NULL, 21, 163, 5, 407, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 33, 'وَإِذَا مَسَّ ٱلنَّاسَ ضُرٌّۭ دَعَوْا۟ رَبَّهُم مُّنِيبِينَ إِلَيْهِ ثُمَّ إِذَآ أَذَاقَهُم مِّنْهُ رَحْمَةً إِذَا فَرِيقٌۭ مِّنْهُم بِرَبِّهِمْ يُشْرِكُونَ', NULL, 21, 163, 5, 408, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 34, 'لِيَكْفُرُوا۟ بِمَآ ءَاتَيْنَٰهُمْ ۚ فَتَمَتَّعُوا۟ فَسَوْفَ تَعْلَمُونَ', NULL, 21, 163, 5, 408, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 35, 'أَمْ أَنزَلْنَا عَلَيْهِمْ سُلْطَٰنًۭا فَهُوَ يَتَكَلَّمُ بِمَا كَانُوا۟ بِهِۦ يُشْرِكُونَ', NULL, 21, 163, 5, 408, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 36, 'وَإِذَآ أَذَقْنَا ٱلنَّاسَ رَحْمَةًۭ فَرِحُوا۟ بِهَا ۖ وَإِن تُصِبْهُمْ سَيِّئَةٌۢ بِمَا قَدَّمَتْ أَيْدِيهِمْ إِذَا هُمْ يَقْنَطُونَ', NULL, 21, 163, 5, 408, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 37, 'أَوَلَمْ يَرَوْا۟ أَنَّ ٱللَّهَ يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ وَيَقْدِرُ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّقَوْمٍۢ يُؤْمِنُونَ', NULL, 21, 163, 5, 408, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 38, 'فَـَٔاتِ ذَا ٱلْقُرْبَىٰ حَقَّهُۥ وَٱلْمِسْكِينَ وَٱبْنَ ٱلسَّبِيلِ ۚ ذَٰلِكَ خَيْرٌۭ لِّلَّذِينَ يُرِيدُونَ وَجْهَ ٱللَّهِ ۖ وَأُو۟لَٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ', NULL, 21, 163, 5, 408, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 39, 'وَمَآ ءَاتَيْتُم مِّن رِّبًۭا لِّيَرْبُوَا۟ فِىٓ أَمْوَٰلِ ٱلنَّاسِ فَلَا يَرْبُوا۟ عِندَ ٱللَّهِ ۖ وَمَآ ءَاتَيْتُم مِّن زَكَوٰةٍۢ تُرِيدُونَ وَجْهَ ٱللَّهِ فَأُو۟لَٰٓئِكَ هُمُ ٱلْمُضْعِفُونَ', NULL, 21, 163, 5, 408, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 40, 'ٱللَّهُ ٱلَّذِى خَلَقَكُمْ ثُمَّ رَزَقَكُمْ ثُمَّ يُمِيتُكُمْ ثُمَّ يُحْيِيكُمْ ۖ هَلْ مِن شُرَكَآئِكُم مَّن يَفْعَلُ مِن ذَٰلِكُم مِّن شَىْءٍۢ ۚ سُبْحَٰنَهُۥ وَتَعَٰلَىٰ عَمَّا يُشْرِكُونَ', NULL, 21, 163, 5, 408, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 41, 'ظَهَرَ ٱلْفَسَادُ فِى ٱلْبَرِّ وَٱلْبَحْرِ بِمَا كَسَبَتْ أَيْدِى ٱلنَّاسِ لِيُذِيقَهُم بَعْضَ ٱلَّذِى عَمِلُوا۟ لَعَلَّهُمْ يَرْجِعُونَ', NULL, 21, 163, 5, 408, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 42, 'قُلْ سِيرُوا۟ فِى ٱلْأَرْضِ فَٱنظُرُوا۟ كَيْفَ كَانَ عَٰقِبَةُ ٱلَّذِينَ مِن قَبْلُ ۚ كَانَ أَكْثَرُهُم مُّشْرِكِينَ', NULL, 21, 163, 5, 409, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 43, 'فَأَقِمْ وَجْهَكَ لِلدِّينِ ٱلْقَيِّمِ مِن قَبْلِ أَن يَأْتِىَ يَوْمٌۭ لَّا مَرَدَّ لَهُۥ مِنَ ٱللَّهِ ۖ يَوْمَئِذٍۢ يَصَّدَّعُونَ', NULL, 21, 163, 5, 409, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 44, 'مَن كَفَرَ فَعَلَيْهِ كُفْرُهُۥ ۖ وَمَنْ عَمِلَ صَٰلِحًۭا فَلِأَنفُسِهِمْ يَمْهَدُونَ', NULL, 21, 163, 5, 409, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 45, 'لِيَجْزِىَ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ مِن فَضْلِهِۦٓ ۚ إِنَّهُۥ لَا يُحِبُّ ٱلْكَٰفِرِينَ', NULL, 21, 163, 5, 409, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 46, 'وَمِنْ ءَايَٰتِهِۦٓ أَن يُرْسِلَ ٱلرِّيَاحَ مُبَشِّرَٰتٍۢ وَلِيُذِيقَكُم مِّن رَّحْمَتِهِۦ وَلِتَجْرِىَ ٱلْفُلْكُ بِأَمْرِهِۦ وَلِتَبْتَغُوا۟ مِن فَضْلِهِۦ وَلَعَلَّكُمْ تَشْكُرُونَ', NULL, 21, 163, 5, 409, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 47, 'وَلَقَدْ أَرْسَلْنَا مِن قَبْلِكَ رُسُلًا إِلَىٰ قَوْمِهِمْ فَجَآءُوهُم بِٱلْبَيِّنَٰتِ فَٱنتَقَمْنَا مِنَ ٱلَّذِينَ أَجْرَمُوا۟ ۖ وَكَانَ حَقًّا عَلَيْنَا نَصْرُ ٱلْمُؤْمِنِينَ', NULL, 21, 163, 5, 409, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 48, 'ٱللَّهُ ٱلَّذِى يُرْسِلُ ٱلرِّيَٰحَ فَتُثِيرُ سَحَابًۭا فَيَبْسُطُهُۥ فِى ٱلسَّمَآءِ كَيْفَ يَشَآءُ وَيَجْعَلُهُۥ كِسَفًۭا فَتَرَى ٱلْوَدْقَ يَخْرُجُ مِنْ خِلَٰلِهِۦ ۖ فَإِذَآ أَصَابَ بِهِۦ مَن يَشَآءُ مِنْ عِبَادِهِۦٓ إِذَا هُمْ يَسْتَبْشِرُونَ', NULL, 21, 163, 5, 409, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 49, 'وَإِن كَانُوا۟ مِن قَبْلِ أَن يُنَزَّلَ عَلَيْهِم مِّن قَبْلِهِۦ لَمُبْلِسِينَ', NULL, 21, 163, 5, 409, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 50, 'فَٱنظُرْ إِلَىٰٓ ءَاثَٰرِ رَحْمَتِ ٱللَّهِ كَيْفَ يُحْىِ ٱلْأَرْضَ بَعْدَ مَوْتِهَآ ۚ إِنَّ ذَٰلِكَ لَمُحْىِ ٱلْمَوْتَىٰ ۖ وَهُوَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ', NULL, 21, 163, 5, 409, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 51, 'وَلَئِنْ أَرْسَلْنَا رِيحًۭا فَرَأَوْهُ مُصْفَرًّۭا لَّظَلُّوا۟ مِنۢ بَعْدِهِۦ يَكْفُرُونَ', NULL, 21, 163, 5, 410, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 52, 'فَإِنَّكَ لَا تُسْمِعُ ٱلْمَوْتَىٰ وَلَا تُسْمِعُ ٱلصُّمَّ ٱلدُّعَآءَ إِذَا وَلَّوْا۟ مُدْبِرِينَ', NULL, 21, 163, 5, 410, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 53, 'وَمَآ أَنتَ بِهَٰدِ ٱلْعُمْىِ عَن ضَلَٰلَتِهِمْ ۖ إِن تُسْمِعُ إِلَّا مَن يُؤْمِنُ بِـَٔايَٰتِنَا فَهُم مُّسْلِمُونَ', NULL, 21, 163, 5, 410, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 54, '۞ ٱللَّهُ ٱلَّذِى خَلَقَكُم مِّن ضَعْفٍۢ ثُمَّ جَعَلَ مِنۢ بَعْدِ ضَعْفٍۢ قُوَّةًۭ ثُمَّ جَعَلَ مِنۢ بَعْدِ قُوَّةٍۢ ضَعْفًۭا وَشَيْبَةًۭ ۚ يَخْلُقُ مَا يَشَآءُ ۖ وَهُوَ ٱلْعَلِيمُ ٱلْقَدِيرُ', NULL, 21, 164, 5, 410, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 55, 'وَيَوْمَ تَقُومُ ٱلسَّاعَةُ يُقْسِمُ ٱلْمُجْرِمُونَ مَا لَبِثُوا۟ غَيْرَ سَاعَةٍۢ ۚ كَذَٰلِكَ كَانُوا۟ يُؤْفَكُونَ', NULL, 21, 164, 5, 410, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 56, 'وَقَالَ ٱلَّذِينَ أُوتُوا۟ ٱلْعِلْمَ وَٱلْإِيمَٰنَ لَقَدْ لَبِثْتُمْ فِى كِتَٰبِ ٱللَّهِ إِلَىٰ يَوْمِ ٱلْبَعْثِ ۖ فَهَٰذَا يَوْمُ ٱلْبَعْثِ وَلَٰكِنَّكُمْ كُنتُمْ لَا تَعْلَمُونَ', NULL, 21, 164, 5, 410, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 57, 'فَيَوْمَئِذٍۢ لَّا يَنفَعُ ٱلَّذِينَ ظَلَمُوا۟ مَعْذِرَتُهُمْ وَلَا هُمْ يُسْتَعْتَبُونَ', NULL, 21, 164, 5, 410, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 58, 'وَلَقَدْ ضَرَبْنَا لِلنَّاسِ فِى هَٰذَا ٱلْقُرْءَانِ مِن كُلِّ مَثَلٍۢ ۚ وَلَئِن جِئْتَهُم بِـَٔايَةٍۢ لَّيَقُولَنَّ ٱلَّذِينَ كَفَرُوٓا۟ إِنْ أَنتُمْ إِلَّا مُبْطِلُونَ', NULL, 21, 164, 5, 410, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 59, 'كَذَٰلِكَ يَطْبَعُ ٱللَّهُ عَلَىٰ قُلُوبِ ٱلَّذِينَ لَا يَعْلَمُونَ', NULL, 21, 164, 5, 410, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 30), 60, 'فَٱصْبِرْ إِنَّ وَعْدَ ٱللَّهِ حَقٌّۭ ۖ وَلَا يَسْتَخِفَّنَّكَ ٱلَّذِينَ لَا يُوقِنُونَ', NULL, 21, 164, 5, 410, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ الٓمٓ', NULL, 21, 164, 5, 411, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 2, 'تِلْكَ ءَايَٰتُ ٱلْكِتَٰبِ ٱلْحَكِيمِ', NULL, 21, 164, 5, 411, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 3, 'هُدًۭى وَرَحْمَةًۭ لِّلْمُحْسِنِينَ', NULL, 21, 164, 5, 411, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 4, 'ٱلَّذِينَ يُقِيمُونَ ٱلصَّلَوٰةَ وَيُؤْتُونَ ٱلزَّكَوٰةَ وَهُم بِٱلْءَاخِرَةِ هُمْ يُوقِنُونَ', NULL, 21, 164, 5, 411, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 5, 'أُو۟لَٰٓئِكَ عَلَىٰ هُدًۭى مِّن رَّبِّهِمْ ۖ وَأُو۟لَٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ', NULL, 21, 164, 5, 411, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 6, 'وَمِنَ ٱلنَّاسِ مَن يَشْتَرِى لَهْوَ ٱلْحَدِيثِ لِيُضِلَّ عَن سَبِيلِ ٱللَّهِ بِغَيْرِ عِلْمٍۢ وَيَتَّخِذَهَا هُزُوًا ۚ أُو۟لَٰٓئِكَ لَهُمْ عَذَابٌۭ مُّهِينٌۭ', NULL, 21, 164, 5, 411, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 7, 'وَإِذَا تُتْلَىٰ عَلَيْهِ ءَايَٰتُنَا وَلَّىٰ مُسْتَكْبِرًۭا كَأَن لَّمْ يَسْمَعْهَا كَأَنَّ فِىٓ أُذُنَيْهِ وَقْرًۭا ۖ فَبَشِّرْهُ بِعَذَابٍ أَلِيمٍ', NULL, 21, 164, 5, 411, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 8, 'إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ لَهُمْ جَنَّٰتُ ٱلنَّعِيمِ', NULL, 21, 164, 5, 411, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 9, 'خَٰلِدِينَ فِيهَا ۖ وَعْدَ ٱللَّهِ حَقًّۭا ۚ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ', NULL, 21, 164, 5, 411, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 10, 'خَلَقَ ٱلسَّمَٰوَٰتِ بِغَيْرِ عَمَدٍۢ تَرَوْنَهَا ۖ وَأَلْقَىٰ فِى ٱلْأَرْضِ رَوَٰسِىَ أَن تَمِيدَ بِكُمْ وَبَثَّ فِيهَا مِن كُلِّ دَآبَّةٍۢ ۚ وَأَنزَلْنَا مِنَ ٱلسَّمَآءِ مَآءًۭ فَأَنۢبَتْنَا فِيهَا مِن كُلِّ زَوْجٍۢ كَرِيمٍ', NULL, 21, 164, 5, 411, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 11, 'هَٰذَا خَلْقُ ٱللَّهِ فَأَرُونِى مَاذَا خَلَقَ ٱلَّذِينَ مِن دُونِهِۦ ۚ بَلِ ٱلظَّٰلِمُونَ فِى ضَلَٰلٍۢ مُّبِينٍۢ', NULL, 21, 164, 5, 411, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 12, 'وَلَقَدْ ءَاتَيْنَا لُقْمَٰنَ ٱلْحِكْمَةَ أَنِ ٱشْكُرْ لِلَّهِ ۚ وَمَن يَشْكُرْ فَإِنَّمَا يَشْكُرُ لِنَفْسِهِۦ ۖ وَمَن كَفَرَ فَإِنَّ ٱللَّهَ غَنِىٌّ حَمِيدٌۭ', NULL, 21, 164, 5, 412, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 13, 'وَإِذْ قَالَ لُقْمَٰنُ لِٱبْنِهِۦ وَهُوَ يَعِظُهُۥ يَٰبُنَىَّ لَا تُشْرِكْ بِٱللَّهِ ۖ إِنَّ ٱلشِّرْكَ لَظُلْمٌ عَظِيمٌۭ', NULL, 21, 164, 5, 412, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 14, 'وَوَصَّيْنَا ٱلْإِنسَٰنَ بِوَٰلِدَيْهِ حَمَلَتْهُ أُمُّهُۥ وَهْنًا عَلَىٰ وَهْنٍۢ وَفِصَٰلُهُۥ فِى عَامَيْنِ أَنِ ٱشْكُرْ لِى وَلِوَٰلِدَيْكَ إِلَىَّ ٱلْمَصِيرُ', NULL, 21, 164, 5, 412, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 15, 'وَإِن جَٰهَدَاكَ عَلَىٰٓ أَن تُشْرِكَ بِى مَا لَيْسَ لَكَ بِهِۦ عِلْمٌۭ فَلَا تُطِعْهُمَا ۖ وَصَاحِبْهُمَا فِى ٱلدُّنْيَا مَعْرُوفًۭا ۖ وَٱتَّبِعْ سَبِيلَ مَنْ أَنَابَ إِلَىَّ ۚ ثُمَّ إِلَىَّ مَرْجِعُكُمْ فَأُنَبِّئُكُم بِمَا كُنتُمْ تَعْمَلُونَ', NULL, 21, 164, 5, 412, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 16, 'يَٰبُنَىَّ إِنَّهَآ إِن تَكُ مِثْقَالَ حَبَّةٍۢ مِّنْ خَرْدَلٍۢ فَتَكُن فِى صَخْرَةٍ أَوْ فِى ٱلسَّمَٰوَٰتِ أَوْ فِى ٱلْأَرْضِ يَأْتِ بِهَا ٱللَّهُ ۚ إِنَّ ٱللَّهَ لَطِيفٌ خَبِيرٌۭ', NULL, 21, 164, 5, 412, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 17, 'يَٰبُنَىَّ أَقِمِ ٱلصَّلَوٰةَ وَأْمُرْ بِٱلْمَعْرُوفِ وَٱنْهَ عَنِ ٱلْمُنكَرِ وَٱصْبِرْ عَلَىٰ مَآ أَصَابَكَ ۖ إِنَّ ذَٰلِكَ مِنْ عَزْمِ ٱلْأُمُورِ', NULL, 21, 164, 5, 412, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 18, 'وَلَا تُصَعِّرْ خَدَّكَ لِلنَّاسِ وَلَا تَمْشِ فِى ٱلْأَرْضِ مَرَحًا ۖ إِنَّ ٱللَّهَ لَا يُحِبُّ كُلَّ مُخْتَالٍۢ فَخُورٍۢ', NULL, 21, 164, 5, 412, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 19, 'وَٱقْصِدْ فِى مَشْيِكَ وَٱغْضُضْ مِن صَوْتِكَ ۚ إِنَّ أَنكَرَ ٱلْأَصْوَٰتِ لَصَوْتُ ٱلْحَمِيرِ', NULL, 21, 164, 5, 412, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 20, 'أَلَمْ تَرَوْا۟ أَنَّ ٱللَّهَ سَخَّرَ لَكُم مَّا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ وَأَسْبَغَ عَلَيْكُمْ نِعَمَهُۥ ظَٰهِرَةًۭ وَبَاطِنَةًۭ ۗ وَمِنَ ٱلنَّاسِ مَن يُجَٰدِلُ فِى ٱللَّهِ بِغَيْرِ عِلْمٍۢ وَلَا هُدًۭى وَلَا كِتَٰبٍۢ مُّنِيرٍۢ', NULL, 21, 164, 5, 413, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 21, 'وَإِذَا قِيلَ لَهُمُ ٱتَّبِعُوا۟ مَآ أَنزَلَ ٱللَّهُ قَالُوا۟ بَلْ نَتَّبِعُ مَا وَجَدْنَا عَلَيْهِ ءَابَآءَنَآ ۚ أَوَلَوْ كَانَ ٱلشَّيْطَٰنُ يَدْعُوهُمْ إِلَىٰ عَذَابِ ٱلسَّعِيرِ', NULL, 21, 164, 5, 413, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 22, '۞ وَمَن يُسْلِمْ وَجْهَهُۥٓ إِلَى ٱللَّهِ وَهُوَ مُحْسِنٌۭ فَقَدِ ٱسْتَمْسَكَ بِٱلْعُرْوَةِ ٱلْوُثْقَىٰ ۗ وَإِلَى ٱللَّهِ عَٰقِبَةُ ٱلْأُمُورِ', NULL, 21, 165, 5, 413, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 23, 'وَمَن كَفَرَ فَلَا يَحْزُنكَ كُفْرُهُۥٓ ۚ إِلَيْنَا مَرْجِعُهُمْ فَنُنَبِّئُهُم بِمَا عَمِلُوٓا۟ ۚ إِنَّ ٱللَّهَ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ', NULL, 21, 165, 5, 413, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 24, 'نُمَتِّعُهُمْ قَلِيلًۭا ثُمَّ نَضْطَرُّهُمْ إِلَىٰ عَذَابٍ غَلِيظٍۢ', NULL, 21, 165, 5, 413, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 25, 'وَلَئِن سَأَلْتَهُم مَّنْ خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ لَيَقُولُنَّ ٱللَّهُ ۚ قُلِ ٱلْحَمْدُ لِلَّهِ ۚ بَلْ أَكْثَرُهُمْ لَا يَعْلَمُونَ', NULL, 21, 165, 5, 413, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 26, 'لِلَّهِ مَا فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ إِنَّ ٱللَّهَ هُوَ ٱلْغَنِىُّ ٱلْحَمِيدُ', NULL, 21, 165, 5, 413, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 27, 'وَلَوْ أَنَّمَا فِى ٱلْأَرْضِ مِن شَجَرَةٍ أَقْلَٰمٌۭ وَٱلْبَحْرُ يَمُدُّهُۥ مِنۢ بَعْدِهِۦ سَبْعَةُ أَبْحُرٍۢ مَّا نَفِدَتْ كَلِمَٰتُ ٱللَّهِ ۗ إِنَّ ٱللَّهَ عَزِيزٌ حَكِيمٌۭ', NULL, 21, 165, 5, 413, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 28, 'مَّا خَلْقُكُمْ وَلَا بَعْثُكُمْ إِلَّا كَنَفْسٍۢ وَٰحِدَةٍ ۗ إِنَّ ٱللَّهَ سَمِيعٌۢ بَصِيرٌ', NULL, 21, 165, 5, 413, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 29, 'أَلَمْ تَرَ أَنَّ ٱللَّهَ يُولِجُ ٱلَّيْلَ فِى ٱلنَّهَارِ وَيُولِجُ ٱلنَّهَارَ فِى ٱلَّيْلِ وَسَخَّرَ ٱلشَّمْسَ وَٱلْقَمَرَ كُلٌّۭ يَجْرِىٓ إِلَىٰٓ أَجَلٍۢ مُّسَمًّۭى وَأَنَّ ٱللَّهَ بِمَا تَعْمَلُونَ خَبِيرٌۭ', NULL, 21, 165, 5, 414, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 30, 'ذَٰلِكَ بِأَنَّ ٱللَّهَ هُوَ ٱلْحَقُّ وَأَنَّ مَا يَدْعُونَ مِن دُونِهِ ٱلْبَٰطِلُ وَأَنَّ ٱللَّهَ هُوَ ٱلْعَلِىُّ ٱلْكَبِيرُ', NULL, 21, 165, 5, 414, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 31, 'أَلَمْ تَرَ أَنَّ ٱلْفُلْكَ تَجْرِى فِى ٱلْبَحْرِ بِنِعْمَتِ ٱللَّهِ لِيُرِيَكُم مِّنْ ءَايَٰتِهِۦٓ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّكُلِّ صَبَّارٍۢ شَكُورٍۢ', NULL, 21, 165, 5, 414, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 32, 'وَإِذَا غَشِيَهُم مَّوْجٌۭ كَٱلظُّلَلِ دَعَوُا۟ ٱللَّهَ مُخْلِصِينَ لَهُ ٱلدِّينَ فَلَمَّا نَجَّىٰهُمْ إِلَى ٱلْبَرِّ فَمِنْهُم مُّقْتَصِدٌۭ ۚ وَمَا يَجْحَدُ بِـَٔايَٰتِنَآ إِلَّا كُلُّ خَتَّارٍۢ كَفُورٍۢ', NULL, 21, 165, 5, 414, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 33, 'يَٰٓأَيُّهَا ٱلنَّاسُ ٱتَّقُوا۟ رَبَّكُمْ وَٱخْشَوْا۟ يَوْمًۭا لَّا يَجْزِى وَالِدٌ عَن وَلَدِهِۦ وَلَا مَوْلُودٌ هُوَ جَازٍ عَن وَالِدِهِۦ شَيْـًٔا ۚ إِنَّ وَعْدَ ٱللَّهِ حَقٌّۭ ۖ فَلَا تَغُرَّنَّكُمُ ٱلْحَيَوٰةُ ٱلدُّنْيَا وَلَا يَغُرَّنَّكُم بِٱللَّهِ ٱلْغَرُورُ', NULL, 21, 165, 5, 414, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 31), 34, 'إِنَّ ٱللَّهَ عِندَهُۥ عِلْمُ ٱلسَّاعَةِ وَيُنَزِّلُ ٱلْغَيْثَ وَيَعْلَمُ مَا فِى ٱلْأَرْحَامِ ۖ وَمَا تَدْرِى نَفْسٌۭ مَّاذَا تَكْسِبُ غَدًۭا ۖ وَمَا تَدْرِى نَفْسٌۢ بِأَىِّ أَرْضٍۢ تَمُوتُ ۚ إِنَّ ٱللَّهَ عَلِيمٌ خَبِيرٌۢ', NULL, 21, 165, 5, 414, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ الٓمٓ', NULL, 21, 165, 5, 415, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 2, 'تَنزِيلُ ٱلْكِتَٰبِ لَا رَيْبَ فِيهِ مِن رَّبِّ ٱلْعَٰلَمِينَ', NULL, 21, 165, 5, 415, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 3, 'أَمْ يَقُولُونَ ٱفْتَرَىٰهُ ۚ بَلْ هُوَ ٱلْحَقُّ مِن رَّبِّكَ لِتُنذِرَ قَوْمًۭا مَّآ أَتَىٰهُم مِّن نَّذِيرٍۢ مِّن قَبْلِكَ لَعَلَّهُمْ يَهْتَدُونَ', NULL, 21, 165, 5, 415, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 4, 'ٱللَّهُ ٱلَّذِى خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ وَمَا بَيْنَهُمَا فِى سِتَّةِ أَيَّامٍۢ ثُمَّ ٱسْتَوَىٰ عَلَى ٱلْعَرْشِ ۖ مَا لَكُم مِّن دُونِهِۦ مِن وَلِىٍّۢ وَلَا شَفِيعٍ ۚ أَفَلَا تَتَذَكَّرُونَ', NULL, 21, 165, 5, 415, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 5, 'يُدَبِّرُ ٱلْأَمْرَ مِنَ ٱلسَّمَآءِ إِلَى ٱلْأَرْضِ ثُمَّ يَعْرُجُ إِلَيْهِ فِى يَوْمٍۢ كَانَ مِقْدَارُهُۥٓ أَلْفَ سَنَةٍۢ مِّمَّا تَعُدُّونَ', NULL, 21, 165, 5, 415, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 6, 'ذَٰلِكَ عَٰلِمُ ٱلْغَيْبِ وَٱلشَّهَٰدَةِ ٱلْعَزِيزُ ٱلرَّحِيمُ', NULL, 21, 165, 5, 415, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 7, 'ٱلَّذِىٓ أَحْسَنَ كُلَّ شَىْءٍ خَلَقَهُۥ ۖ وَبَدَأَ خَلْقَ ٱلْإِنسَٰنِ مِن طِينٍۢ', NULL, 21, 165, 5, 415, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 8, 'ثُمَّ جَعَلَ نَسْلَهُۥ مِن سُلَٰلَةٍۢ مِّن مَّآءٍۢ مَّهِينٍۢ', NULL, 21, 165, 5, 415, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 9, 'ثُمَّ سَوَّىٰهُ وَنَفَخَ فِيهِ مِن رُّوحِهِۦ ۖ وَجَعَلَ لَكُمُ ٱلسَّمْعَ وَٱلْأَبْصَٰرَ وَٱلْأَفْـِٔدَةَ ۚ قَلِيلًۭا مَّا تَشْكُرُونَ', NULL, 21, 165, 5, 415, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 10, 'وَقَالُوٓا۟ أَءِذَا ضَلَلْنَا فِى ٱلْأَرْضِ أَءِنَّا لَفِى خَلْقٍۢ جَدِيدٍۭ ۚ بَلْ هُم بِلِقَآءِ رَبِّهِمْ كَٰفِرُونَ', NULL, 21, 165, 5, 415, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 11, '۞ قُلْ يَتَوَفَّىٰكُم مَّلَكُ ٱلْمَوْتِ ٱلَّذِى وُكِّلَ بِكُمْ ثُمَّ إِلَىٰ رَبِّكُمْ تُرْجَعُونَ', NULL, 21, 166, 5, 415, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 12, 'وَلَوْ تَرَىٰٓ إِذِ ٱلْمُجْرِمُونَ نَاكِسُوا۟ رُءُوسِهِمْ عِندَ رَبِّهِمْ رَبَّنَآ أَبْصَرْنَا وَسَمِعْنَا فَٱرْجِعْنَا نَعْمَلْ صَٰلِحًا إِنَّا مُوقِنُونَ', NULL, 21, 166, 5, 416, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 13, 'وَلَوْ شِئْنَا لَءَاتَيْنَا كُلَّ نَفْسٍ هُدَىٰهَا وَلَٰكِنْ حَقَّ ٱلْقَوْلُ مِنِّى لَأَمْلَأَنَّ جَهَنَّمَ مِنَ ٱلْجِنَّةِ وَٱلنَّاسِ أَجْمَعِينَ', NULL, 21, 166, 5, 416, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 14, 'فَذُوقُوا۟ بِمَا نَسِيتُمْ لِقَآءَ يَوْمِكُمْ هَٰذَآ إِنَّا نَسِينَٰكُمْ ۖ وَذُوقُوا۟ عَذَابَ ٱلْخُلْدِ بِمَا كُنتُمْ تَعْمَلُونَ', NULL, 21, 166, 5, 416, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 15, 'إِنَّمَا يُؤْمِنُ بِـَٔايَٰتِنَا ٱلَّذِينَ إِذَا ذُكِّرُوا۟ بِهَا خَرُّوا۟ سُجَّدًۭا وَسَبَّحُوا۟ بِحَمْدِ رَبِّهِمْ وَهُمْ لَا يَسْتَكْبِرُونَ ۩', NULL, 21, 166, 5, 416, true, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 16, 'تَتَجَافَىٰ جُنُوبُهُمْ عَنِ ٱلْمَضَاجِعِ يَدْعُونَ رَبَّهُمْ خَوْفًۭا وَطَمَعًۭا وَمِمَّا رَزَقْنَٰهُمْ يُنفِقُونَ', NULL, 21, 166, 5, 416, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 17, 'فَلَا تَعْلَمُ نَفْسٌۭ مَّآ أُخْفِىَ لَهُم مِّن قُرَّةِ أَعْيُنٍۢ جَزَآءًۢ بِمَا كَانُوا۟ يَعْمَلُونَ', NULL, 21, 166, 5, 416, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 18, 'أَفَمَن كَانَ مُؤْمِنًۭا كَمَن كَانَ فَاسِقًۭا ۚ لَّا يَسْتَوُۥنَ', NULL, 21, 166, 5, 416, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 19, 'أَمَّا ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ فَلَهُمْ جَنَّٰتُ ٱلْمَأْوَىٰ نُزُلًۢا بِمَا كَانُوا۟ يَعْمَلُونَ', NULL, 21, 166, 5, 416, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 20, 'وَأَمَّا ٱلَّذِينَ فَسَقُوا۟ فَمَأْوَىٰهُمُ ٱلنَّارُ ۖ كُلَّمَآ أَرَادُوٓا۟ أَن يَخْرُجُوا۟ مِنْهَآ أُعِيدُوا۟ فِيهَا وَقِيلَ لَهُمْ ذُوقُوا۟ عَذَابَ ٱلنَّارِ ٱلَّذِى كُنتُم بِهِۦ تُكَذِّبُونَ', NULL, 21, 166, 5, 416, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 21, 'وَلَنُذِيقَنَّهُم مِّنَ ٱلْعَذَابِ ٱلْأَدْنَىٰ دُونَ ٱلْعَذَابِ ٱلْأَكْبَرِ لَعَلَّهُمْ يَرْجِعُونَ', NULL, 21, 166, 5, 417, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 22, 'وَمَنْ أَظْلَمُ مِمَّن ذُكِّرَ بِـَٔايَٰتِ رَبِّهِۦ ثُمَّ أَعْرَضَ عَنْهَآ ۚ إِنَّا مِنَ ٱلْمُجْرِمِينَ مُنتَقِمُونَ', NULL, 21, 166, 5, 417, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 23, 'وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْكِتَٰبَ فَلَا تَكُن فِى مِرْيَةٍۢ مِّن لِّقَآئِهِۦ ۖ وَجَعَلْنَٰهُ هُدًۭى لِّبَنِىٓ إِسْرَٰٓءِيلَ', NULL, 21, 166, 5, 417, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 24, 'وَجَعَلْنَا مِنْهُمْ أَئِمَّةًۭ يَهْدُونَ بِأَمْرِنَا لَمَّا صَبَرُوا۟ ۖ وَكَانُوا۟ بِـَٔايَٰتِنَا يُوقِنُونَ', NULL, 21, 166, 5, 417, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 25, 'إِنَّ رَبَّكَ هُوَ يَفْصِلُ بَيْنَهُمْ يَوْمَ ٱلْقِيَٰمَةِ فِيمَا كَانُوا۟ فِيهِ يَخْتَلِفُونَ', NULL, 21, 166, 5, 417, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 26, 'أَوَلَمْ يَهْدِ لَهُمْ كَمْ أَهْلَكْنَا مِن قَبْلِهِم مِّنَ ٱلْقُرُونِ يَمْشُونَ فِى مَسَٰكِنِهِمْ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍ ۖ أَفَلَا يَسْمَعُونَ', NULL, 21, 166, 5, 417, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 27, 'أَوَلَمْ يَرَوْا۟ أَنَّا نَسُوقُ ٱلْمَآءَ إِلَى ٱلْأَرْضِ ٱلْجُرُزِ فَنُخْرِجُ بِهِۦ زَرْعًۭا تَأْكُلُ مِنْهُ أَنْعَٰمُهُمْ وَأَنفُسُهُمْ ۖ أَفَلَا يُبْصِرُونَ', NULL, 21, 166, 5, 417, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 28, 'وَيَقُولُونَ مَتَىٰ هَٰذَا ٱلْفَتْحُ إِن كُنتُمْ صَٰدِقِينَ', NULL, 21, 166, 5, 417, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 29, 'قُلْ يَوْمَ ٱلْفَتْحِ لَا يَنفَعُ ٱلَّذِينَ كَفَرُوٓا۟ إِيمَٰنُهُمْ وَلَا هُمْ يُنظَرُونَ', NULL, 21, 166, 5, 417, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 32), 30, 'فَأَعْرِضْ عَنْهُمْ وَٱنتَظِرْ إِنَّهُم مُّنتَظِرُونَ', NULL, 21, 166, 5, 417, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ يَٰٓأَيُّهَا ٱلنَّبِىُّ ٱتَّقِ ٱللَّهَ وَلَا تُطِعِ ٱلْكَٰفِرِينَ وَٱلْمُنَٰفِقِينَ ۗ إِنَّ ٱللَّهَ كَانَ عَلِيمًا حَكِيمًۭا', NULL, 21, 167, 5, 418, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 2, 'وَٱتَّبِعْ مَا يُوحَىٰٓ إِلَيْكَ مِن رَّبِّكَ ۚ إِنَّ ٱللَّهَ كَانَ بِمَا تَعْمَلُونَ خَبِيرًۭا', NULL, 21, 167, 5, 418, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 3, 'وَتَوَكَّلْ عَلَى ٱللَّهِ ۚ وَكَفَىٰ بِٱللَّهِ وَكِيلًۭا', NULL, 21, 167, 5, 418, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 4, 'مَّا جَعَلَ ٱللَّهُ لِرَجُلٍۢ مِّن قَلْبَيْنِ فِى جَوْفِهِۦ ۚ وَمَا جَعَلَ أَزْوَٰجَكُمُ ٱلَّٰٓـِٔى تُظَٰهِرُونَ مِنْهُنَّ أُمَّهَٰتِكُمْ ۚ وَمَا جَعَلَ أَدْعِيَآءَكُمْ أَبْنَآءَكُمْ ۚ ذَٰلِكُمْ قَوْلُكُم بِأَفْوَٰهِكُمْ ۖ وَٱللَّهُ يَقُولُ ٱلْحَقَّ وَهُوَ يَهْدِى ٱلسَّبِيلَ', NULL, 21, 167, 5, 418, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 5, 'ٱدْعُوهُمْ لِءَابَآئِهِمْ هُوَ أَقْسَطُ عِندَ ٱللَّهِ ۚ فَإِن لَّمْ تَعْلَمُوٓا۟ ءَابَآءَهُمْ فَإِخْوَٰنُكُمْ فِى ٱلدِّينِ وَمَوَٰلِيكُمْ ۚ وَلَيْسَ عَلَيْكُمْ جُنَاحٌۭ فِيمَآ أَخْطَأْتُم بِهِۦ وَلَٰكِن مَّا تَعَمَّدَتْ قُلُوبُكُمْ ۚ وَكَانَ ٱللَّهُ غَفُورًۭا رَّحِيمًا', NULL, 21, 167, 5, 418, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 6, 'ٱلنَّبِىُّ أَوْلَىٰ بِٱلْمُؤْمِنِينَ مِنْ أَنفُسِهِمْ ۖ وَأَزْوَٰجُهُۥٓ أُمَّهَٰتُهُمْ ۗ وَأُو۟لُوا۟ ٱلْأَرْحَامِ بَعْضُهُمْ أَوْلَىٰ بِبَعْضٍۢ فِى كِتَٰبِ ٱللَّهِ مِنَ ٱلْمُؤْمِنِينَ وَٱلْمُهَٰجِرِينَ إِلَّآ أَن تَفْعَلُوٓا۟ إِلَىٰٓ أَوْلِيَآئِكُم مَّعْرُوفًۭا ۚ كَانَ ذَٰلِكَ فِى ٱلْكِتَٰبِ مَسْطُورًۭا', NULL, 21, 167, 5, 418, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 7, 'وَإِذْ أَخَذْنَا مِنَ ٱلنَّبِيِّۦنَ مِيثَٰقَهُمْ وَمِنكَ وَمِن نُّوحٍۢ وَإِبْرَٰهِيمَ وَمُوسَىٰ وَعِيسَى ٱبْنِ مَرْيَمَ ۖ وَأَخَذْنَا مِنْهُم مِّيثَٰقًا غَلِيظًۭا', NULL, 21, 167, 5, 419, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 8, 'لِّيَسْـَٔلَ ٱلصَّٰدِقِينَ عَن صِدْقِهِمْ ۚ وَأَعَدَّ لِلْكَٰفِرِينَ عَذَابًا أَلِيمًۭا', NULL, 21, 167, 5, 419, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 9, 'يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱذْكُرُوا۟ نِعْمَةَ ٱللَّهِ عَلَيْكُمْ إِذْ جَآءَتْكُمْ جُنُودٌۭ فَأَرْسَلْنَا عَلَيْهِمْ رِيحًۭا وَجُنُودًۭا لَّمْ تَرَوْهَا ۚ وَكَانَ ٱللَّهُ بِمَا تَعْمَلُونَ بَصِيرًا', NULL, 21, 167, 5, 419, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 10, 'إِذْ جَآءُوكُم مِّن فَوْقِكُمْ وَمِنْ أَسْفَلَ مِنكُمْ وَإِذْ زَاغَتِ ٱلْأَبْصَٰرُ وَبَلَغَتِ ٱلْقُلُوبُ ٱلْحَنَاجِرَ وَتَظُنُّونَ بِٱللَّهِ ٱلظُّنُونَا۠', NULL, 21, 167, 5, 419, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 11, 'هُنَالِكَ ٱبْتُلِىَ ٱلْمُؤْمِنُونَ وَزُلْزِلُوا۟ زِلْزَالًۭا شَدِيدًۭا', NULL, 21, 167, 5, 419, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 12, 'وَإِذْ يَقُولُ ٱلْمُنَٰفِقُونَ وَٱلَّذِينَ فِى قُلُوبِهِم مَّرَضٌۭ مَّا وَعَدَنَا ٱللَّهُ وَرَسُولُهُۥٓ إِلَّا غُرُورًۭا', NULL, 21, 167, 5, 419, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 13, 'وَإِذْ قَالَت طَّآئِفَةٌۭ مِّنْهُمْ يَٰٓأَهْلَ يَثْرِبَ لَا مُقَامَ لَكُمْ فَٱرْجِعُوا۟ ۚ وَيَسْتَـْٔذِنُ فَرِيقٌۭ مِّنْهُمُ ٱلنَّبِىَّ يَقُولُونَ إِنَّ بُيُوتَنَا عَوْرَةٌۭ وَمَا هِىَ بِعَوْرَةٍ ۖ إِن يُرِيدُونَ إِلَّا فِرَارًۭا', NULL, 21, 167, 5, 419, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 14, 'وَلَوْ دُخِلَتْ عَلَيْهِم مِّنْ أَقْطَارِهَا ثُمَّ سُئِلُوا۟ ٱلْفِتْنَةَ لَءَاتَوْهَا وَمَا تَلَبَّثُوا۟ بِهَآ إِلَّا يَسِيرًۭا', NULL, 21, 167, 5, 419, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 15, 'وَلَقَدْ كَانُوا۟ عَٰهَدُوا۟ ٱللَّهَ مِن قَبْلُ لَا يُوَلُّونَ ٱلْأَدْبَٰرَ ۚ وَكَانَ عَهْدُ ٱللَّهِ مَسْـُٔولًۭا', NULL, 21, 167, 5, 419, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 16, 'قُل لَّن يَنفَعَكُمُ ٱلْفِرَارُ إِن فَرَرْتُم مِّنَ ٱلْمَوْتِ أَوِ ٱلْقَتْلِ وَإِذًۭا لَّا تُمَتَّعُونَ إِلَّا قَلِيلًۭا', NULL, 21, 167, 5, 420, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 17, 'قُلْ مَن ذَا ٱلَّذِى يَعْصِمُكُم مِّنَ ٱللَّهِ إِنْ أَرَادَ بِكُمْ سُوٓءًا أَوْ أَرَادَ بِكُمْ رَحْمَةًۭ ۚ وَلَا يَجِدُونَ لَهُم مِّن دُونِ ٱللَّهِ وَلِيًّۭا وَلَا نَصِيرًۭا', NULL, 21, 167, 5, 420, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 18, '۞ قَدْ يَعْلَمُ ٱللَّهُ ٱلْمُعَوِّقِينَ مِنكُمْ وَٱلْقَآئِلِينَ لِإِخْوَٰنِهِمْ هَلُمَّ إِلَيْنَا ۖ وَلَا يَأْتُونَ ٱلْبَأْسَ إِلَّا قَلِيلًا', NULL, 21, 168, 5, 420, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 19, 'أَشِحَّةً عَلَيْكُمْ ۖ فَإِذَا جَآءَ ٱلْخَوْفُ رَأَيْتَهُمْ يَنظُرُونَ إِلَيْكَ تَدُورُ أَعْيُنُهُمْ كَٱلَّذِى يُغْشَىٰ عَلَيْهِ مِنَ ٱلْمَوْتِ ۖ فَإِذَا ذَهَبَ ٱلْخَوْفُ سَلَقُوكُم بِأَلْسِنَةٍ حِدَادٍ أَشِحَّةً عَلَى ٱلْخَيْرِ ۚ أُو۟لَٰٓئِكَ لَمْ يُؤْمِنُوا۟ فَأَحْبَطَ ٱللَّهُ أَعْمَٰلَهُمْ ۚ وَكَانَ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرًۭا', NULL, 21, 168, 5, 420, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 20, 'يَحْسَبُونَ ٱلْأَحْزَابَ لَمْ يَذْهَبُوا۟ ۖ وَإِن يَأْتِ ٱلْأَحْزَابُ يَوَدُّوا۟ لَوْ أَنَّهُم بَادُونَ فِى ٱلْأَعْرَابِ يَسْـَٔلُونَ عَنْ أَنۢبَآئِكُمْ ۖ وَلَوْ كَانُوا۟ فِيكُم مَّا قَٰتَلُوٓا۟ إِلَّا قَلِيلًۭا', NULL, 21, 168, 5, 420, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 21, 'لَّقَدْ كَانَ لَكُمْ فِى رَسُولِ ٱللَّهِ أُسْوَةٌ حَسَنَةٌۭ لِّمَن كَانَ يَرْجُوا۟ ٱللَّهَ وَٱلْيَوْمَ ٱلْءَاخِرَ وَذَكَرَ ٱللَّهَ كَثِيرًۭا', NULL, 21, 168, 5, 420, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 22, 'وَلَمَّا رَءَا ٱلْمُؤْمِنُونَ ٱلْأَحْزَابَ قَالُوا۟ هَٰذَا مَا وَعَدَنَا ٱللَّهُ وَرَسُولُهُۥ وَصَدَقَ ٱللَّهُ وَرَسُولُهُۥ ۚ وَمَا زَادَهُمْ إِلَّآ إِيمَٰنًۭا وَتَسْلِيمًۭا', NULL, 21, 168, 5, 420, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 23, 'مِّنَ ٱلْمُؤْمِنِينَ رِجَالٌۭ صَدَقُوا۟ مَا عَٰهَدُوا۟ ٱللَّهَ عَلَيْهِ ۖ فَمِنْهُم مَّن قَضَىٰ نَحْبَهُۥ وَمِنْهُم مَّن يَنتَظِرُ ۖ وَمَا بَدَّلُوا۟ تَبْدِيلًۭا', NULL, 21, 168, 5, 421, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 24, 'لِّيَجْزِىَ ٱللَّهُ ٱلصَّٰدِقِينَ بِصِدْقِهِمْ وَيُعَذِّبَ ٱلْمُنَٰفِقِينَ إِن شَآءَ أَوْ يَتُوبَ عَلَيْهِمْ ۚ إِنَّ ٱللَّهَ كَانَ غَفُورًۭا رَّحِيمًۭا', NULL, 21, 168, 5, 421, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 25, 'وَرَدَّ ٱللَّهُ ٱلَّذِينَ كَفَرُوا۟ بِغَيْظِهِمْ لَمْ يَنَالُوا۟ خَيْرًۭا ۚ وَكَفَى ٱللَّهُ ٱلْمُؤْمِنِينَ ٱلْقِتَالَ ۚ وَكَانَ ٱللَّهُ قَوِيًّا عَزِيزًۭا', NULL, 21, 168, 5, 421, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 26, 'وَأَنزَلَ ٱلَّذِينَ ظَٰهَرُوهُم مِّنْ أَهْلِ ٱلْكِتَٰبِ مِن صَيَاصِيهِمْ وَقَذَفَ فِى قُلُوبِهِمُ ٱلرُّعْبَ فَرِيقًۭا تَقْتُلُونَ وَتَأْسِرُونَ فَرِيقًۭا', NULL, 21, 168, 5, 421, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 27, 'وَأَوْرَثَكُمْ أَرْضَهُمْ وَدِيَٰرَهُمْ وَأَمْوَٰلَهُمْ وَأَرْضًۭا لَّمْ تَطَـُٔوهَا ۚ وَكَانَ ٱللَّهُ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرًۭا', NULL, 21, 168, 5, 421, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 28, 'يَٰٓأَيُّهَا ٱلنَّبِىُّ قُل لِّأَزْوَٰجِكَ إِن كُنتُنَّ تُرِدْنَ ٱلْحَيَوٰةَ ٱلدُّنْيَا وَزِينَتَهَا فَتَعَالَيْنَ أُمَتِّعْكُنَّ وَأُسَرِّحْكُنَّ سَرَاحًۭا جَمِيلًۭا', NULL, 21, 168, 5, 421, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 29, 'وَإِن كُنتُنَّ تُرِدْنَ ٱللَّهَ وَرَسُولَهُۥ وَٱلدَّارَ ٱلْءَاخِرَةَ فَإِنَّ ٱللَّهَ أَعَدَّ لِلْمُحْسِنَٰتِ مِنكُنَّ أَجْرًا عَظِيمًۭا', NULL, 21, 168, 5, 421, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 30, 'يَٰنِسَآءَ ٱلنَّبِىِّ مَن يَأْتِ مِنكُنَّ بِفَٰحِشَةٍۢ مُّبَيِّنَةٍۢ يُضَٰعَفْ لَهَا ٱلْعَذَابُ ضِعْفَيْنِ ۚ وَكَانَ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرًۭا', NULL, 21, 168, 5, 421, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 31, '۞ وَمَن يَقْنُتْ مِنكُنَّ لِلَّهِ وَرَسُولِهِۦ وَتَعْمَلْ صَٰلِحًۭا نُّؤْتِهَآ أَجْرَهَا مَرَّتَيْنِ وَأَعْتَدْنَا لَهَا رِزْقًۭا كَرِيمًۭا', NULL, 22, 169, 5, 422, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 32, 'يَٰنِسَآءَ ٱلنَّبِىِّ لَسْتُنَّ كَأَحَدٍۢ مِّنَ ٱلنِّسَآءِ ۚ إِنِ ٱتَّقَيْتُنَّ فَلَا تَخْضَعْنَ بِٱلْقَوْلِ فَيَطْمَعَ ٱلَّذِى فِى قَلْبِهِۦ مَرَضٌۭ وَقُلْنَ قَوْلًۭا مَّعْرُوفًۭا', NULL, 22, 169, 5, 422, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 33, 'وَقَرْنَ فِى بُيُوتِكُنَّ وَلَا تَبَرَّجْنَ تَبَرُّجَ ٱلْجَٰهِلِيَّةِ ٱلْأُولَىٰ ۖ وَأَقِمْنَ ٱلصَّلَوٰةَ وَءَاتِينَ ٱلزَّكَوٰةَ وَأَطِعْنَ ٱللَّهَ وَرَسُولَهُۥٓ ۚ إِنَّمَا يُرِيدُ ٱللَّهُ لِيُذْهِبَ عَنكُمُ ٱلرِّجْسَ أَهْلَ ٱلْبَيْتِ وَيُطَهِّرَكُمْ تَطْهِيرًۭا', NULL, 22, 169, 5, 422, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 34, 'وَٱذْكُرْنَ مَا يُتْلَىٰ فِى بُيُوتِكُنَّ مِنْ ءَايَٰتِ ٱللَّهِ وَٱلْحِكْمَةِ ۚ إِنَّ ٱللَّهَ كَانَ لَطِيفًا خَبِيرًا', NULL, 22, 169, 5, 422, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 35, 'إِنَّ ٱلْمُسْلِمِينَ وَٱلْمُسْلِمَٰتِ وَٱلْمُؤْمِنِينَ وَٱلْمُؤْمِنَٰتِ وَٱلْقَٰنِتِينَ وَٱلْقَٰنِتَٰتِ وَٱلصَّٰدِقِينَ وَٱلصَّٰدِقَٰتِ وَٱلصَّٰبِرِينَ وَٱلصَّٰبِرَٰتِ وَٱلْخَٰشِعِينَ وَٱلْخَٰشِعَٰتِ وَٱلْمُتَصَدِّقِينَ وَٱلْمُتَصَدِّقَٰتِ وَٱلصَّٰٓئِمِينَ وَٱلصَّٰٓئِمَٰتِ وَٱلْحَٰفِظِينَ فُرُوجَهُمْ وَٱلْحَٰفِظَٰتِ وَٱلذَّٰكِرِينَ ٱللَّهَ كَثِيرًۭا وَٱلذَّٰكِرَٰتِ أَعَدَّ ٱللَّهُ لَهُم مَّغْفِرَةًۭ وَأَجْرًا عَظِيمًۭا', NULL, 22, 169, 5, 422, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 36, 'وَمَا كَانَ لِمُؤْمِنٍۢ وَلَا مُؤْمِنَةٍ إِذَا قَضَى ٱللَّهُ وَرَسُولُهُۥٓ أَمْرًا أَن يَكُونَ لَهُمُ ٱلْخِيَرَةُ مِنْ أَمْرِهِمْ ۗ وَمَن يَعْصِ ٱللَّهَ وَرَسُولَهُۥ فَقَدْ ضَلَّ ضَلَٰلًۭا مُّبِينًۭا', NULL, 22, 169, 5, 423, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 37, 'وَإِذْ تَقُولُ لِلَّذِىٓ أَنْعَمَ ٱللَّهُ عَلَيْهِ وَأَنْعَمْتَ عَلَيْهِ أَمْسِكْ عَلَيْكَ زَوْجَكَ وَٱتَّقِ ٱللَّهَ وَتُخْفِى فِى نَفْسِكَ مَا ٱللَّهُ مُبْدِيهِ وَتَخْشَى ٱلنَّاسَ وَٱللَّهُ أَحَقُّ أَن تَخْشَىٰهُ ۖ فَلَمَّا قَضَىٰ زَيْدٌۭ مِّنْهَا وَطَرًۭا زَوَّجْنَٰكَهَا لِكَىْ لَا يَكُونَ عَلَى ٱلْمُؤْمِنِينَ حَرَجٌۭ فِىٓ أَزْوَٰجِ أَدْعِيَآئِهِمْ إِذَا قَضَوْا۟ مِنْهُنَّ وَطَرًۭا ۚ وَكَانَ أَمْرُ ٱللَّهِ مَفْعُولًۭا', NULL, 22, 169, 5, 423, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 38, 'مَّا كَانَ عَلَى ٱلنَّبِىِّ مِنْ حَرَجٍۢ فِيمَا فَرَضَ ٱللَّهُ لَهُۥ ۖ سُنَّةَ ٱللَّهِ فِى ٱلَّذِينَ خَلَوْا۟ مِن قَبْلُ ۚ وَكَانَ أَمْرُ ٱللَّهِ قَدَرًۭا مَّقْدُورًا', NULL, 22, 169, 5, 423, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 39, 'ٱلَّذِينَ يُبَلِّغُونَ رِسَٰلَٰتِ ٱللَّهِ وَيَخْشَوْنَهُۥ وَلَا يَخْشَوْنَ أَحَدًا إِلَّا ٱللَّهَ ۗ وَكَفَىٰ بِٱللَّهِ حَسِيبًۭا', NULL, 22, 169, 5, 423, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 40, 'مَّا كَانَ مُحَمَّدٌ أَبَآ أَحَدٍۢ مِّن رِّجَالِكُمْ وَلَٰكِن رَّسُولَ ٱللَّهِ وَخَاتَمَ ٱلنَّبِيِّۦنَ ۗ وَكَانَ ٱللَّهُ بِكُلِّ شَىْءٍ عَلِيمًۭا', NULL, 22, 169, 5, 423, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 41, 'يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱذْكُرُوا۟ ٱللَّهَ ذِكْرًۭا كَثِيرًۭا', NULL, 22, 169, 5, 423, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 42, 'وَسَبِّحُوهُ بُكْرَةًۭ وَأَصِيلًا', NULL, 22, 169, 5, 423, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 43, 'هُوَ ٱلَّذِى يُصَلِّى عَلَيْكُمْ وَمَلَٰٓئِكَتُهُۥ لِيُخْرِجَكُم مِّنَ ٱلظُّلُمَٰتِ إِلَى ٱلنُّورِ ۚ وَكَانَ بِٱلْمُؤْمِنِينَ رَحِيمًۭا', NULL, 22, 169, 5, 423, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 44, 'تَحِيَّتُهُمْ يَوْمَ يَلْقَوْنَهُۥ سَلَٰمٌۭ ۚ وَأَعَدَّ لَهُمْ أَجْرًۭا كَرِيمًۭا', NULL, 22, 169, 5, 424, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 45, 'يَٰٓأَيُّهَا ٱلنَّبِىُّ إِنَّآ أَرْسَلْنَٰكَ شَٰهِدًۭا وَمُبَشِّرًۭا وَنَذِيرًۭا', NULL, 22, 169, 5, 424, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 46, 'وَدَاعِيًا إِلَى ٱللَّهِ بِإِذْنِهِۦ وَسِرَاجًۭا مُّنِيرًۭا', NULL, 22, 169, 5, 424, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 47, 'وَبَشِّرِ ٱلْمُؤْمِنِينَ بِأَنَّ لَهُم مِّنَ ٱللَّهِ فَضْلًۭا كَبِيرًۭا', NULL, 22, 169, 5, 424, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 48, 'وَلَا تُطِعِ ٱلْكَٰفِرِينَ وَٱلْمُنَٰفِقِينَ وَدَعْ أَذَىٰهُمْ وَتَوَكَّلْ عَلَى ٱللَّهِ ۚ وَكَفَىٰ بِٱللَّهِ وَكِيلًۭا', NULL, 22, 169, 5, 424, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 49, 'يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِذَا نَكَحْتُمُ ٱلْمُؤْمِنَٰتِ ثُمَّ طَلَّقْتُمُوهُنَّ مِن قَبْلِ أَن تَمَسُّوهُنَّ فَمَا لَكُمْ عَلَيْهِنَّ مِنْ عِدَّةٍۢ تَعْتَدُّونَهَا ۖ فَمَتِّعُوهُنَّ وَسَرِّحُوهُنَّ سَرَاحًۭا جَمِيلًۭا', NULL, 22, 169, 5, 424, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 50, 'يَٰٓأَيُّهَا ٱلنَّبِىُّ إِنَّآ أَحْلَلْنَا لَكَ أَزْوَٰجَكَ ٱلَّٰتِىٓ ءَاتَيْتَ أُجُورَهُنَّ وَمَا مَلَكَتْ يَمِينُكَ مِمَّآ أَفَآءَ ٱللَّهُ عَلَيْكَ وَبَنَاتِ عَمِّكَ وَبَنَاتِ عَمَّٰتِكَ وَبَنَاتِ خَالِكَ وَبَنَاتِ خَٰلَٰتِكَ ٱلَّٰتِى هَاجَرْنَ مَعَكَ وَٱمْرَأَةًۭ مُّؤْمِنَةً إِن وَهَبَتْ نَفْسَهَا لِلنَّبِىِّ إِنْ أَرَادَ ٱلنَّبِىُّ أَن يَسْتَنكِحَهَا خَالِصَةًۭ لَّكَ مِن دُونِ ٱلْمُؤْمِنِينَ ۗ قَدْ عَلِمْنَا مَا فَرَضْنَا عَلَيْهِمْ فِىٓ أَزْوَٰجِهِمْ وَمَا مَلَكَتْ أَيْمَٰنُهُمْ لِكَيْلَا يَكُونَ عَلَيْكَ حَرَجٌۭ ۗ وَكَانَ ٱللَّهُ غَفُورًۭا رَّحِيمًۭا', NULL, 22, 169, 5, 424, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 51, '۞ تُرْجِى مَن تَشَآءُ مِنْهُنَّ وَتُـْٔوِىٓ إِلَيْكَ مَن تَشَآءُ ۖ وَمَنِ ٱبْتَغَيْتَ مِمَّنْ عَزَلْتَ فَلَا جُنَاحَ عَلَيْكَ ۚ ذَٰلِكَ أَدْنَىٰٓ أَن تَقَرَّ أَعْيُنُهُنَّ وَلَا يَحْزَنَّ وَيَرْضَيْنَ بِمَآ ءَاتَيْتَهُنَّ كُلُّهُنَّ ۚ وَٱللَّهُ يَعْلَمُ مَا فِى قُلُوبِكُمْ ۚ وَكَانَ ٱللَّهُ عَلِيمًا حَلِيمًۭا', NULL, 22, 170, 5, 425, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 52, 'لَّا يَحِلُّ لَكَ ٱلنِّسَآءُ مِنۢ بَعْدُ وَلَآ أَن تَبَدَّلَ بِهِنَّ مِنْ أَزْوَٰجٍۢ وَلَوْ أَعْجَبَكَ حُسْنُهُنَّ إِلَّا مَا مَلَكَتْ يَمِينُكَ ۗ وَكَانَ ٱللَّهُ عَلَىٰ كُلِّ شَىْءٍۢ رَّقِيبًۭا', NULL, 22, 170, 5, 425, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 53, 'يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَدْخُلُوا۟ بُيُوتَ ٱلنَّبِىِّ إِلَّآ أَن يُؤْذَنَ لَكُمْ إِلَىٰ طَعَامٍ غَيْرَ نَٰظِرِينَ إِنَىٰهُ وَلَٰكِنْ إِذَا دُعِيتُمْ فَٱدْخُلُوا۟ فَإِذَا طَعِمْتُمْ فَٱنتَشِرُوا۟ وَلَا مُسْتَـْٔنِسِينَ لِحَدِيثٍ ۚ إِنَّ ذَٰلِكُمْ كَانَ يُؤْذِى ٱلنَّبِىَّ فَيَسْتَحْىِۦ مِنكُمْ ۖ وَٱللَّهُ لَا يَسْتَحْىِۦ مِنَ ٱلْحَقِّ ۚ وَإِذَا سَأَلْتُمُوهُنَّ مَتَٰعًۭا فَسْـَٔلُوهُنَّ مِن وَرَآءِ حِجَابٍۢ ۚ ذَٰلِكُمْ أَطْهَرُ لِقُلُوبِكُمْ وَقُلُوبِهِنَّ ۚ وَمَا كَانَ لَكُمْ أَن تُؤْذُوا۟ رَسُولَ ٱللَّهِ وَلَآ أَن تَنكِحُوٓا۟ أَزْوَٰجَهُۥ مِنۢ بَعْدِهِۦٓ أَبَدًا ۚ إِنَّ ذَٰلِكُمْ كَانَ عِندَ ٱللَّهِ عَظِيمًا', NULL, 22, 170, 5, 425, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 54, 'إِن تُبْدُوا۟ شَيْـًٔا أَوْ تُخْفُوهُ فَإِنَّ ٱللَّهَ كَانَ بِكُلِّ شَىْءٍ عَلِيمًۭا', NULL, 22, 170, 5, 425, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 55, 'لَّا جُنَاحَ عَلَيْهِنَّ فِىٓ ءَابَآئِهِنَّ وَلَآ أَبْنَآئِهِنَّ وَلَآ إِخْوَٰنِهِنَّ وَلَآ أَبْنَآءِ إِخْوَٰنِهِنَّ وَلَآ أَبْنَآءِ أَخَوَٰتِهِنَّ وَلَا نِسَآئِهِنَّ وَلَا مَا مَلَكَتْ أَيْمَٰنُهُنَّ ۗ وَٱتَّقِينَ ٱللَّهَ ۚ إِنَّ ٱللَّهَ كَانَ عَلَىٰ كُلِّ شَىْءٍۢ شَهِيدًا', NULL, 22, 170, 5, 426, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 56, 'إِنَّ ٱللَّهَ وَمَلَٰٓئِكَتَهُۥ يُصَلُّونَ عَلَى ٱلنَّبِىِّ ۚ يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ صَلُّوا۟ عَلَيْهِ وَسَلِّمُوا۟ تَسْلِيمًا', NULL, 22, 170, 5, 426, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 57, 'إِنَّ ٱلَّذِينَ يُؤْذُونَ ٱللَّهَ وَرَسُولَهُۥ لَعَنَهُمُ ٱللَّهُ فِى ٱلدُّنْيَا وَٱلْءَاخِرَةِ وَأَعَدَّ لَهُمْ عَذَابًۭا مُّهِينًۭا', NULL, 22, 170, 5, 426, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 58, 'وَٱلَّذِينَ يُؤْذُونَ ٱلْمُؤْمِنِينَ وَٱلْمُؤْمِنَٰتِ بِغَيْرِ مَا ٱكْتَسَبُوا۟ فَقَدِ ٱحْتَمَلُوا۟ بُهْتَٰنًۭا وَإِثْمًۭا مُّبِينًۭا', NULL, 22, 170, 5, 426, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 59, 'يَٰٓأَيُّهَا ٱلنَّبِىُّ قُل لِّأَزْوَٰجِكَ وَبَنَاتِكَ وَنِسَآءِ ٱلْمُؤْمِنِينَ يُدْنِينَ عَلَيْهِنَّ مِن جَلَٰبِيبِهِنَّ ۚ ذَٰلِكَ أَدْنَىٰٓ أَن يُعْرَفْنَ فَلَا يُؤْذَيْنَ ۗ وَكَانَ ٱللَّهُ غَفُورًۭا رَّحِيمًۭا', NULL, 22, 170, 5, 426, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 60, '۞ لَّئِن لَّمْ يَنتَهِ ٱلْمُنَٰفِقُونَ وَٱلَّذِينَ فِى قُلُوبِهِم مَّرَضٌۭ وَٱلْمُرْجِفُونَ فِى ٱلْمَدِينَةِ لَنُغْرِيَنَّكَ بِهِمْ ثُمَّ لَا يُجَاوِرُونَكَ فِيهَآ إِلَّا قَلِيلًۭا', NULL, 22, 171, 5, 426, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 61, 'مَّلْعُونِينَ ۖ أَيْنَمَا ثُقِفُوٓا۟ أُخِذُوا۟ وَقُتِّلُوا۟ تَقْتِيلًۭا', NULL, 22, 171, 5, 426, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 62, 'سُنَّةَ ٱللَّهِ فِى ٱلَّذِينَ خَلَوْا۟ مِن قَبْلُ ۖ وَلَن تَجِدَ لِسُنَّةِ ٱللَّهِ تَبْدِيلًۭا', NULL, 22, 171, 5, 426, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 63, 'يَسْـَٔلُكَ ٱلنَّاسُ عَنِ ٱلسَّاعَةِ ۖ قُلْ إِنَّمَا عِلْمُهَا عِندَ ٱللَّهِ ۚ وَمَا يُدْرِيكَ لَعَلَّ ٱلسَّاعَةَ تَكُونُ قَرِيبًا', NULL, 22, 171, 5, 427, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 64, 'إِنَّ ٱللَّهَ لَعَنَ ٱلْكَٰفِرِينَ وَأَعَدَّ لَهُمْ سَعِيرًا', NULL, 22, 171, 5, 427, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 65, 'خَٰلِدِينَ فِيهَآ أَبَدًۭا ۖ لَّا يَجِدُونَ وَلِيًّۭا وَلَا نَصِيرًۭا', NULL, 22, 171, 5, 427, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 66, 'يَوْمَ تُقَلَّبُ وُجُوهُهُمْ فِى ٱلنَّارِ يَقُولُونَ يَٰلَيْتَنَآ أَطَعْنَا ٱللَّهَ وَأَطَعْنَا ٱلرَّسُولَا۠', NULL, 22, 171, 5, 427, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 67, 'وَقَالُوا۟ رَبَّنَآ إِنَّآ أَطَعْنَا سَادَتَنَا وَكُبَرَآءَنَا فَأَضَلُّونَا ٱلسَّبِيلَا۠', NULL, 22, 171, 5, 427, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 68, 'رَبَّنَآ ءَاتِهِمْ ضِعْفَيْنِ مِنَ ٱلْعَذَابِ وَٱلْعَنْهُمْ لَعْنًۭا كَبِيرًۭا', NULL, 22, 171, 5, 427, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 69, 'يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَكُونُوا۟ كَٱلَّذِينَ ءَاذَوْا۟ مُوسَىٰ فَبَرَّأَهُ ٱللَّهُ مِمَّا قَالُوا۟ ۚ وَكَانَ عِندَ ٱللَّهِ وَجِيهًۭا', NULL, 22, 171, 5, 427, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 70, 'يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱتَّقُوا۟ ٱللَّهَ وَقُولُوا۟ قَوْلًۭا سَدِيدًۭا', NULL, 22, 171, 5, 427, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 71, 'يُصْلِحْ لَكُمْ أَعْمَٰلَكُمْ وَيَغْفِرْ لَكُمْ ذُنُوبَكُمْ ۗ وَمَن يُطِعِ ٱللَّهَ وَرَسُولَهُۥ فَقَدْ فَازَ فَوْزًا عَظِيمًا', NULL, 22, 171, 5, 427, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 72, 'إِنَّا عَرَضْنَا ٱلْأَمَانَةَ عَلَى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَٱلْجِبَالِ فَأَبَيْنَ أَن يَحْمِلْنَهَا وَأَشْفَقْنَ مِنْهَا وَحَمَلَهَا ٱلْإِنسَٰنُ ۖ إِنَّهُۥ كَانَ ظَلُومًۭا جَهُولًۭا', NULL, 22, 171, 5, 427, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 33), 73, 'لِّيُعَذِّبَ ٱللَّهُ ٱلْمُنَٰفِقِينَ وَٱلْمُنَٰفِقَٰتِ وَٱلْمُشْرِكِينَ وَٱلْمُشْرِكَٰتِ وَيَتُوبَ ٱللَّهُ عَلَى ٱلْمُؤْمِنِينَ وَٱلْمُؤْمِنَٰتِ ۗ وَكَانَ ٱللَّهُ غَفُورًۭا رَّحِيمًۢا', NULL, 22, 171, 5, 427, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ ٱلْحَمْدُ لِلَّهِ ٱلَّذِى لَهُۥ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ وَلَهُ ٱلْحَمْدُ فِى ٱلْءَاخِرَةِ ۚ وَهُوَ ٱلْحَكِيمُ ٱلْخَبِيرُ', NULL, 22, 171, 5, 428, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 2, 'يَعْلَمُ مَا يَلِجُ فِى ٱلْأَرْضِ وَمَا يَخْرُجُ مِنْهَا وَمَا يَنزِلُ مِنَ ٱلسَّمَآءِ وَمَا يَعْرُجُ فِيهَا ۚ وَهُوَ ٱلرَّحِيمُ ٱلْغَفُورُ', NULL, 22, 171, 5, 428, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 3, 'وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لَا تَأْتِينَا ٱلسَّاعَةُ ۖ قُلْ بَلَىٰ وَرَبِّى لَتَأْتِيَنَّكُمْ عَٰلِمِ ٱلْغَيْبِ ۖ لَا يَعْزُبُ عَنْهُ مِثْقَالُ ذَرَّةٍۢ فِى ٱلسَّمَٰوَٰتِ وَلَا فِى ٱلْأَرْضِ وَلَآ أَصْغَرُ مِن ذَٰلِكَ وَلَآ أَكْبَرُ إِلَّا فِى كِتَٰبٍۢ مُّبِينٍۢ', NULL, 22, 171, 5, 428, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 4, 'لِّيَجْزِىَ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ ۚ أُو۟لَٰٓئِكَ لَهُم مَّغْفِرَةٌۭ وَرِزْقٌۭ كَرِيمٌۭ', NULL, 22, 171, 5, 428, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 5, 'وَٱلَّذِينَ سَعَوْ فِىٓ ءَايَٰتِنَا مُعَٰجِزِينَ أُو۟لَٰٓئِكَ لَهُمْ عَذَابٌۭ مِّن رِّجْزٍ أَلِيمٌۭ', NULL, 22, 171, 5, 428, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 6, 'وَيَرَى ٱلَّذِينَ أُوتُوا۟ ٱلْعِلْمَ ٱلَّذِىٓ أُنزِلَ إِلَيْكَ مِن رَّبِّكَ هُوَ ٱلْحَقَّ وَيَهْدِىٓ إِلَىٰ صِرَٰطِ ٱلْعَزِيزِ ٱلْحَمِيدِ', NULL, 22, 171, 5, 428, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 7, 'وَقَالَ ٱلَّذِينَ كَفَرُوا۟ هَلْ نَدُلُّكُمْ عَلَىٰ رَجُلٍۢ يُنَبِّئُكُمْ إِذَا مُزِّقْتُمْ كُلَّ مُمَزَّقٍ إِنَّكُمْ لَفِى خَلْقٍۢ جَدِيدٍ', NULL, 22, 171, 5, 428, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 8, 'أَفْتَرَىٰ عَلَى ٱللَّهِ كَذِبًا أَم بِهِۦ جِنَّةٌۢ ۗ بَلِ ٱلَّذِينَ لَا يُؤْمِنُونَ بِٱلْءَاخِرَةِ فِى ٱلْعَذَابِ وَٱلضَّلَٰلِ ٱلْبَعِيدِ', NULL, 22, 171, 5, 429, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 9, 'أَفَلَمْ يَرَوْا۟ إِلَىٰ مَا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُم مِّنَ ٱلسَّمَآءِ وَٱلْأَرْضِ ۚ إِن نَّشَأْ نَخْسِفْ بِهِمُ ٱلْأَرْضَ أَوْ نُسْقِطْ عَلَيْهِمْ كِسَفًۭا مِّنَ ٱلسَّمَآءِ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ لِّكُلِّ عَبْدٍۢ مُّنِيبٍۢ', NULL, 22, 171, 5, 429, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 10, '۞ وَلَقَدْ ءَاتَيْنَا دَاوُۥدَ مِنَّا فَضْلًۭا ۖ يَٰجِبَالُ أَوِّبِى مَعَهُۥ وَٱلطَّيْرَ ۖ وَأَلَنَّا لَهُ ٱلْحَدِيدَ', NULL, 22, 172, 5, 429, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 11, 'أَنِ ٱعْمَلْ سَٰبِغَٰتٍۢ وَقَدِّرْ فِى ٱلسَّرْدِ ۖ وَٱعْمَلُوا۟ صَٰلِحًا ۖ إِنِّى بِمَا تَعْمَلُونَ بَصِيرٌۭ', NULL, 22, 172, 5, 429, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 12, 'وَلِسُلَيْمَٰنَ ٱلرِّيحَ غُدُوُّهَا شَهْرٌۭ وَرَوَاحُهَا شَهْرٌۭ ۖ وَأَسَلْنَا لَهُۥ عَيْنَ ٱلْقِطْرِ ۖ وَمِنَ ٱلْجِنِّ مَن يَعْمَلُ بَيْنَ يَدَيْهِ بِإِذْنِ رَبِّهِۦ ۖ وَمَن يَزِغْ مِنْهُمْ عَنْ أَمْرِنَا نُذِقْهُ مِنْ عَذَابِ ٱلسَّعِيرِ', NULL, 22, 172, 5, 429, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 13, 'يَعْمَلُونَ لَهُۥ مَا يَشَآءُ مِن مَّحَٰرِيبَ وَتَمَٰثِيلَ وَجِفَانٍۢ كَٱلْجَوَابِ وَقُدُورٍۢ رَّاسِيَٰتٍ ۚ ٱعْمَلُوٓا۟ ءَالَ دَاوُۥدَ شُكْرًۭا ۚ وَقَلِيلٌۭ مِّنْ عِبَادِىَ ٱلشَّكُورُ', NULL, 22, 172, 5, 429, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 14, 'فَلَمَّا قَضَيْنَا عَلَيْهِ ٱلْمَوْتَ مَا دَلَّهُمْ عَلَىٰ مَوْتِهِۦٓ إِلَّا دَآبَّةُ ٱلْأَرْضِ تَأْكُلُ مِنسَأَتَهُۥ ۖ فَلَمَّا خَرَّ تَبَيَّنَتِ ٱلْجِنُّ أَن لَّوْ كَانُوا۟ يَعْلَمُونَ ٱلْغَيْبَ مَا لَبِثُوا۟ فِى ٱلْعَذَابِ ٱلْمُهِينِ', NULL, 22, 172, 5, 429, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 15, 'لَقَدْ كَانَ لِسَبَإٍۢ فِى مَسْكَنِهِمْ ءَايَةٌۭ ۖ جَنَّتَانِ عَن يَمِينٍۢ وَشِمَالٍۢ ۖ كُلُوا۟ مِن رِّزْقِ رَبِّكُمْ وَٱشْكُرُوا۟ لَهُۥ ۚ بَلْدَةٌۭ طَيِّبَةٌۭ وَرَبٌّ غَفُورٌۭ', NULL, 22, 172, 5, 430, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 16, 'فَأَعْرَضُوا۟ فَأَرْسَلْنَا عَلَيْهِمْ سَيْلَ ٱلْعَرِمِ وَبَدَّلْنَٰهُم بِجَنَّتَيْهِمْ جَنَّتَيْنِ ذَوَاتَىْ أُكُلٍ خَمْطٍۢ وَأَثْلٍۢ وَشَىْءٍۢ مِّن سِدْرٍۢ قَلِيلٍۢ', NULL, 22, 172, 5, 430, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 17, 'ذَٰلِكَ جَزَيْنَٰهُم بِمَا كَفَرُوا۟ ۖ وَهَلْ نُجَٰزِىٓ إِلَّا ٱلْكَفُورَ', NULL, 22, 172, 5, 430, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 18, 'وَجَعَلْنَا بَيْنَهُمْ وَبَيْنَ ٱلْقُرَى ٱلَّتِى بَٰرَكْنَا فِيهَا قُرًۭى ظَٰهِرَةًۭ وَقَدَّرْنَا فِيهَا ٱلسَّيْرَ ۖ سِيرُوا۟ فِيهَا لَيَالِىَ وَأَيَّامًا ءَامِنِينَ', NULL, 22, 172, 5, 430, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 19, 'فَقَالُوا۟ رَبَّنَا بَٰعِدْ بَيْنَ أَسْفَارِنَا وَظَلَمُوٓا۟ أَنفُسَهُمْ فَجَعَلْنَٰهُمْ أَحَادِيثَ وَمَزَّقْنَٰهُمْ كُلَّ مُمَزَّقٍ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّكُلِّ صَبَّارٍۢ شَكُورٍۢ', NULL, 22, 172, 5, 430, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 20, 'وَلَقَدْ صَدَّقَ عَلَيْهِمْ إِبْلِيسُ ظَنَّهُۥ فَٱتَّبَعُوهُ إِلَّا فَرِيقًۭا مِّنَ ٱلْمُؤْمِنِينَ', NULL, 22, 172, 5, 430, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 21, 'وَمَا كَانَ لَهُۥ عَلَيْهِم مِّن سُلْطَٰنٍ إِلَّا لِنَعْلَمَ مَن يُؤْمِنُ بِٱلْءَاخِرَةِ مِمَّنْ هُوَ مِنْهَا فِى شَكٍّۢ ۗ وَرَبُّكَ عَلَىٰ كُلِّ شَىْءٍ حَفِيظٌۭ', NULL, 22, 172, 5, 430, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 22, 'قُلِ ٱدْعُوا۟ ٱلَّذِينَ زَعَمْتُم مِّن دُونِ ٱللَّهِ ۖ لَا يَمْلِكُونَ مِثْقَالَ ذَرَّةٍۢ فِى ٱلسَّمَٰوَٰتِ وَلَا فِى ٱلْأَرْضِ وَمَا لَهُمْ فِيهِمَا مِن شِرْكٍۢ وَمَا لَهُۥ مِنْهُم مِّن ظَهِيرٍۢ', NULL, 22, 172, 5, 430, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 23, 'وَلَا تَنفَعُ ٱلشَّفَٰعَةُ عِندَهُۥٓ إِلَّا لِمَنْ أَذِنَ لَهُۥ ۚ حَتَّىٰٓ إِذَا فُزِّعَ عَن قُلُوبِهِمْ قَالُوا۟ مَاذَا قَالَ رَبُّكُمْ ۖ قَالُوا۟ ٱلْحَقَّ ۖ وَهُوَ ٱلْعَلِىُّ ٱلْكَبِيرُ', NULL, 22, 172, 5, 431, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 24, '۞ قُلْ مَن يَرْزُقُكُم مِّنَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ قُلِ ٱللَّهُ ۖ وَإِنَّآ أَوْ إِيَّاكُمْ لَعَلَىٰ هُدًى أَوْ فِى ضَلَٰلٍۢ مُّبِينٍۢ', NULL, 22, 173, 5, 431, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 25, 'قُل لَّا تُسْـَٔلُونَ عَمَّآ أَجْرَمْنَا وَلَا نُسْـَٔلُ عَمَّا تَعْمَلُونَ', NULL, 22, 173, 5, 431, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 26, 'قُلْ يَجْمَعُ بَيْنَنَا رَبُّنَا ثُمَّ يَفْتَحُ بَيْنَنَا بِٱلْحَقِّ وَهُوَ ٱلْفَتَّاحُ ٱلْعَلِيمُ', NULL, 22, 173, 5, 431, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 27, 'قُلْ أَرُونِىَ ٱلَّذِينَ أَلْحَقْتُم بِهِۦ شُرَكَآءَ ۖ كَلَّا ۚ بَلْ هُوَ ٱللَّهُ ٱلْعَزِيزُ ٱلْحَكِيمُ', NULL, 22, 173, 5, 431, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 28, 'وَمَآ أَرْسَلْنَٰكَ إِلَّا كَآفَّةًۭ لِّلنَّاسِ بَشِيرًۭا وَنَذِيرًۭا وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ', NULL, 22, 173, 5, 431, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 29, 'وَيَقُولُونَ مَتَىٰ هَٰذَا ٱلْوَعْدُ إِن كُنتُمْ صَٰدِقِينَ', NULL, 22, 173, 5, 431, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 30, 'قُل لَّكُم مِّيعَادُ يَوْمٍۢ لَّا تَسْتَـْٔخِرُونَ عَنْهُ سَاعَةًۭ وَلَا تَسْتَقْدِمُونَ', NULL, 22, 173, 5, 431, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 31, 'وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لَن نُّؤْمِنَ بِهَٰذَا ٱلْقُرْءَانِ وَلَا بِٱلَّذِى بَيْنَ يَدَيْهِ ۗ وَلَوْ تَرَىٰٓ إِذِ ٱلظَّٰلِمُونَ مَوْقُوفُونَ عِندَ رَبِّهِمْ يَرْجِعُ بَعْضُهُمْ إِلَىٰ بَعْضٍ ٱلْقَوْلَ يَقُولُ ٱلَّذِينَ ٱسْتُضْعِفُوا۟ لِلَّذِينَ ٱسْتَكْبَرُوا۟ لَوْلَآ أَنتُمْ لَكُنَّا مُؤْمِنِينَ', NULL, 22, 173, 5, 431, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 32, 'قَالَ ٱلَّذِينَ ٱسْتَكْبَرُوا۟ لِلَّذِينَ ٱسْتُضْعِفُوٓا۟ أَنَحْنُ صَدَدْنَٰكُمْ عَنِ ٱلْهُدَىٰ بَعْدَ إِذْ جَآءَكُم ۖ بَلْ كُنتُم مُّجْرِمِينَ', NULL, 22, 173, 5, 432, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 33, 'وَقَالَ ٱلَّذِينَ ٱسْتُضْعِفُوا۟ لِلَّذِينَ ٱسْتَكْبَرُوا۟ بَلْ مَكْرُ ٱلَّيْلِ وَٱلنَّهَارِ إِذْ تَأْمُرُونَنَآ أَن نَّكْفُرَ بِٱللَّهِ وَنَجْعَلَ لَهُۥٓ أَندَادًۭا ۚ وَأَسَرُّوا۟ ٱلنَّدَامَةَ لَمَّا رَأَوُا۟ ٱلْعَذَابَ وَجَعَلْنَا ٱلْأَغْلَٰلَ فِىٓ أَعْنَاقِ ٱلَّذِينَ كَفَرُوا۟ ۚ هَلْ يُجْزَوْنَ إِلَّا مَا كَانُوا۟ يَعْمَلُونَ', NULL, 22, 173, 5, 432, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 34, 'وَمَآ أَرْسَلْنَا فِى قَرْيَةٍۢ مِّن نَّذِيرٍ إِلَّا قَالَ مُتْرَفُوهَآ إِنَّا بِمَآ أُرْسِلْتُم بِهِۦ كَٰفِرُونَ', NULL, 22, 173, 5, 432, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 35, 'وَقَالُوا۟ نَحْنُ أَكْثَرُ أَمْوَٰلًۭا وَأَوْلَٰدًۭا وَمَا نَحْنُ بِمُعَذَّبِينَ', NULL, 22, 173, 5, 432, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 36, 'قُلْ إِنَّ رَبِّى يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ وَيَقْدِرُ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ', NULL, 22, 173, 5, 432, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 37, 'وَمَآ أَمْوَٰلُكُمْ وَلَآ أَوْلَٰدُكُم بِٱلَّتِى تُقَرِّبُكُمْ عِندَنَا زُلْفَىٰٓ إِلَّا مَنْ ءَامَنَ وَعَمِلَ صَٰلِحًۭا فَأُو۟لَٰٓئِكَ لَهُمْ جَزَآءُ ٱلضِّعْفِ بِمَا عَمِلُوا۟ وَهُمْ فِى ٱلْغُرُفَٰتِ ءَامِنُونَ', NULL, 22, 173, 5, 432, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 38, 'وَٱلَّذِينَ يَسْعَوْنَ فِىٓ ءَايَٰتِنَا مُعَٰجِزِينَ أُو۟لَٰٓئِكَ فِى ٱلْعَذَابِ مُحْضَرُونَ', NULL, 22, 173, 5, 432, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 39, 'قُلْ إِنَّ رَبِّى يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ مِنْ عِبَادِهِۦ وَيَقْدِرُ لَهُۥ ۚ وَمَآ أَنفَقْتُم مِّن شَىْءٍۢ فَهُوَ يُخْلِفُهُۥ ۖ وَهُوَ خَيْرُ ٱلرَّٰزِقِينَ', NULL, 22, 173, 5, 432, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 40, 'وَيَوْمَ يَحْشُرُهُمْ جَمِيعًۭا ثُمَّ يَقُولُ لِلْمَلَٰٓئِكَةِ أَهَٰٓؤُلَآءِ إِيَّاكُمْ كَانُوا۟ يَعْبُدُونَ', NULL, 22, 173, 5, 433, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 41, 'قَالُوا۟ سُبْحَٰنَكَ أَنتَ وَلِيُّنَا مِن دُونِهِم ۖ بَلْ كَانُوا۟ يَعْبُدُونَ ٱلْجِنَّ ۖ أَكْثَرُهُم بِهِم مُّؤْمِنُونَ', NULL, 22, 173, 5, 433, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 42, 'فَٱلْيَوْمَ لَا يَمْلِكُ بَعْضُكُمْ لِبَعْضٍۢ نَّفْعًۭا وَلَا ضَرًّۭا وَنَقُولُ لِلَّذِينَ ظَلَمُوا۟ ذُوقُوا۟ عَذَابَ ٱلنَّارِ ٱلَّتِى كُنتُم بِهَا تُكَذِّبُونَ', NULL, 22, 173, 5, 433, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 43, 'وَإِذَا تُتْلَىٰ عَلَيْهِمْ ءَايَٰتُنَا بَيِّنَٰتٍۢ قَالُوا۟ مَا هَٰذَآ إِلَّا رَجُلٌۭ يُرِيدُ أَن يَصُدَّكُمْ عَمَّا كَانَ يَعْبُدُ ءَابَآؤُكُمْ وَقَالُوا۟ مَا هَٰذَآ إِلَّآ إِفْكٌۭ مُّفْتَرًۭى ۚ وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لِلْحَقِّ لَمَّا جَآءَهُمْ إِنْ هَٰذَآ إِلَّا سِحْرٌۭ مُّبِينٌۭ', NULL, 22, 173, 5, 433, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 44, 'وَمَآ ءَاتَيْنَٰهُم مِّن كُتُبٍۢ يَدْرُسُونَهَا ۖ وَمَآ أَرْسَلْنَآ إِلَيْهِمْ قَبْلَكَ مِن نَّذِيرٍۢ', NULL, 22, 173, 5, 433, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 45, 'وَكَذَّبَ ٱلَّذِينَ مِن قَبْلِهِمْ وَمَا بَلَغُوا۟ مِعْشَارَ مَآ ءَاتَيْنَٰهُمْ فَكَذَّبُوا۟ رُسُلِى ۖ فَكَيْفَ كَانَ نَكِيرِ', NULL, 22, 173, 5, 433, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 46, '۞ قُلْ إِنَّمَآ أَعِظُكُم بِوَٰحِدَةٍ ۖ أَن تَقُومُوا۟ لِلَّهِ مَثْنَىٰ وَفُرَٰدَىٰ ثُمَّ تَتَفَكَّرُوا۟ ۚ مَا بِصَاحِبِكُم مِّن جِنَّةٍ ۚ إِنْ هُوَ إِلَّا نَذِيرٌۭ لَّكُم بَيْنَ يَدَىْ عَذَابٍۢ شَدِيدٍۢ', NULL, 22, 174, 5, 433, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 47, 'قُلْ مَا سَأَلْتُكُم مِّنْ أَجْرٍۢ فَهُوَ لَكُمْ ۖ إِنْ أَجْرِىَ إِلَّا عَلَى ٱللَّهِ ۖ وَهُوَ عَلَىٰ كُلِّ شَىْءٍۢ شَهِيدٌۭ', NULL, 22, 174, 5, 433, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 48, 'قُلْ إِنَّ رَبِّى يَقْذِفُ بِٱلْحَقِّ عَلَّٰمُ ٱلْغُيُوبِ', NULL, 22, 174, 5, 433, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 49, 'قُلْ جَآءَ ٱلْحَقُّ وَمَا يُبْدِئُ ٱلْبَٰطِلُ وَمَا يُعِيدُ', NULL, 22, 174, 5, 434, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 50, 'قُلْ إِن ضَلَلْتُ فَإِنَّمَآ أَضِلُّ عَلَىٰ نَفْسِى ۖ وَإِنِ ٱهْتَدَيْتُ فَبِمَا يُوحِىٓ إِلَىَّ رَبِّىٓ ۚ إِنَّهُۥ سَمِيعٌۭ قَرِيبٌۭ', NULL, 22, 174, 5, 434, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 51, 'وَلَوْ تَرَىٰٓ إِذْ فَزِعُوا۟ فَلَا فَوْتَ وَأُخِذُوا۟ مِن مَّكَانٍۢ قَرِيبٍۢ', NULL, 22, 174, 5, 434, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 52, 'وَقَالُوٓا۟ ءَامَنَّا بِهِۦ وَأَنَّىٰ لَهُمُ ٱلتَّنَاوُشُ مِن مَّكَانٍۭ بَعِيدٍۢ', NULL, 22, 174, 5, 434, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 53, 'وَقَدْ كَفَرُوا۟ بِهِۦ مِن قَبْلُ ۖ وَيَقْذِفُونَ بِٱلْغَيْبِ مِن مَّكَانٍۭ بَعِيدٍۢ', NULL, 22, 174, 5, 434, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 34), 54, 'وَحِيلَ بَيْنَهُمْ وَبَيْنَ مَا يَشْتَهُونَ كَمَا فُعِلَ بِأَشْيَاعِهِم مِّن قَبْلُ ۚ إِنَّهُمْ كَانُوا۟ فِى شَكٍّۢ مُّرِيبٍۭ', NULL, 22, 174, 5, 434, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ ٱلْحَمْدُ لِلَّهِ فَاطِرِ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ جَاعِلِ ٱلْمَلَٰٓئِكَةِ رُسُلًا أُو۟لِىٓ أَجْنِحَةٍۢ مَّثْنَىٰ وَثُلَٰثَ وَرُبَٰعَ ۚ يَزِيدُ فِى ٱلْخَلْقِ مَا يَشَآءُ ۚ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ', NULL, 22, 174, 5, 434, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 2, 'مَّا يَفْتَحِ ٱللَّهُ لِلنَّاسِ مِن رَّحْمَةٍۢ فَلَا مُمْسِكَ لَهَا ۖ وَمَا يُمْسِكْ فَلَا مُرْسِلَ لَهُۥ مِنۢ بَعْدِهِۦ ۚ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ', NULL, 22, 174, 5, 434, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 3, 'يَٰٓأَيُّهَا ٱلنَّاسُ ٱذْكُرُوا۟ نِعْمَتَ ٱللَّهِ عَلَيْكُمْ ۚ هَلْ مِنْ خَٰلِقٍ غَيْرُ ٱللَّهِ يَرْزُقُكُم مِّنَ ٱلسَّمَآءِ وَٱلْأَرْضِ ۚ لَآ إِلَٰهَ إِلَّا هُوَ ۖ فَأَنَّىٰ تُؤْفَكُونَ', NULL, 22, 174, 5, 434, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 4, 'وَإِن يُكَذِّبُوكَ فَقَدْ كُذِّبَتْ رُسُلٌۭ مِّن قَبْلِكَ ۚ وَإِلَى ٱللَّهِ تُرْجَعُ ٱلْأُمُورُ', NULL, 22, 174, 5, 435, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 5, 'يَٰٓأَيُّهَا ٱلنَّاسُ إِنَّ وَعْدَ ٱللَّهِ حَقٌّۭ ۖ فَلَا تَغُرَّنَّكُمُ ٱلْحَيَوٰةُ ٱلدُّنْيَا ۖ وَلَا يَغُرَّنَّكُم بِٱللَّهِ ٱلْغَرُورُ', NULL, 22, 174, 5, 435, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 6, 'إِنَّ ٱلشَّيْطَٰنَ لَكُمْ عَدُوٌّۭ فَٱتَّخِذُوهُ عَدُوًّا ۚ إِنَّمَا يَدْعُوا۟ حِزْبَهُۥ لِيَكُونُوا۟ مِنْ أَصْحَٰبِ ٱلسَّعِيرِ', NULL, 22, 174, 5, 435, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 7, 'ٱلَّذِينَ كَفَرُوا۟ لَهُمْ عَذَابٌۭ شَدِيدٌۭ ۖ وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ لَهُم مَّغْفِرَةٌۭ وَأَجْرٌۭ كَبِيرٌ', NULL, 22, 174, 5, 435, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 8, 'أَفَمَن زُيِّنَ لَهُۥ سُوٓءُ عَمَلِهِۦ فَرَءَاهُ حَسَنًۭا ۖ فَإِنَّ ٱللَّهَ يُضِلُّ مَن يَشَآءُ وَيَهْدِى مَن يَشَآءُ ۖ فَلَا تَذْهَبْ نَفْسُكَ عَلَيْهِمْ حَسَرَٰتٍ ۚ إِنَّ ٱللَّهَ عَلِيمٌۢ بِمَا يَصْنَعُونَ', NULL, 22, 174, 5, 435, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 9, 'وَٱللَّهُ ٱلَّذِىٓ أَرْسَلَ ٱلرِّيَٰحَ فَتُثِيرُ سَحَابًۭا فَسُقْنَٰهُ إِلَىٰ بَلَدٍۢ مَّيِّتٍۢ فَأَحْيَيْنَا بِهِ ٱلْأَرْضَ بَعْدَ مَوْتِهَا ۚ كَذَٰلِكَ ٱلنُّشُورُ', NULL, 22, 174, 5, 435, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 10, 'مَن كَانَ يُرِيدُ ٱلْعِزَّةَ فَلِلَّهِ ٱلْعِزَّةُ جَمِيعًا ۚ إِلَيْهِ يَصْعَدُ ٱلْكَلِمُ ٱلطَّيِّبُ وَٱلْعَمَلُ ٱلصَّٰلِحُ يَرْفَعُهُۥ ۚ وَٱلَّذِينَ يَمْكُرُونَ ٱلسَّيِّـَٔاتِ لَهُمْ عَذَابٌۭ شَدِيدٌۭ ۖ وَمَكْرُ أُو۟لَٰٓئِكَ هُوَ يَبُورُ', NULL, 22, 174, 5, 435, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 11, 'وَٱللَّهُ خَلَقَكُم مِّن تُرَابٍۢ ثُمَّ مِن نُّطْفَةٍۢ ثُمَّ جَعَلَكُمْ أَزْوَٰجًۭا ۚ وَمَا تَحْمِلُ مِنْ أُنثَىٰ وَلَا تَضَعُ إِلَّا بِعِلْمِهِۦ ۚ وَمَا يُعَمَّرُ مِن مُّعَمَّرٍۢ وَلَا يُنقَصُ مِنْ عُمُرِهِۦٓ إِلَّا فِى كِتَٰبٍ ۚ إِنَّ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرٌۭ', NULL, 22, 174, 5, 435, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 12, 'وَمَا يَسْتَوِى ٱلْبَحْرَانِ هَٰذَا عَذْبٌۭ فُرَاتٌۭ سَآئِغٌۭ شَرَابُهُۥ وَهَٰذَا مِلْحٌ أُجَاجٌۭ ۖ وَمِن كُلٍّۢ تَأْكُلُونَ لَحْمًۭا طَرِيًّۭا وَتَسْتَخْرِجُونَ حِلْيَةًۭ تَلْبَسُونَهَا ۖ وَتَرَى ٱلْفُلْكَ فِيهِ مَوَاخِرَ لِتَبْتَغُوا۟ مِن فَضْلِهِۦ وَلَعَلَّكُمْ تَشْكُرُونَ', NULL, 22, 174, 5, 436, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 13, 'يُولِجُ ٱلَّيْلَ فِى ٱلنَّهَارِ وَيُولِجُ ٱلنَّهَارَ فِى ٱلَّيْلِ وَسَخَّرَ ٱلشَّمْسَ وَٱلْقَمَرَ كُلٌّۭ يَجْرِى لِأَجَلٍۢ مُّسَمًّۭى ۚ ذَٰلِكُمُ ٱللَّهُ رَبُّكُمْ لَهُ ٱلْمُلْكُ ۚ وَٱلَّذِينَ تَدْعُونَ مِن دُونِهِۦ مَا يَمْلِكُونَ مِن قِطْمِيرٍ', NULL, 22, 174, 5, 436, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 14, 'إِن تَدْعُوهُمْ لَا يَسْمَعُوا۟ دُعَآءَكُمْ وَلَوْ سَمِعُوا۟ مَا ٱسْتَجَابُوا۟ لَكُمْ ۖ وَيَوْمَ ٱلْقِيَٰمَةِ يَكْفُرُونَ بِشِرْكِكُمْ ۚ وَلَا يُنَبِّئُكَ مِثْلُ خَبِيرٍۢ', NULL, 22, 174, 5, 436, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 15, '۞ يَٰٓأَيُّهَا ٱلنَّاسُ أَنتُمُ ٱلْفُقَرَآءُ إِلَى ٱللَّهِ ۖ وَٱللَّهُ هُوَ ٱلْغَنِىُّ ٱلْحَمِيدُ', NULL, 22, 175, 5, 436, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 16, 'إِن يَشَأْ يُذْهِبْكُمْ وَيَأْتِ بِخَلْقٍۢ جَدِيدٍۢ', NULL, 22, 175, 5, 436, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 17, 'وَمَا ذَٰلِكَ عَلَى ٱللَّهِ بِعَزِيزٍۢ', NULL, 22, 175, 5, 436, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 18, 'وَلَا تَزِرُ وَازِرَةٌۭ وِزْرَ أُخْرَىٰ ۚ وَإِن تَدْعُ مُثْقَلَةٌ إِلَىٰ حِمْلِهَا لَا يُحْمَلْ مِنْهُ شَىْءٌۭ وَلَوْ كَانَ ذَا قُرْبَىٰٓ ۗ إِنَّمَا تُنذِرُ ٱلَّذِينَ يَخْشَوْنَ رَبَّهُم بِٱلْغَيْبِ وَأَقَامُوا۟ ٱلصَّلَوٰةَ ۚ وَمَن تَزَكَّىٰ فَإِنَّمَا يَتَزَكَّىٰ لِنَفْسِهِۦ ۚ وَإِلَى ٱللَّهِ ٱلْمَصِيرُ', NULL, 22, 175, 5, 436, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 19, 'وَمَا يَسْتَوِى ٱلْأَعْمَىٰ وَٱلْبَصِيرُ', NULL, 22, 175, 5, 437, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 20, 'وَلَا ٱلظُّلُمَٰتُ وَلَا ٱلنُّورُ', NULL, 22, 175, 5, 437, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 21, 'وَلَا ٱلظِّلُّ وَلَا ٱلْحَرُورُ', NULL, 22, 175, 5, 437, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 22, 'وَمَا يَسْتَوِى ٱلْأَحْيَآءُ وَلَا ٱلْأَمْوَٰتُ ۚ إِنَّ ٱللَّهَ يُسْمِعُ مَن يَشَآءُ ۖ وَمَآ أَنتَ بِمُسْمِعٍۢ مَّن فِى ٱلْقُبُورِ', NULL, 22, 175, 5, 437, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 23, 'إِنْ أَنتَ إِلَّا نَذِيرٌ', NULL, 22, 175, 5, 437, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 24, 'إِنَّآ أَرْسَلْنَٰكَ بِٱلْحَقِّ بَشِيرًۭا وَنَذِيرًۭا ۚ وَإِن مِّنْ أُمَّةٍ إِلَّا خَلَا فِيهَا نَذِيرٌۭ', NULL, 22, 175, 5, 437, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 25, 'وَإِن يُكَذِّبُوكَ فَقَدْ كَذَّبَ ٱلَّذِينَ مِن قَبْلِهِمْ جَآءَتْهُمْ رُسُلُهُم بِٱلْبَيِّنَٰتِ وَبِٱلزُّبُرِ وَبِٱلْكِتَٰبِ ٱلْمُنِيرِ', NULL, 22, 175, 5, 437, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 26, 'ثُمَّ أَخَذْتُ ٱلَّذِينَ كَفَرُوا۟ ۖ فَكَيْفَ كَانَ نَكِيرِ', NULL, 22, 175, 5, 437, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 27, 'أَلَمْ تَرَ أَنَّ ٱللَّهَ أَنزَلَ مِنَ ٱلسَّمَآءِ مَآءًۭ فَأَخْرَجْنَا بِهِۦ ثَمَرَٰتٍۢ مُّخْتَلِفًا أَلْوَٰنُهَا ۚ وَمِنَ ٱلْجِبَالِ جُدَدٌۢ بِيضٌۭ وَحُمْرٌۭ مُّخْتَلِفٌ أَلْوَٰنُهَا وَغَرَابِيبُ سُودٌۭ', NULL, 22, 175, 5, 437, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 28, 'وَمِنَ ٱلنَّاسِ وَٱلدَّوَآبِّ وَٱلْأَنْعَٰمِ مُخْتَلِفٌ أَلْوَٰنُهُۥ كَذَٰلِكَ ۗ إِنَّمَا يَخْشَى ٱللَّهَ مِنْ عِبَادِهِ ٱلْعُلَمَٰٓؤُا۟ ۗ إِنَّ ٱللَّهَ عَزِيزٌ غَفُورٌ', NULL, 22, 175, 5, 437, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 29, 'إِنَّ ٱلَّذِينَ يَتْلُونَ كِتَٰبَ ٱللَّهِ وَأَقَامُوا۟ ٱلصَّلَوٰةَ وَأَنفَقُوا۟ مِمَّا رَزَقْنَٰهُمْ سِرًّۭا وَعَلَانِيَةًۭ يَرْجُونَ تِجَٰرَةًۭ لَّن تَبُورَ', NULL, 22, 175, 5, 437, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 30, 'لِيُوَفِّيَهُمْ أُجُورَهُمْ وَيَزِيدَهُم مِّن فَضْلِهِۦٓ ۚ إِنَّهُۥ غَفُورٌۭ شَكُورٌۭ', NULL, 22, 175, 5, 437, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 31, 'وَٱلَّذِىٓ أَوْحَيْنَآ إِلَيْكَ مِنَ ٱلْكِتَٰبِ هُوَ ٱلْحَقُّ مُصَدِّقًۭا لِّمَا بَيْنَ يَدَيْهِ ۗ إِنَّ ٱللَّهَ بِعِبَادِهِۦ لَخَبِيرٌۢ بَصِيرٌۭ', NULL, 22, 175, 5, 438, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 32, 'ثُمَّ أَوْرَثْنَا ٱلْكِتَٰبَ ٱلَّذِينَ ٱصْطَفَيْنَا مِنْ عِبَادِنَا ۖ فَمِنْهُمْ ظَالِمٌۭ لِّنَفْسِهِۦ وَمِنْهُم مُّقْتَصِدٌۭ وَمِنْهُمْ سَابِقٌۢ بِٱلْخَيْرَٰتِ بِإِذْنِ ٱللَّهِ ۚ ذَٰلِكَ هُوَ ٱلْفَضْلُ ٱلْكَبِيرُ', NULL, 22, 175, 5, 438, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 33, 'جَنَّٰتُ عَدْنٍۢ يَدْخُلُونَهَا يُحَلَّوْنَ فِيهَا مِنْ أَسَاوِرَ مِن ذَهَبٍۢ وَلُؤْلُؤًۭا ۖ وَلِبَاسُهُمْ فِيهَا حَرِيرٌۭ', NULL, 22, 175, 5, 438, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 34, 'وَقَالُوا۟ ٱلْحَمْدُ لِلَّهِ ٱلَّذِىٓ أَذْهَبَ عَنَّا ٱلْحَزَنَ ۖ إِنَّ رَبَّنَا لَغَفُورٌۭ شَكُورٌ', NULL, 22, 175, 5, 438, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 35, 'ٱلَّذِىٓ أَحَلَّنَا دَارَ ٱلْمُقَامَةِ مِن فَضْلِهِۦ لَا يَمَسُّنَا فِيهَا نَصَبٌۭ وَلَا يَمَسُّنَا فِيهَا لُغُوبٌۭ', NULL, 22, 175, 5, 438, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 36, 'وَٱلَّذِينَ كَفَرُوا۟ لَهُمْ نَارُ جَهَنَّمَ لَا يُقْضَىٰ عَلَيْهِمْ فَيَمُوتُوا۟ وَلَا يُخَفَّفُ عَنْهُم مِّنْ عَذَابِهَا ۚ كَذَٰلِكَ نَجْزِى كُلَّ كَفُورٍۢ', NULL, 22, 175, 5, 438, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 37, 'وَهُمْ يَصْطَرِخُونَ فِيهَا رَبَّنَآ أَخْرِجْنَا نَعْمَلْ صَٰلِحًا غَيْرَ ٱلَّذِى كُنَّا نَعْمَلُ ۚ أَوَلَمْ نُعَمِّرْكُم مَّا يَتَذَكَّرُ فِيهِ مَن تَذَكَّرَ وَجَآءَكُمُ ٱلنَّذِيرُ ۖ فَذُوقُوا۟ فَمَا لِلظَّٰلِمِينَ مِن نَّصِيرٍ', NULL, 22, 175, 5, 438, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 38, 'إِنَّ ٱللَّهَ عَٰلِمُ غَيْبِ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ إِنَّهُۥ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ', NULL, 22, 175, 5, 438, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 39, 'هُوَ ٱلَّذِى جَعَلَكُمْ خَلَٰٓئِفَ فِى ٱلْأَرْضِ ۚ فَمَن كَفَرَ فَعَلَيْهِ كُفْرُهُۥ ۖ وَلَا يَزِيدُ ٱلْكَٰفِرِينَ كُفْرُهُمْ عِندَ رَبِّهِمْ إِلَّا مَقْتًۭا ۖ وَلَا يَزِيدُ ٱلْكَٰفِرِينَ كُفْرُهُمْ إِلَّا خَسَارًۭا', NULL, 22, 175, 5, 439, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 40, 'قُلْ أَرَءَيْتُمْ شُرَكَآءَكُمُ ٱلَّذِينَ تَدْعُونَ مِن دُونِ ٱللَّهِ أَرُونِى مَاذَا خَلَقُوا۟ مِنَ ٱلْأَرْضِ أَمْ لَهُمْ شِرْكٌۭ فِى ٱلسَّمَٰوَٰتِ أَمْ ءَاتَيْنَٰهُمْ كِتَٰبًۭا فَهُمْ عَلَىٰ بَيِّنَتٍۢ مِّنْهُ ۚ بَلْ إِن يَعِدُ ٱلظَّٰلِمُونَ بَعْضُهُم بَعْضًا إِلَّا غُرُورًا', NULL, 22, 175, 5, 439, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 41, '۞ إِنَّ ٱللَّهَ يُمْسِكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ أَن تَزُولَا ۚ وَلَئِن زَالَتَآ إِنْ أَمْسَكَهُمَا مِنْ أَحَدٍۢ مِّنۢ بَعْدِهِۦٓ ۚ إِنَّهُۥ كَانَ حَلِيمًا غَفُورًۭا', NULL, 22, 176, 5, 439, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 42, 'وَأَقْسَمُوا۟ بِٱللَّهِ جَهْدَ أَيْمَٰنِهِمْ لَئِن جَآءَهُمْ نَذِيرٌۭ لَّيَكُونُنَّ أَهْدَىٰ مِنْ إِحْدَى ٱلْأُمَمِ ۖ فَلَمَّا جَآءَهُمْ نَذِيرٌۭ مَّا زَادَهُمْ إِلَّا نُفُورًا', NULL, 22, 176, 5, 439, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 43, 'ٱسْتِكْبَارًۭا فِى ٱلْأَرْضِ وَمَكْرَ ٱلسَّيِّئِ ۚ وَلَا يَحِيقُ ٱلْمَكْرُ ٱلسَّيِّئُ إِلَّا بِأَهْلِهِۦ ۚ فَهَلْ يَنظُرُونَ إِلَّا سُنَّتَ ٱلْأَوَّلِينَ ۚ فَلَن تَجِدَ لِسُنَّتِ ٱللَّهِ تَبْدِيلًۭا ۖ وَلَن تَجِدَ لِسُنَّتِ ٱللَّهِ تَحْوِيلًا', NULL, 22, 176, 5, 439, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 44, 'أَوَلَمْ يَسِيرُوا۟ فِى ٱلْأَرْضِ فَيَنظُرُوا۟ كَيْفَ كَانَ عَٰقِبَةُ ٱلَّذِينَ مِن قَبْلِهِمْ وَكَانُوٓا۟ أَشَدَّ مِنْهُمْ قُوَّةًۭ ۚ وَمَا كَانَ ٱللَّهُ لِيُعْجِزَهُۥ مِن شَىْءٍۢ فِى ٱلسَّمَٰوَٰتِ وَلَا فِى ٱلْأَرْضِ ۚ إِنَّهُۥ كَانَ عَلِيمًۭا قَدِيرًۭا', NULL, 22, 176, 5, 439, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 35), 45, 'وَلَوْ يُؤَاخِذُ ٱللَّهُ ٱلنَّاسَ بِمَا كَسَبُوا۟ مَا تَرَكَ عَلَىٰ ظَهْرِهَا مِن دَآبَّةٍۢ وَلَٰكِن يُؤَخِّرُهُمْ إِلَىٰٓ أَجَلٍۢ مُّسَمًّۭى ۖ فَإِذَا جَآءَ أَجَلُهُمْ فَإِنَّ ٱللَّهَ كَانَ بِعِبَادِهِۦ بَصِيرًۢا', NULL, 22, 176, 5, 440, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ يسٓ', NULL, 22, 176, 5, 440, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 2, 'وَٱلْقُرْءَانِ ٱلْحَكِيمِ', NULL, 22, 176, 5, 440, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 3, 'إِنَّكَ لَمِنَ ٱلْمُرْسَلِينَ', NULL, 22, 176, 5, 440, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 4, 'عَلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍۢ', NULL, 22, 176, 5, 440, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 5, 'تَنزِيلَ ٱلْعَزِيزِ ٱلرَّحِيمِ', NULL, 22, 176, 5, 440, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 6, 'لِتُنذِرَ قَوْمًۭا مَّآ أُنذِرَ ءَابَآؤُهُمْ فَهُمْ غَٰفِلُونَ', NULL, 22, 176, 5, 440, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 7, 'لَقَدْ حَقَّ ٱلْقَوْلُ عَلَىٰٓ أَكْثَرِهِمْ فَهُمْ لَا يُؤْمِنُونَ', NULL, 22, 176, 5, 440, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 8, 'إِنَّا جَعَلْنَا فِىٓ أَعْنَٰقِهِمْ أَغْلَٰلًۭا فَهِىَ إِلَى ٱلْأَذْقَانِ فَهُم مُّقْمَحُونَ', NULL, 22, 176, 5, 440, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 9, 'وَجَعَلْنَا مِنۢ بَيْنِ أَيْدِيهِمْ سَدًّۭا وَمِنْ خَلْفِهِمْ سَدًّۭا فَأَغْشَيْنَٰهُمْ فَهُمْ لَا يُبْصِرُونَ', NULL, 22, 176, 5, 440, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 10, 'وَسَوَآءٌ عَلَيْهِمْ ءَأَنذَرْتَهُمْ أَمْ لَمْ تُنذِرْهُمْ لَا يُؤْمِنُونَ', NULL, 22, 176, 5, 440, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 11, 'إِنَّمَا تُنذِرُ مَنِ ٱتَّبَعَ ٱلذِّكْرَ وَخَشِىَ ٱلرَّحْمَٰنَ بِٱلْغَيْبِ ۖ فَبَشِّرْهُ بِمَغْفِرَةٍۢ وَأَجْرٍۢ كَرِيمٍ', NULL, 22, 176, 5, 440, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 12, 'إِنَّا نَحْنُ نُحْىِ ٱلْمَوْتَىٰ وَنَكْتُبُ مَا قَدَّمُوا۟ وَءَاثَٰرَهُمْ ۚ وَكُلَّ شَىْءٍ أَحْصَيْنَٰهُ فِىٓ إِمَامٍۢ مُّبِينٍۢ', NULL, 22, 176, 5, 440, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 13, 'وَٱضْرِبْ لَهُم مَّثَلًا أَصْحَٰبَ ٱلْقَرْيَةِ إِذْ جَآءَهَا ٱلْمُرْسَلُونَ', NULL, 22, 176, 5, 441, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 14, 'إِذْ أَرْسَلْنَآ إِلَيْهِمُ ٱثْنَيْنِ فَكَذَّبُوهُمَا فَعَزَّزْنَا بِثَالِثٍۢ فَقَالُوٓا۟ إِنَّآ إِلَيْكُم مُّرْسَلُونَ', NULL, 22, 176, 5, 441, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 15, 'قَالُوا۟ مَآ أَنتُمْ إِلَّا بَشَرٌۭ مِّثْلُنَا وَمَآ أَنزَلَ ٱلرَّحْمَٰنُ مِن شَىْءٍ إِنْ أَنتُمْ إِلَّا تَكْذِبُونَ', NULL, 22, 176, 5, 441, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 16, 'قَالُوا۟ رَبُّنَا يَعْلَمُ إِنَّآ إِلَيْكُمْ لَمُرْسَلُونَ', NULL, 22, 176, 5, 441, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 17, 'وَمَا عَلَيْنَآ إِلَّا ٱلْبَلَٰغُ ٱلْمُبِينُ', NULL, 22, 176, 5, 441, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 18, 'قَالُوٓا۟ إِنَّا تَطَيَّرْنَا بِكُمْ ۖ لَئِن لَّمْ تَنتَهُوا۟ لَنَرْجُمَنَّكُمْ وَلَيَمَسَّنَّكُم مِّنَّا عَذَابٌ أَلِيمٌۭ', NULL, 22, 176, 5, 441, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 19, 'قَالُوا۟ طَٰٓئِرُكُم مَّعَكُمْ ۚ أَئِن ذُكِّرْتُم ۚ بَلْ أَنتُمْ قَوْمٌۭ مُّسْرِفُونَ', NULL, 22, 176, 5, 441, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 20, 'وَجَآءَ مِنْ أَقْصَا ٱلْمَدِينَةِ رَجُلٌۭ يَسْعَىٰ قَالَ يَٰقَوْمِ ٱتَّبِعُوا۟ ٱلْمُرْسَلِينَ', NULL, 22, 176, 5, 441, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 21, 'ٱتَّبِعُوا۟ مَن لَّا يَسْـَٔلُكُمْ أَجْرًۭا وَهُم مُّهْتَدُونَ', NULL, 22, 176, 5, 441, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 22, 'وَمَا لِىَ لَآ أَعْبُدُ ٱلَّذِى فَطَرَنِى وَإِلَيْهِ تُرْجَعُونَ', NULL, 22, 176, 5, 441, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 23, 'ءَأَتَّخِذُ مِن دُونِهِۦٓ ءَالِهَةً إِن يُرِدْنِ ٱلرَّحْمَٰنُ بِضُرٍّۢ لَّا تُغْنِ عَنِّى شَفَٰعَتُهُمْ شَيْـًۭٔا وَلَا يُنقِذُونِ', NULL, 22, 176, 5, 441, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 24, 'إِنِّىٓ إِذًۭا لَّفِى ضَلَٰلٍۢ مُّبِينٍ', NULL, 22, 176, 5, 441, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 25, 'إِنِّىٓ ءَامَنتُ بِرَبِّكُمْ فَٱسْمَعُونِ', NULL, 22, 176, 5, 441, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 26, 'قِيلَ ٱدْخُلِ ٱلْجَنَّةَ ۖ قَالَ يَٰلَيْتَ قَوْمِى يَعْلَمُونَ', NULL, 22, 176, 5, 441, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 27, 'بِمَا غَفَرَ لِى رَبِّى وَجَعَلَنِى مِنَ ٱلْمُكْرَمِينَ', NULL, 22, 176, 5, 441, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 28, '۞ وَمَآ أَنزَلْنَا عَلَىٰ قَوْمِهِۦ مِنۢ بَعْدِهِۦ مِن جُندٍۢ مِّنَ ٱلسَّمَآءِ وَمَا كُنَّا مُنزِلِينَ', NULL, 23, 177, 5, 442, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 29, 'إِن كَانَتْ إِلَّا صَيْحَةًۭ وَٰحِدَةًۭ فَإِذَا هُمْ خَٰمِدُونَ', NULL, 23, 177, 5, 442, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 30, 'يَٰحَسْرَةً عَلَى ٱلْعِبَادِ ۚ مَا يَأْتِيهِم مِّن رَّسُولٍ إِلَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ', NULL, 23, 177, 5, 442, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 31, 'أَلَمْ يَرَوْا۟ كَمْ أَهْلَكْنَا قَبْلَهُم مِّنَ ٱلْقُرُونِ أَنَّهُمْ إِلَيْهِمْ لَا يَرْجِعُونَ', NULL, 23, 177, 5, 442, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 32, 'وَإِن كُلٌّۭ لَّمَّا جَمِيعٌۭ لَّدَيْنَا مُحْضَرُونَ', NULL, 23, 177, 5, 442, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 33, 'وَءَايَةٌۭ لَّهُمُ ٱلْأَرْضُ ٱلْمَيْتَةُ أَحْيَيْنَٰهَا وَأَخْرَجْنَا مِنْهَا حَبًّۭا فَمِنْهُ يَأْكُلُونَ', NULL, 23, 177, 5, 442, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 34, 'وَجَعَلْنَا فِيهَا جَنَّٰتٍۢ مِّن نَّخِيلٍۢ وَأَعْنَٰبٍۢ وَفَجَّرْنَا فِيهَا مِنَ ٱلْعُيُونِ', NULL, 23, 177, 5, 442, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 35, 'لِيَأْكُلُوا۟ مِن ثَمَرِهِۦ وَمَا عَمِلَتْهُ أَيْدِيهِمْ ۖ أَفَلَا يَشْكُرُونَ', NULL, 23, 177, 5, 442, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 36, 'سُبْحَٰنَ ٱلَّذِى خَلَقَ ٱلْأَزْوَٰجَ كُلَّهَا مِمَّا تُنۢبِتُ ٱلْأَرْضُ وَمِنْ أَنفُسِهِمْ وَمِمَّا لَا يَعْلَمُونَ', NULL, 23, 177, 5, 442, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 37, 'وَءَايَةٌۭ لَّهُمُ ٱلَّيْلُ نَسْلَخُ مِنْهُ ٱلنَّهَارَ فَإِذَا هُم مُّظْلِمُونَ', NULL, 23, 177, 5, 442, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 38, 'وَٱلشَّمْسُ تَجْرِى لِمُسْتَقَرٍّۢ لَّهَا ۚ ذَٰلِكَ تَقْدِيرُ ٱلْعَزِيزِ ٱلْعَلِيمِ', NULL, 23, 177, 5, 442, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 39, 'وَٱلْقَمَرَ قَدَّرْنَٰهُ مَنَازِلَ حَتَّىٰ عَادَ كَٱلْعُرْجُونِ ٱلْقَدِيمِ', NULL, 23, 177, 5, 442, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 40, 'لَا ٱلشَّمْسُ يَنۢبَغِى لَهَآ أَن تُدْرِكَ ٱلْقَمَرَ وَلَا ٱلَّيْلُ سَابِقُ ٱلنَّهَارِ ۚ وَكُلٌّۭ فِى فَلَكٍۢ يَسْبَحُونَ', NULL, 23, 177, 5, 442, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 41, 'وَءَايَةٌۭ لَّهُمْ أَنَّا حَمَلْنَا ذُرِّيَّتَهُمْ فِى ٱلْفُلْكِ ٱلْمَشْحُونِ', NULL, 23, 177, 5, 443, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 42, 'وَخَلَقْنَا لَهُم مِّن مِّثْلِهِۦ مَا يَرْكَبُونَ', NULL, 23, 177, 5, 443, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 43, 'وَإِن نَّشَأْ نُغْرِقْهُمْ فَلَا صَرِيخَ لَهُمْ وَلَا هُمْ يُنقَذُونَ', NULL, 23, 177, 5, 443, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 44, 'إِلَّا رَحْمَةًۭ مِّنَّا وَمَتَٰعًا إِلَىٰ حِينٍۢ', NULL, 23, 177, 5, 443, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 45, 'وَإِذَا قِيلَ لَهُمُ ٱتَّقُوا۟ مَا بَيْنَ أَيْدِيكُمْ وَمَا خَلْفَكُمْ لَعَلَّكُمْ تُرْحَمُونَ', NULL, 23, 177, 5, 443, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 46, 'وَمَا تَأْتِيهِم مِّنْ ءَايَةٍۢ مِّنْ ءَايَٰتِ رَبِّهِمْ إِلَّا كَانُوا۟ عَنْهَا مُعْرِضِينَ', NULL, 23, 177, 5, 443, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 47, 'وَإِذَا قِيلَ لَهُمْ أَنفِقُوا۟ مِمَّا رَزَقَكُمُ ٱللَّهُ قَالَ ٱلَّذِينَ كَفَرُوا۟ لِلَّذِينَ ءَامَنُوٓا۟ أَنُطْعِمُ مَن لَّوْ يَشَآءُ ٱللَّهُ أَطْعَمَهُۥٓ إِنْ أَنتُمْ إِلَّا فِى ضَلَٰلٍۢ مُّبِينٍۢ', NULL, 23, 177, 5, 443, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 48, 'وَيَقُولُونَ مَتَىٰ هَٰذَا ٱلْوَعْدُ إِن كُنتُمْ صَٰدِقِينَ', NULL, 23, 177, 5, 443, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 49, 'مَا يَنظُرُونَ إِلَّا صَيْحَةًۭ وَٰحِدَةًۭ تَأْخُذُهُمْ وَهُمْ يَخِصِّمُونَ', NULL, 23, 177, 5, 443, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 50, 'فَلَا يَسْتَطِيعُونَ تَوْصِيَةًۭ وَلَآ إِلَىٰٓ أَهْلِهِمْ يَرْجِعُونَ', NULL, 23, 177, 5, 443, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 51, 'وَنُفِخَ فِى ٱلصُّورِ فَإِذَا هُم مِّنَ ٱلْأَجْدَاثِ إِلَىٰ رَبِّهِمْ يَنسِلُونَ', NULL, 23, 177, 5, 443, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 52, 'قَالُوا۟ يَٰوَيْلَنَا مَنۢ بَعَثَنَا مِن مَّرْقَدِنَا ۜ ۗ هَٰذَا مَا وَعَدَ ٱلرَّحْمَٰنُ وَصَدَقَ ٱلْمُرْسَلُونَ', NULL, 23, 177, 5, 443, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 53, 'إِن كَانَتْ إِلَّا صَيْحَةًۭ وَٰحِدَةًۭ فَإِذَا هُمْ جَمِيعٌۭ لَّدَيْنَا مُحْضَرُونَ', NULL, 23, 177, 5, 443, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 54, 'فَٱلْيَوْمَ لَا تُظْلَمُ نَفْسٌۭ شَيْـًۭٔا وَلَا تُجْزَوْنَ إِلَّا مَا كُنتُمْ تَعْمَلُونَ', NULL, 23, 177, 5, 443, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 55, 'إِنَّ أَصْحَٰبَ ٱلْجَنَّةِ ٱلْيَوْمَ فِى شُغُلٍۢ فَٰكِهُونَ', NULL, 23, 177, 5, 444, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 56, 'هُمْ وَأَزْوَٰجُهُمْ فِى ظِلَٰلٍ عَلَى ٱلْأَرَآئِكِ مُتَّكِـُٔونَ', NULL, 23, 177, 5, 444, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 57, 'لَهُمْ فِيهَا فَٰكِهَةٌۭ وَلَهُم مَّا يَدَّعُونَ', NULL, 23, 177, 5, 444, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 58, 'سَلَٰمٌۭ قَوْلًۭا مِّن رَّبٍّۢ رَّحِيمٍۢ', NULL, 23, 177, 5, 444, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 59, 'وَٱمْتَٰزُوا۟ ٱلْيَوْمَ أَيُّهَا ٱلْمُجْرِمُونَ', NULL, 23, 177, 5, 444, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 60, '۞ أَلَمْ أَعْهَدْ إِلَيْكُمْ يَٰبَنِىٓ ءَادَمَ أَن لَّا تَعْبُدُوا۟ ٱلشَّيْطَٰنَ ۖ إِنَّهُۥ لَكُمْ عَدُوٌّۭ مُّبِينٌۭ', NULL, 23, 178, 5, 444, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 61, 'وَأَنِ ٱعْبُدُونِى ۚ هَٰذَا صِرَٰطٌۭ مُّسْتَقِيمٌۭ', NULL, 23, 178, 5, 444, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 62, 'وَلَقَدْ أَضَلَّ مِنكُمْ جِبِلًّۭا كَثِيرًا ۖ أَفَلَمْ تَكُونُوا۟ تَعْقِلُونَ', NULL, 23, 178, 5, 444, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 63, 'هَٰذِهِۦ جَهَنَّمُ ٱلَّتِى كُنتُمْ تُوعَدُونَ', NULL, 23, 178, 5, 444, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 64, 'ٱصْلَوْهَا ٱلْيَوْمَ بِمَا كُنتُمْ تَكْفُرُونَ', NULL, 23, 178, 5, 444, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 65, 'ٱلْيَوْمَ نَخْتِمُ عَلَىٰٓ أَفْوَٰهِهِمْ وَتُكَلِّمُنَآ أَيْدِيهِمْ وَتَشْهَدُ أَرْجُلُهُم بِمَا كَانُوا۟ يَكْسِبُونَ', NULL, 23, 178, 5, 444, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 66, 'وَلَوْ نَشَآءُ لَطَمَسْنَا عَلَىٰٓ أَعْيُنِهِمْ فَٱسْتَبَقُوا۟ ٱلصِّرَٰطَ فَأَنَّىٰ يُبْصِرُونَ', NULL, 23, 178, 5, 444, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 67, 'وَلَوْ نَشَآءُ لَمَسَخْنَٰهُمْ عَلَىٰ مَكَانَتِهِمْ فَمَا ٱسْتَطَٰعُوا۟ مُضِيًّۭا وَلَا يَرْجِعُونَ', NULL, 23, 178, 5, 444, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 68, 'وَمَن نُّعَمِّرْهُ نُنَكِّسْهُ فِى ٱلْخَلْقِ ۖ أَفَلَا يَعْقِلُونَ', NULL, 23, 178, 5, 444, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 69, 'وَمَا عَلَّمْنَٰهُ ٱلشِّعْرَ وَمَا يَنۢبَغِى لَهُۥٓ ۚ إِنْ هُوَ إِلَّا ذِكْرٌۭ وَقُرْءَانٌۭ مُّبِينٌۭ', NULL, 23, 178, 5, 444, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 70, 'لِّيُنذِرَ مَن كَانَ حَيًّۭا وَيَحِقَّ ٱلْقَوْلُ عَلَى ٱلْكَٰفِرِينَ', NULL, 23, 178, 5, 444, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 71, 'أَوَلَمْ يَرَوْا۟ أَنَّا خَلَقْنَا لَهُم مِّمَّا عَمِلَتْ أَيْدِينَآ أَنْعَٰمًۭا فَهُمْ لَهَا مَٰلِكُونَ', NULL, 23, 178, 5, 445, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 72, 'وَذَلَّلْنَٰهَا لَهُمْ فَمِنْهَا رَكُوبُهُمْ وَمِنْهَا يَأْكُلُونَ', NULL, 23, 178, 5, 445, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 73, 'وَلَهُمْ فِيهَا مَنَٰفِعُ وَمَشَارِبُ ۖ أَفَلَا يَشْكُرُونَ', NULL, 23, 178, 5, 445, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 74, 'وَٱتَّخَذُوا۟ مِن دُونِ ٱللَّهِ ءَالِهَةًۭ لَّعَلَّهُمْ يُنصَرُونَ', NULL, 23, 178, 5, 445, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 75, 'لَا يَسْتَطِيعُونَ نَصْرَهُمْ وَهُمْ لَهُمْ جُندٌۭ مُّحْضَرُونَ', NULL, 23, 178, 5, 445, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 76, 'فَلَا يَحْزُنكَ قَوْلُهُمْ ۘ إِنَّا نَعْلَمُ مَا يُسِرُّونَ وَمَا يُعْلِنُونَ', NULL, 23, 178, 5, 445, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 77, 'أَوَلَمْ يَرَ ٱلْإِنسَٰنُ أَنَّا خَلَقْنَٰهُ مِن نُّطْفَةٍۢ فَإِذَا هُوَ خَصِيمٌۭ مُّبِينٌۭ', NULL, 23, 178, 5, 445, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 78, 'وَضَرَبَ لَنَا مَثَلًۭا وَنَسِىَ خَلْقَهُۥ ۖ قَالَ مَن يُحْىِ ٱلْعِظَٰمَ وَهِىَ رَمِيمٌۭ', NULL, 23, 178, 5, 445, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 79, 'قُلْ يُحْيِيهَا ٱلَّذِىٓ أَنشَأَهَآ أَوَّلَ مَرَّةٍۢ ۖ وَهُوَ بِكُلِّ خَلْقٍ عَلِيمٌ', NULL, 23, 178, 5, 445, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 80, 'ٱلَّذِى جَعَلَ لَكُم مِّنَ ٱلشَّجَرِ ٱلْأَخْضَرِ نَارًۭا فَإِذَآ أَنتُم مِّنْهُ تُوقِدُونَ', NULL, 23, 178, 5, 445, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 81, 'أَوَلَيْسَ ٱلَّذِى خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ بِقَٰدِرٍ عَلَىٰٓ أَن يَخْلُقَ مِثْلَهُم ۚ بَلَىٰ وَهُوَ ٱلْخَلَّٰقُ ٱلْعَلِيمُ', NULL, 23, 178, 5, 445, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 82, 'إِنَّمَآ أَمْرُهُۥٓ إِذَآ أَرَادَ شَيْـًٔا أَن يَقُولَ لَهُۥ كُن فَيَكُونُ', NULL, 23, 178, 5, 445, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 36), 83, 'فَسُبْحَٰنَ ٱلَّذِى بِيَدِهِۦ مَلَكُوتُ كُلِّ شَىْءٍۢ وَإِلَيْهِ تُرْجَعُونَ', NULL, 23, 178, 5, 445, false, NOW(), NOW()),
