((SELECT id FROM mst_surah WHERE surah_number = 37), 178, 'وَتَوَلَّ عَنْهُمْ حَتَّىٰ حِينٍۢ', NULL, 23, 181, 6, 452, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 37), 179, 'وَأَبْصِرْ فَسَوْفَ يُبْصِرُونَ', NULL, 23, 181, 6, 452, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 37), 180, 'سُبْحَٰنَ رَبِّكَ رَبِّ ٱلْعِزَّةِ عَمَّا يَصِفُونَ', NULL, 23, 181, 6, 452, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 37), 181, 'وَسَلَٰمٌ عَلَى ٱلْمُرْسَلِينَ', NULL, 23, 181, 6, 452, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 37), 182, 'وَٱلْحَمْدُ لِلَّهِ رَبِّ ٱلْعَٰلَمِينَ', NULL, 23, 181, 6, 452, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ صٓ ۚ وَٱلْقُرْءَانِ ذِى ٱلذِّكْرِ', NULL, 23, 181, 6, 453, false, NOW(), NOW()),
