((SELECT id FROM mst_surah WHERE surah_number = 38), 3, 'كَمْ أَهْلَكْنَا مِن قَبْلِهِم مِّن قَرْنٍۢ فَنَادَوا۟ وَّلَاتَ حِينَ مَنَاصٍۢ', NULL, 23, 181, 6, 453, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 4, 'وَعَجِبُوٓا۟ أَن جَآءَهُم مُّنذِرٌۭ مِّنْهُمْ ۖ وَقَالَ ٱلْكَٰفِرُونَ هَٰذَا سَٰحِرٌۭ كَذَّابٌ', NULL, 23, 181, 6, 453, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 5, 'أَجَعَلَ ٱلْءَالِهَةَ إِلَٰهًۭا وَٰحِدًا ۖ إِنَّ هَٰذَا لَشَىْءٌ عُجَابٌۭ', NULL, 23, 181, 6, 453, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 6, 'وَٱنطَلَقَ ٱلْمَلَأُ مِنْهُمْ أَنِ ٱمْشُوا۟ وَٱصْبِرُوا۟ عَلَىٰٓ ءَالِهَتِكُمْ ۖ إِنَّ هَٰذَا لَشَىْءٌۭ يُرَادُ', NULL, 23, 181, 6, 453, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 7, 'مَا سَمِعْنَا بِهَٰذَا فِى ٱلْمِلَّةِ ٱلْءَاخِرَةِ إِنْ هَٰذَآ إِلَّا ٱخْتِلَٰقٌ', NULL, 23, 181, 6, 453, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 8, 'أَءُنزِلَ عَلَيْهِ ٱلذِّكْرُ مِنۢ بَيْنِنَا ۚ بَلْ هُمْ فِى شَكٍّۢ مِّن ذِكْرِى ۖ بَل لَّمَّا يَذُوقُوا۟ عَذَابِ', NULL, 23, 181, 6, 453, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 9, 'أَمْ عِندَهُمْ خَزَآئِنُ رَحْمَةِ رَبِّكَ ٱلْعَزِيزِ ٱلْوَهَّابِ', NULL, 23, 181, 6, 453, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 10, 'أَمْ لَهُم مُّلْكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَمَا بَيْنَهُمَا ۖ فَلْيَرْتَقُوا۟ فِى ٱلْأَسْبَٰبِ', NULL, 23, 181, 6, 453, false, NOW(), NOW()),
