((SELECT id FROM mst_surah WHERE surah_number = 38), 12, 'كَذَّبَتْ قَبْلَهُمْ قَوْمُ نُوحٍۢ وَعَادٌۭ وَفِرْعَوْنُ ذُو ٱلْأَوْتَادِ', NULL, 23, 181, 6, 453, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 13, 'وَثَمُودُ وَقَوْمُ لُوطٍۢ وَأَصْحَٰبُ لْـَٔيْكَةِ ۚ أُو۟لَٰٓئِكَ ٱلْأَحْزَابُ', NULL, 23, 181, 6, 453, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 14, 'إِن كُلٌّ إِلَّا كَذَّبَ ٱلرُّسُلَ فَحَقَّ عِقَابِ', NULL, 23, 181, 6, 453, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 15, 'وَمَا يَنظُرُ هَٰٓؤُلَآءِ إِلَّا صَيْحَةًۭ وَٰحِدَةًۭ مَّا لَهَا مِن فَوَاقٍۢ', NULL, 23, 181, 6, 453, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 16, 'وَقَالُوا۟ رَبَّنَا عَجِّل لَّنَا قِطَّنَا قَبْلَ يَوْمِ ٱلْحِسَابِ', NULL, 23, 181, 6, 453, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 17, 'ٱصْبِرْ عَلَىٰ مَا يَقُولُونَ وَٱذْكُرْ عَبْدَنَا دَاوُۥدَ ذَا ٱلْأَيْدِ ۖ إِنَّهُۥٓ أَوَّابٌ', NULL, 23, 181, 6, 454, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 18, 'إِنَّا سَخَّرْنَا ٱلْجِبَالَ مَعَهُۥ يُسَبِّحْنَ بِٱلْعَشِىِّ وَٱلْإِشْرَاقِ', NULL, 23, 181, 6, 454, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 19, 'وَٱلطَّيْرَ مَحْشُورَةًۭ ۖ كُلٌّۭ لَّهُۥٓ أَوَّابٌۭ', NULL, 23, 181, 6, 454, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 20, 'وَشَدَدْنَا مُلْكَهُۥ وَءَاتَيْنَٰهُ ٱلْحِكْمَةَ وَفَصْلَ ٱلْخِطَابِ', NULL, 23, 181, 6, 454, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 21, '۞ وَهَلْ أَتَىٰكَ نَبَؤُا۟ ٱلْخَصْمِ إِذْ تَسَوَّرُوا۟ ٱلْمِحْرَابَ', NULL, 23, 182, 6, 454, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 22, 'إِذْ دَخَلُوا۟ عَلَىٰ دَاوُۥدَ فَفَزِعَ مِنْهُمْ ۖ قَالُوا۟ لَا تَخَفْ ۖ خَصْمَانِ بَغَىٰ بَعْضُنَا عَلَىٰ بَعْضٍۢ فَٱحْكُم بَيْنَنَا بِٱلْحَقِّ وَلَا تُشْطِطْ وَٱهْدِنَآ إِلَىٰ سَوَآءِ ٱلصِّرَٰطِ', NULL, 23, 182, 6, 454, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 23, 'إِنَّ هَٰذَآ أَخِى لَهُۥ تِسْعٌۭ وَتِسْعُونَ نَعْجَةًۭ وَلِىَ نَعْجَةٌۭ وَٰحِدَةٌۭ فَقَالَ أَكْفِلْنِيهَا وَعَزَّنِى فِى ٱلْخِطَابِ', NULL, 23, 182, 6, 454, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 24, 'قَالَ لَقَدْ ظَلَمَكَ بِسُؤَالِ نَعْجَتِكَ إِلَىٰ نِعَاجِهِۦ ۖ وَإِنَّ كَثِيرًۭا مِّنَ ٱلْخُلَطَآءِ لَيَبْغِى بَعْضُهُمْ عَلَىٰ بَعْضٍ إِلَّا ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ وَقَلِيلٌۭ مَّا هُمْ ۗ وَظَنَّ دَاوُۥدُ أَنَّمَا فَتَنَّٰهُ فَٱسْتَغْفَرَ رَبَّهُۥ وَخَرَّ رَاكِعًۭا وَأَنَابَ ۩', NULL, 23, 182, 6, 454, true, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 25, 'فَغَفَرْنَا لَهُۥ ذَٰلِكَ ۖ وَإِنَّ لَهُۥ عِندَنَا لَزُلْفَىٰ وَحُسْنَ مَـَٔابٍۢ', NULL, 23, 182, 6, 454, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 26, 'يَٰدَاوُۥدُ إِنَّا جَعَلْنَٰكَ خَلِيفَةًۭ فِى ٱلْأَرْضِ فَٱحْكُم بَيْنَ ٱلنَّاسِ بِٱلْحَقِّ وَلَا تَتَّبِعِ ٱلْهَوَىٰ فَيُضِلَّكَ عَن سَبِيلِ ٱللَّهِ ۚ إِنَّ ٱلَّذِينَ يَضِلُّونَ عَن سَبِيلِ ٱللَّهِ لَهُمْ عَذَابٌۭ شَدِيدٌۢ بِمَا نَسُوا۟ يَوْمَ ٱلْحِسَابِ', NULL, 23, 182, 6, 454, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 27, 'وَمَا خَلَقْنَا ٱلسَّمَآءَ وَٱلْأَرْضَ وَمَا بَيْنَهُمَا بَٰطِلًۭا ۚ ذَٰلِكَ ظَنُّ ٱلَّذِينَ كَفَرُوا۟ ۚ فَوَيْلٌۭ لِّلَّذِينَ كَفَرُوا۟ مِنَ ٱلنَّارِ', NULL, 23, 182, 6, 455, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 28, 'أَمْ نَجْعَلُ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ كَٱلْمُفْسِدِينَ فِى ٱلْأَرْضِ أَمْ نَجْعَلُ ٱلْمُتَّقِينَ كَٱلْفُجَّارِ', NULL, 23, 182, 6, 455, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 29, 'كِتَٰبٌ أَنزَلْنَٰهُ إِلَيْكَ مُبَٰرَكٌۭ لِّيَدَّبَّرُوٓا۟ ءَايَٰتِهِۦ وَلِيَتَذَكَّرَ أُو۟لُوا۟ ٱلْأَلْبَٰبِ', NULL, 23, 182, 6, 455, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 30, 'وَوَهَبْنَا لِدَاوُۥدَ سُلَيْمَٰنَ ۚ نِعْمَ ٱلْعَبْدُ ۖ إِنَّهُۥٓ أَوَّابٌ', NULL, 23, 182, 6, 455, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 31, 'إِذْ عُرِضَ عَلَيْهِ بِٱلْعَشِىِّ ٱلصَّٰفِنَٰتُ ٱلْجِيَادُ', NULL, 23, 182, 6, 455, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 32, 'فَقَالَ إِنِّىٓ أَحْبَبْتُ حُبَّ ٱلْخَيْرِ عَن ذِكْرِ رَبِّى حَتَّىٰ تَوَارَتْ بِٱلْحِجَابِ', NULL, 23, 182, 6, 455, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 33, 'رُدُّوهَا عَلَىَّ ۖ فَطَفِقَ مَسْحًۢا بِٱلسُّوقِ وَٱلْأَعْنَاقِ', NULL, 23, 182, 6, 455, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 34, 'وَلَقَدْ فَتَنَّا سُلَيْمَٰنَ وَأَلْقَيْنَا عَلَىٰ كُرْسِيِّهِۦ جَسَدًۭا ثُمَّ أَنَابَ', NULL, 23, 182, 6, 455, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 35, 'قَالَ رَبِّ ٱغْفِرْ لِى وَهَبْ لِى مُلْكًۭا لَّا يَنۢبَغِى لِأَحَدٍۢ مِّنۢ بَعْدِىٓ ۖ إِنَّكَ أَنتَ ٱلْوَهَّابُ', NULL, 23, 182, 6, 455, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 36, 'فَسَخَّرْنَا لَهُ ٱلرِّيحَ تَجْرِى بِأَمْرِهِۦ رُخَآءً حَيْثُ أَصَابَ', NULL, 23, 182, 6, 455, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 37, 'وَٱلشَّيَٰطِينَ كُلَّ بَنَّآءٍۢ وَغَوَّاصٍۢ', NULL, 23, 182, 6, 455, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 38, 'وَءَاخَرِينَ مُقَرَّنِينَ فِى ٱلْأَصْفَادِ', NULL, 23, 182, 6, 455, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 39, 'هَٰذَا عَطَآؤُنَا فَٱمْنُنْ أَوْ أَمْسِكْ بِغَيْرِ حِسَابٍۢ', NULL, 23, 182, 6, 455, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 40, 'وَإِنَّ لَهُۥ عِندَنَا لَزُلْفَىٰ وَحُسْنَ مَـَٔابٍۢ', NULL, 23, 182, 6, 455, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 41, 'وَٱذْكُرْ عَبْدَنَآ أَيُّوبَ إِذْ نَادَىٰ رَبَّهُۥٓ أَنِّى مَسَّنِىَ ٱلشَّيْطَٰنُ بِنُصْبٍۢ وَعَذَابٍ', NULL, 23, 182, 6, 455, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 42, 'ٱرْكُضْ بِرِجْلِكَ ۖ هَٰذَا مُغْتَسَلٌۢ بَارِدٌۭ وَشَرَابٌۭ', NULL, 23, 182, 6, 455, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 43, 'وَوَهَبْنَا لَهُۥٓ أَهْلَهُۥ وَمِثْلَهُم مَّعَهُمْ رَحْمَةًۭ مِّنَّا وَذِكْرَىٰ لِأُو۟لِى ٱلْأَلْبَٰبِ', NULL, 23, 182, 6, 456, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 44, 'وَخُذْ بِيَدِكَ ضِغْثًۭا فَٱضْرِب بِّهِۦ وَلَا تَحْنَثْ ۗ إِنَّا وَجَدْنَٰهُ صَابِرًۭا ۚ نِّعْمَ ٱلْعَبْدُ ۖ إِنَّهُۥٓ أَوَّابٌۭ', NULL, 23, 182, 6, 456, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 45, 'وَٱذْكُرْ عِبَٰدَنَآ إِبْرَٰهِيمَ وَإِسْحَٰقَ وَيَعْقُوبَ أُو۟لِى ٱلْأَيْدِى وَٱلْأَبْصَٰرِ', NULL, 23, 182, 6, 456, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 46, 'إِنَّآ أَخْلَصْنَٰهُم بِخَالِصَةٍۢ ذِكْرَى ٱلدَّارِ', NULL, 23, 182, 6, 456, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 47, 'وَإِنَّهُمْ عِندَنَا لَمِنَ ٱلْمُصْطَفَيْنَ ٱلْأَخْيَارِ', NULL, 23, 182, 6, 456, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 48, 'وَٱذْكُرْ إِسْمَٰعِيلَ وَٱلْيَسَعَ وَذَا ٱلْكِفْلِ ۖ وَكُلٌّۭ مِّنَ ٱلْأَخْيَارِ', NULL, 23, 182, 6, 456, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 49, 'هَٰذَا ذِكْرٌۭ ۚ وَإِنَّ لِلْمُتَّقِينَ لَحُسْنَ مَـَٔابٍۢ', NULL, 23, 182, 6, 456, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 50, 'جَنَّٰتِ عَدْنٍۢ مُّفَتَّحَةًۭ لَّهُمُ ٱلْأَبْوَٰبُ', NULL, 23, 182, 6, 456, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 51, 'مُتَّكِـِٔينَ فِيهَا يَدْعُونَ فِيهَا بِفَٰكِهَةٍۢ كَثِيرَةٍۢ وَشَرَابٍۢ', NULL, 23, 182, 6, 456, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 52, '۞ وَعِندَهُمْ قَٰصِرَٰتُ ٱلطَّرْفِ أَتْرَابٌ', NULL, 23, 183, 6, 456, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 53, 'هَٰذَا مَا تُوعَدُونَ لِيَوْمِ ٱلْحِسَابِ', NULL, 23, 183, 6, 456, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 54, 'إِنَّ هَٰذَا لَرِزْقُنَا مَا لَهُۥ مِن نَّفَادٍ', NULL, 23, 183, 6, 456, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 55, 'هَٰذَا ۚ وَإِنَّ لِلطَّٰغِينَ لَشَرَّ مَـَٔابٍۢ', NULL, 23, 183, 6, 456, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 56, 'جَهَنَّمَ يَصْلَوْنَهَا فَبِئْسَ ٱلْمِهَادُ', NULL, 23, 183, 6, 456, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 57, 'هَٰذَا فَلْيَذُوقُوهُ حَمِيمٌۭ وَغَسَّاقٌۭ', NULL, 23, 183, 6, 456, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 58, 'وَءَاخَرُ مِن شَكْلِهِۦٓ أَزْوَٰجٌ', NULL, 23, 183, 6, 456, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 59, 'هَٰذَا فَوْجٌۭ مُّقْتَحِمٌۭ مَّعَكُمْ ۖ لَا مَرْحَبًۢا بِهِمْ ۚ إِنَّهُمْ صَالُوا۟ ٱلنَّارِ', NULL, 23, 183, 6, 456, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 60, 'قَالُوا۟ بَلْ أَنتُمْ لَا مَرْحَبًۢا بِكُمْ ۖ أَنتُمْ قَدَّمْتُمُوهُ لَنَا ۖ فَبِئْسَ ٱلْقَرَارُ', NULL, 23, 183, 6, 456, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 61, 'قَالُوا۟ رَبَّنَا مَن قَدَّمَ لَنَا هَٰذَا فَزِدْهُ عَذَابًۭا ضِعْفًۭا فِى ٱلنَّارِ', NULL, 23, 183, 6, 456, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 62, 'وَقَالُوا۟ مَا لَنَا لَا نَرَىٰ رِجَالًۭا كُنَّا نَعُدُّهُم مِّنَ ٱلْأَشْرَارِ', NULL, 23, 183, 6, 457, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 63, 'أَتَّخَذْنَٰهُمْ سِخْرِيًّا أَمْ زَاغَتْ عَنْهُمُ ٱلْأَبْصَٰرُ', NULL, 23, 183, 6, 457, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 64, 'إِنَّ ذَٰلِكَ لَحَقٌّۭ تَخَاصُمُ أَهْلِ ٱلنَّارِ', NULL, 23, 183, 6, 457, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 65, 'قُلْ إِنَّمَآ أَنَا۠ مُنذِرٌۭ ۖ وَمَا مِنْ إِلَٰهٍ إِلَّا ٱللَّهُ ٱلْوَٰحِدُ ٱلْقَهَّارُ', NULL, 23, 183, 6, 457, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 66, 'رَبُّ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَمَا بَيْنَهُمَا ٱلْعَزِيزُ ٱلْغَفَّٰرُ', NULL, 23, 183, 6, 457, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 67, 'قُلْ هُوَ نَبَؤٌا۟ عَظِيمٌ', NULL, 23, 183, 6, 457, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 68, 'أَنتُمْ عَنْهُ مُعْرِضُونَ', NULL, 23, 183, 6, 457, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 69, 'مَا كَانَ لِىَ مِنْ عِلْمٍۭ بِٱلْمَلَإِ ٱلْأَعْلَىٰٓ إِذْ يَخْتَصِمُونَ', NULL, 23, 183, 6, 457, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 70, 'إِن يُوحَىٰٓ إِلَىَّ إِلَّآ أَنَّمَآ أَنَا۠ نَذِيرٌۭ مُّبِينٌ', NULL, 23, 183, 6, 457, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 71, 'إِذْ قَالَ رَبُّكَ لِلْمَلَٰٓئِكَةِ إِنِّى خَٰلِقٌۢ بَشَرًۭا مِّن طِينٍۢ', NULL, 23, 183, 6, 457, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 72, 'فَإِذَا سَوَّيْتُهُۥ وَنَفَخْتُ فِيهِ مِن رُّوحِى فَقَعُوا۟ لَهُۥ سَٰجِدِينَ', NULL, 23, 183, 6, 457, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 73, 'فَسَجَدَ ٱلْمَلَٰٓئِكَةُ كُلُّهُمْ أَجْمَعُونَ', NULL, 23, 183, 6, 457, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 74, 'إِلَّآ إِبْلِيسَ ٱسْتَكْبَرَ وَكَانَ مِنَ ٱلْكَٰفِرِينَ', NULL, 23, 183, 6, 457, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 75, 'قَالَ يَٰٓإِبْلِيسُ مَا مَنَعَكَ أَن تَسْجُدَ لِمَا خَلَقْتُ بِيَدَىَّ ۖ أَسْتَكْبَرْتَ أَمْ كُنتَ مِنَ ٱلْعَالِينَ', NULL, 23, 183, 6, 457, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 76, 'قَالَ أَنَا۠ خَيْرٌۭ مِّنْهُ ۖ خَلَقْتَنِى مِن نَّارٍۢ وَخَلَقْتَهُۥ مِن طِينٍۢ', NULL, 23, 183, 6, 457, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 77, 'قَالَ فَٱخْرُجْ مِنْهَا فَإِنَّكَ رَجِيمٌۭ', NULL, 23, 183, 6, 457, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 78, 'وَإِنَّ عَلَيْكَ لَعْنَتِىٓ إِلَىٰ يَوْمِ ٱلدِّينِ', NULL, 23, 183, 6, 457, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 79, 'قَالَ رَبِّ فَأَنظِرْنِىٓ إِلَىٰ يَوْمِ يُبْعَثُونَ', NULL, 23, 183, 6, 457, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 80, 'قَالَ فَإِنَّكَ مِنَ ٱلْمُنظَرِينَ', NULL, 23, 183, 6, 457, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 81, 'إِلَىٰ يَوْمِ ٱلْوَقْتِ ٱلْمَعْلُومِ', NULL, 23, 183, 6, 457, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 82, 'قَالَ فَبِعِزَّتِكَ لَأُغْوِيَنَّهُمْ أَجْمَعِينَ', NULL, 23, 183, 6, 457, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 83, 'إِلَّا عِبَادَكَ مِنْهُمُ ٱلْمُخْلَصِينَ', NULL, 23, 183, 6, 457, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 84, 'قَالَ فَٱلْحَقُّ وَٱلْحَقَّ أَقُولُ', NULL, 23, 183, 6, 458, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 85, 'لَأَمْلَأَنَّ جَهَنَّمَ مِنكَ وَمِمَّن تَبِعَكَ مِنْهُمْ أَجْمَعِينَ', NULL, 23, 183, 6, 458, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 86, 'قُلْ مَآ أَسْـَٔلُكُمْ عَلَيْهِ مِنْ أَجْرٍۢ وَمَآ أَنَا۠ مِنَ ٱلْمُتَكَلِّفِينَ', NULL, 23, 183, 6, 458, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 87, 'إِنْ هُوَ إِلَّا ذِكْرٌۭ لِّلْعَٰلَمِينَ', NULL, 23, 183, 6, 458, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 38), 88, 'وَلَتَعْلَمُنَّ نَبَأَهُۥ بَعْدَ حِينٍۭ', NULL, 23, 183, 6, 458, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ تَنزِيلُ ٱلْكِتَٰبِ مِنَ ٱللَّهِ ٱلْعَزِيزِ ٱلْحَكِيمِ', NULL, 23, 183, 6, 458, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 2, 'إِنَّآ أَنزَلْنَآ إِلَيْكَ ٱلْكِتَٰبَ بِٱلْحَقِّ فَٱعْبُدِ ٱللَّهَ مُخْلِصًۭا لَّهُ ٱلدِّينَ', NULL, 23, 183, 6, 458, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 3, 'أَلَا لِلَّهِ ٱلدِّينُ ٱلْخَالِصُ ۚ وَٱلَّذِينَ ٱتَّخَذُوا۟ مِن دُونِهِۦٓ أَوْلِيَآءَ مَا نَعْبُدُهُمْ إِلَّا لِيُقَرِّبُونَآ إِلَى ٱللَّهِ زُلْفَىٰٓ إِنَّ ٱللَّهَ يَحْكُمُ بَيْنَهُمْ فِى مَا هُمْ فِيهِ يَخْتَلِفُونَ ۗ إِنَّ ٱللَّهَ لَا يَهْدِى مَنْ هُوَ كَٰذِبٌۭ كَفَّارٌۭ', NULL, 23, 183, 6, 458, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 4, 'لَّوْ أَرَادَ ٱللَّهُ أَن يَتَّخِذَ وَلَدًۭا لَّٱصْطَفَىٰ مِمَّا يَخْلُقُ مَا يَشَآءُ ۚ سُبْحَٰنَهُۥ ۖ هُوَ ٱللَّهُ ٱلْوَٰحِدُ ٱلْقَهَّارُ', NULL, 23, 183, 6, 458, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 5, 'خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ بِٱلْحَقِّ ۖ يُكَوِّرُ ٱلَّيْلَ عَلَى ٱلنَّهَارِ وَيُكَوِّرُ ٱلنَّهَارَ عَلَى ٱلَّيْلِ ۖ وَسَخَّرَ ٱلشَّمْسَ وَٱلْقَمَرَ ۖ كُلٌّۭ يَجْرِى لِأَجَلٍۢ مُّسَمًّى ۗ أَلَا هُوَ ٱلْعَزِيزُ ٱلْغَفَّٰرُ', NULL, 23, 183, 6, 458, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 6, 'خَلَقَكُم مِّن نَّفْسٍۢ وَٰحِدَةٍۢ ثُمَّ جَعَلَ مِنْهَا زَوْجَهَا وَأَنزَلَ لَكُم مِّنَ ٱلْأَنْعَٰمِ ثَمَٰنِيَةَ أَزْوَٰجٍۢ ۚ يَخْلُقُكُمْ فِى بُطُونِ أُمَّهَٰتِكُمْ خَلْقًۭا مِّنۢ بَعْدِ خَلْقٍۢ فِى ظُلُمَٰتٍۢ ثَلَٰثٍۢ ۚ ذَٰلِكُمُ ٱللَّهُ رَبُّكُمْ لَهُ ٱلْمُلْكُ ۖ لَآ إِلَٰهَ إِلَّا هُوَ ۖ فَأَنَّىٰ تُصْرَفُونَ', NULL, 23, 183, 6, 459, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 7, 'إِن تَكْفُرُوا۟ فَإِنَّ ٱللَّهَ غَنِىٌّ عَنكُمْ ۖ وَلَا يَرْضَىٰ لِعِبَادِهِ ٱلْكُفْرَ ۖ وَإِن تَشْكُرُوا۟ يَرْضَهُ لَكُمْ ۗ وَلَا تَزِرُ وَازِرَةٌۭ وِزْرَ أُخْرَىٰ ۗ ثُمَّ إِلَىٰ رَبِّكُم مَّرْجِعُكُمْ فَيُنَبِّئُكُم بِمَا كُنتُمْ تَعْمَلُونَ ۚ إِنَّهُۥ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ', NULL, 23, 183, 6, 459, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 8, '۞ وَإِذَا مَسَّ ٱلْإِنسَٰنَ ضُرٌّۭ دَعَا رَبَّهُۥ مُنِيبًا إِلَيْهِ ثُمَّ إِذَا خَوَّلَهُۥ نِعْمَةًۭ مِّنْهُ نَسِىَ مَا كَانَ يَدْعُوٓا۟ إِلَيْهِ مِن قَبْلُ وَجَعَلَ لِلَّهِ أَندَادًۭا لِّيُضِلَّ عَن سَبِيلِهِۦ ۚ قُلْ تَمَتَّعْ بِكُفْرِكَ قَلِيلًا ۖ إِنَّكَ مِنْ أَصْحَٰبِ ٱلنَّارِ', NULL, 23, 184, 6, 459, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 9, 'أَمَّنْ هُوَ قَٰنِتٌ ءَانَآءَ ٱلَّيْلِ سَاجِدًۭا وَقَآئِمًۭا يَحْذَرُ ٱلْءَاخِرَةَ وَيَرْجُوا۟ رَحْمَةَ رَبِّهِۦ ۗ قُلْ هَلْ يَسْتَوِى ٱلَّذِينَ يَعْلَمُونَ وَٱلَّذِينَ لَا يَعْلَمُونَ ۗ إِنَّمَا يَتَذَكَّرُ أُو۟لُوا۟ ٱلْأَلْبَٰبِ', NULL, 23, 184, 6, 459, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 10, 'قُلْ يَٰعِبَادِ ٱلَّذِينَ ءَامَنُوا۟ ٱتَّقُوا۟ رَبَّكُمْ ۚ لِلَّذِينَ أَحْسَنُوا۟ فِى هَٰذِهِ ٱلدُّنْيَا حَسَنَةٌۭ ۗ وَأَرْضُ ٱللَّهِ وَٰسِعَةٌ ۗ إِنَّمَا يُوَفَّى ٱلصَّٰبِرُونَ أَجْرَهُم بِغَيْرِ حِسَابٍۢ', NULL, 23, 184, 6, 459, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 11, 'قُلْ إِنِّىٓ أُمِرْتُ أَنْ أَعْبُدَ ٱللَّهَ مُخْلِصًۭا لَّهُ ٱلدِّينَ', NULL, 23, 184, 6, 460, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 12, 'وَأُمِرْتُ لِأَنْ أَكُونَ أَوَّلَ ٱلْمُسْلِمِينَ', NULL, 23, 184, 6, 460, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 13, 'قُلْ إِنِّىٓ أَخَافُ إِنْ عَصَيْتُ رَبِّى عَذَابَ يَوْمٍ عَظِيمٍۢ', NULL, 23, 184, 6, 460, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 14, 'قُلِ ٱللَّهَ أَعْبُدُ مُخْلِصًۭا لَّهُۥ دِينِى', NULL, 23, 184, 6, 460, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 15, 'فَٱعْبُدُوا۟ مَا شِئْتُم مِّن دُونِهِۦ ۗ قُلْ إِنَّ ٱلْخَٰسِرِينَ ٱلَّذِينَ خَسِرُوٓا۟ أَنفُسَهُمْ وَأَهْلِيهِمْ يَوْمَ ٱلْقِيَٰمَةِ ۗ أَلَا ذَٰلِكَ هُوَ ٱلْخُسْرَانُ ٱلْمُبِينُ', NULL, 23, 184, 6, 460, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 16, 'لَهُم مِّن فَوْقِهِمْ ظُلَلٌۭ مِّنَ ٱلنَّارِ وَمِن تَحْتِهِمْ ظُلَلٌۭ ۚ ذَٰلِكَ يُخَوِّفُ ٱللَّهُ بِهِۦ عِبَادَهُۥ ۚ يَٰعِبَادِ فَٱتَّقُونِ', NULL, 23, 184, 6, 460, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 17, 'وَٱلَّذِينَ ٱجْتَنَبُوا۟ ٱلطَّٰغُوتَ أَن يَعْبُدُوهَا وَأَنَابُوٓا۟ إِلَى ٱللَّهِ لَهُمُ ٱلْبُشْرَىٰ ۚ فَبَشِّرْ عِبَادِ', NULL, 23, 184, 6, 460, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 18, 'ٱلَّذِينَ يَسْتَمِعُونَ ٱلْقَوْلَ فَيَتَّبِعُونَ أَحْسَنَهُۥٓ ۚ أُو۟لَٰٓئِكَ ٱلَّذِينَ هَدَىٰهُمُ ٱللَّهُ ۖ وَأُو۟لَٰٓئِكَ هُمْ أُو۟لُوا۟ ٱلْأَلْبَٰبِ', NULL, 23, 184, 6, 460, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 19, 'أَفَمَنْ حَقَّ عَلَيْهِ كَلِمَةُ ٱلْعَذَابِ أَفَأَنتَ تُنقِذُ مَن فِى ٱلنَّارِ', NULL, 23, 184, 6, 460, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 20, 'لَٰكِنِ ٱلَّذِينَ ٱتَّقَوْا۟ رَبَّهُمْ لَهُمْ غُرَفٌۭ مِّن فَوْقِهَا غُرَفٌۭ مَّبْنِيَّةٌۭ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ ۖ وَعْدَ ٱللَّهِ ۖ لَا يُخْلِفُ ٱللَّهُ ٱلْمِيعَادَ', NULL, 23, 184, 6, 460, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 21, 'أَلَمْ تَرَ أَنَّ ٱللَّهَ أَنزَلَ مِنَ ٱلسَّمَآءِ مَآءًۭ فَسَلَكَهُۥ يَنَٰبِيعَ فِى ٱلْأَرْضِ ثُمَّ يُخْرِجُ بِهِۦ زَرْعًۭا مُّخْتَلِفًا أَلْوَٰنُهُۥ ثُمَّ يَهِيجُ فَتَرَىٰهُ مُصْفَرًّۭا ثُمَّ يَجْعَلُهُۥ حُطَٰمًا ۚ إِنَّ فِى ذَٰلِكَ لَذِكْرَىٰ لِأُو۟لِى ٱلْأَلْبَٰبِ', NULL, 23, 184, 6, 460, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 22, 'أَفَمَن شَرَحَ ٱللَّهُ صَدْرَهُۥ لِلْإِسْلَٰمِ فَهُوَ عَلَىٰ نُورٍۢ مِّن رَّبِّهِۦ ۚ فَوَيْلٌۭ لِّلْقَٰسِيَةِ قُلُوبُهُم مِّن ذِكْرِ ٱللَّهِ ۚ أُو۟لَٰٓئِكَ فِى ضَلَٰلٍۢ مُّبِينٍ', NULL, 23, 184, 6, 461, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 23, 'ٱللَّهُ نَزَّلَ أَحْسَنَ ٱلْحَدِيثِ كِتَٰبًۭا مُّتَشَٰبِهًۭا مَّثَانِىَ تَقْشَعِرُّ مِنْهُ جُلُودُ ٱلَّذِينَ يَخْشَوْنَ رَبَّهُمْ ثُمَّ تَلِينُ جُلُودُهُمْ وَقُلُوبُهُمْ إِلَىٰ ذِكْرِ ٱللَّهِ ۚ ذَٰلِكَ هُدَى ٱللَّهِ يَهْدِى بِهِۦ مَن يَشَآءُ ۚ وَمَن يُضْلِلِ ٱللَّهُ فَمَا لَهُۥ مِنْ هَادٍ', NULL, 23, 184, 6, 461, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 24, 'أَفَمَن يَتَّقِى بِوَجْهِهِۦ سُوٓءَ ٱلْعَذَابِ يَوْمَ ٱلْقِيَٰمَةِ ۚ وَقِيلَ لِلظَّٰلِمِينَ ذُوقُوا۟ مَا كُنتُمْ تَكْسِبُونَ', NULL, 23, 184, 6, 461, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 25, 'كَذَّبَ ٱلَّذِينَ مِن قَبْلِهِمْ فَأَتَىٰهُمُ ٱلْعَذَابُ مِنْ حَيْثُ لَا يَشْعُرُونَ', NULL, 23, 184, 6, 461, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 26, 'فَأَذَاقَهُمُ ٱللَّهُ ٱلْخِزْىَ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا ۖ وَلَعَذَابُ ٱلْءَاخِرَةِ أَكْبَرُ ۚ لَوْ كَانُوا۟ يَعْلَمُونَ', NULL, 23, 184, 6, 461, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 27, 'وَلَقَدْ ضَرَبْنَا لِلنَّاسِ فِى هَٰذَا ٱلْقُرْءَانِ مِن كُلِّ مَثَلٍۢ لَّعَلَّهُمْ يَتَذَكَّرُونَ', NULL, 23, 184, 6, 461, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 28, 'قُرْءَانًا عَرَبِيًّا غَيْرَ ذِى عِوَجٍۢ لَّعَلَّهُمْ يَتَّقُونَ', NULL, 23, 184, 6, 461, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 29, 'ضَرَبَ ٱللَّهُ مَثَلًۭا رَّجُلًۭا فِيهِ شُرَكَآءُ مُتَشَٰكِسُونَ وَرَجُلًۭا سَلَمًۭا لِّرَجُلٍ هَلْ يَسْتَوِيَانِ مَثَلًا ۚ ٱلْحَمْدُ لِلَّهِ ۚ بَلْ أَكْثَرُهُمْ لَا يَعْلَمُونَ', NULL, 23, 184, 6, 461, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 30, 'إِنَّكَ مَيِّتٌۭ وَإِنَّهُم مَّيِّتُونَ', NULL, 23, 184, 6, 461, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 31, 'ثُمَّ إِنَّكُمْ يَوْمَ ٱلْقِيَٰمَةِ عِندَ رَبِّكُمْ تَخْتَصِمُونَ', NULL, 23, 184, 6, 461, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 32, '۞ فَمَنْ أَظْلَمُ مِمَّن كَذَبَ عَلَى ٱللَّهِ وَكَذَّبَ بِٱلصِّدْقِ إِذْ جَآءَهُۥٓ ۚ أَلَيْسَ فِى جَهَنَّمَ مَثْوًۭى لِّلْكَٰفِرِينَ', NULL, 24, 185, 6, 462, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 33, 'وَٱلَّذِى جَآءَ بِٱلصِّدْقِ وَصَدَّقَ بِهِۦٓ ۙ أُو۟لَٰٓئِكَ هُمُ ٱلْمُتَّقُونَ', NULL, 24, 185, 6, 462, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 34, 'لَهُم مَّا يَشَآءُونَ عِندَ رَبِّهِمْ ۚ ذَٰلِكَ جَزَآءُ ٱلْمُحْسِنِينَ', NULL, 24, 185, 6, 462, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 35, 'لِيُكَفِّرَ ٱللَّهُ عَنْهُمْ أَسْوَأَ ٱلَّذِى عَمِلُوا۟ وَيَجْزِيَهُمْ أَجْرَهُم بِأَحْسَنِ ٱلَّذِى كَانُوا۟ يَعْمَلُونَ', NULL, 24, 185, 6, 462, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 36, 'أَلَيْسَ ٱللَّهُ بِكَافٍ عَبْدَهُۥ ۖ وَيُخَوِّفُونَكَ بِٱلَّذِينَ مِن دُونِهِۦ ۚ وَمَن يُضْلِلِ ٱللَّهُ فَمَا لَهُۥ مِنْ هَادٍۢ', NULL, 24, 185, 6, 462, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 37, 'وَمَن يَهْدِ ٱللَّهُ فَمَا لَهُۥ مِن مُّضِلٍّ ۗ أَلَيْسَ ٱللَّهُ بِعَزِيزٍۢ ذِى ٱنتِقَامٍۢ', NULL, 24, 185, 6, 462, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 38, 'وَلَئِن سَأَلْتَهُم مَّنْ خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ لَيَقُولُنَّ ٱللَّهُ ۚ قُلْ أَفَرَءَيْتُم مَّا تَدْعُونَ مِن دُونِ ٱللَّهِ إِنْ أَرَادَنِىَ ٱللَّهُ بِضُرٍّ هَلْ هُنَّ كَٰشِفَٰتُ ضُرِّهِۦٓ أَوْ أَرَادَنِى بِرَحْمَةٍ هَلْ هُنَّ مُمْسِكَٰتُ رَحْمَتِهِۦ ۚ قُلْ حَسْبِىَ ٱللَّهُ ۖ عَلَيْهِ يَتَوَكَّلُ ٱلْمُتَوَكِّلُونَ', NULL, 24, 185, 6, 462, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 39, 'قُلْ يَٰقَوْمِ ٱعْمَلُوا۟ عَلَىٰ مَكَانَتِكُمْ إِنِّى عَٰمِلٌۭ ۖ فَسَوْفَ تَعْلَمُونَ', NULL, 24, 185, 6, 462, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 40, 'مَن يَأْتِيهِ عَذَابٌۭ يُخْزِيهِ وَيَحِلُّ عَلَيْهِ عَذَابٌۭ مُّقِيمٌ', NULL, 24, 185, 6, 462, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 41, 'إِنَّآ أَنزَلْنَا عَلَيْكَ ٱلْكِتَٰبَ لِلنَّاسِ بِٱلْحَقِّ ۖ فَمَنِ ٱهْتَدَىٰ فَلِنَفْسِهِۦ ۖ وَمَن ضَلَّ فَإِنَّمَا يَضِلُّ عَلَيْهَا ۖ وَمَآ أَنتَ عَلَيْهِم بِوَكِيلٍ', NULL, 24, 185, 6, 463, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 42, 'ٱللَّهُ يَتَوَفَّى ٱلْأَنفُسَ حِينَ مَوْتِهَا وَٱلَّتِى لَمْ تَمُتْ فِى مَنَامِهَا ۖ فَيُمْسِكُ ٱلَّتِى قَضَىٰ عَلَيْهَا ٱلْمَوْتَ وَيُرْسِلُ ٱلْأُخْرَىٰٓ إِلَىٰٓ أَجَلٍۢ مُّسَمًّى ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّقَوْمٍۢ يَتَفَكَّرُونَ', NULL, 24, 185, 6, 463, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 43, 'أَمِ ٱتَّخَذُوا۟ مِن دُونِ ٱللَّهِ شُفَعَآءَ ۚ قُلْ أَوَلَوْ كَانُوا۟ لَا يَمْلِكُونَ شَيْـًۭٔا وَلَا يَعْقِلُونَ', NULL, 24, 185, 6, 463, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 44, 'قُل لِّلَّهِ ٱلشَّفَٰعَةُ جَمِيعًۭا ۖ لَّهُۥ مُلْكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ ثُمَّ إِلَيْهِ تُرْجَعُونَ', NULL, 24, 185, 6, 463, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 45, 'وَإِذَا ذُكِرَ ٱللَّهُ وَحْدَهُ ٱشْمَأَزَّتْ قُلُوبُ ٱلَّذِينَ لَا يُؤْمِنُونَ بِٱلْءَاخِرَةِ ۖ وَإِذَا ذُكِرَ ٱلَّذِينَ مِن دُونِهِۦٓ إِذَا هُمْ يَسْتَبْشِرُونَ', NULL, 24, 185, 6, 463, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 46, 'قُلِ ٱللَّهُمَّ فَاطِرَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ عَٰلِمَ ٱلْغَيْبِ وَٱلشَّهَٰدَةِ أَنتَ تَحْكُمُ بَيْنَ عِبَادِكَ فِى مَا كَانُوا۟ فِيهِ يَخْتَلِفُونَ', NULL, 24, 185, 6, 463, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 47, 'وَلَوْ أَنَّ لِلَّذِينَ ظَلَمُوا۟ مَا فِى ٱلْأَرْضِ جَمِيعًۭا وَمِثْلَهُۥ مَعَهُۥ لَٱفْتَدَوْا۟ بِهِۦ مِن سُوٓءِ ٱلْعَذَابِ يَوْمَ ٱلْقِيَٰمَةِ ۚ وَبَدَا لَهُم مِّنَ ٱللَّهِ مَا لَمْ يَكُونُوا۟ يَحْتَسِبُونَ', NULL, 24, 185, 6, 463, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 48, 'وَبَدَا لَهُمْ سَيِّـَٔاتُ مَا كَسَبُوا۟ وَحَاقَ بِهِم مَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ', NULL, 24, 185, 6, 464, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 49, 'فَإِذَا مَسَّ ٱلْإِنسَٰنَ ضُرٌّۭ دَعَانَا ثُمَّ إِذَا خَوَّلْنَٰهُ نِعْمَةًۭ مِّنَّا قَالَ إِنَّمَآ أُوتِيتُهُۥ عَلَىٰ عِلْمٍۭ ۚ بَلْ هِىَ فِتْنَةٌۭ وَلَٰكِنَّ أَكْثَرَهُمْ لَا يَعْلَمُونَ', NULL, 24, 185, 6, 464, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 50, 'قَدْ قَالَهَا ٱلَّذِينَ مِن قَبْلِهِمْ فَمَآ أَغْنَىٰ عَنْهُم مَّا كَانُوا۟ يَكْسِبُونَ', NULL, 24, 185, 6, 464, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 51, 'فَأَصَابَهُمْ سَيِّـَٔاتُ مَا كَسَبُوا۟ ۚ وَٱلَّذِينَ ظَلَمُوا۟ مِنْ هَٰٓؤُلَآءِ سَيُصِيبُهُمْ سَيِّـَٔاتُ مَا كَسَبُوا۟ وَمَا هُم بِمُعْجِزِينَ', NULL, 24, 185, 6, 464, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 52, 'أَوَلَمْ يَعْلَمُوٓا۟ أَنَّ ٱللَّهَ يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ وَيَقْدِرُ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّقَوْمٍۢ يُؤْمِنُونَ', NULL, 24, 185, 6, 464, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 53, '۞ قُلْ يَٰعِبَادِىَ ٱلَّذِينَ أَسْرَفُوا۟ عَلَىٰٓ أَنفُسِهِمْ لَا تَقْنَطُوا۟ مِن رَّحْمَةِ ٱللَّهِ ۚ إِنَّ ٱللَّهَ يَغْفِرُ ٱلذُّنُوبَ جَمِيعًا ۚ إِنَّهُۥ هُوَ ٱلْغَفُورُ ٱلرَّحِيمُ', NULL, 24, 186, 6, 464, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 54, 'وَأَنِيبُوٓا۟ إِلَىٰ رَبِّكُمْ وَأَسْلِمُوا۟ لَهُۥ مِن قَبْلِ أَن يَأْتِيَكُمُ ٱلْعَذَابُ ثُمَّ لَا تُنصَرُونَ', NULL, 24, 186, 6, 464, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 55, 'وَٱتَّبِعُوٓا۟ أَحْسَنَ مَآ أُنزِلَ إِلَيْكُم مِّن رَّبِّكُم مِّن قَبْلِ أَن يَأْتِيَكُمُ ٱلْعَذَابُ بَغْتَةًۭ وَأَنتُمْ لَا تَشْعُرُونَ', NULL, 24, 186, 6, 464, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 56, 'أَن تَقُولَ نَفْسٌۭ يَٰحَسْرَتَىٰ عَلَىٰ مَا فَرَّطتُ فِى جَنۢبِ ٱللَّهِ وَإِن كُنتُ لَمِنَ ٱلسَّٰخِرِينَ', NULL, 24, 186, 6, 464, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 57, 'أَوْ تَقُولَ لَوْ أَنَّ ٱللَّهَ هَدَىٰنِى لَكُنتُ مِنَ ٱلْمُتَّقِينَ', NULL, 24, 186, 6, 465, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 58, 'أَوْ تَقُولَ حِينَ تَرَى ٱلْعَذَابَ لَوْ أَنَّ لِى كَرَّةًۭ فَأَكُونَ مِنَ ٱلْمُحْسِنِينَ', NULL, 24, 186, 6, 465, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 59, 'بَلَىٰ قَدْ جَآءَتْكَ ءَايَٰتِى فَكَذَّبْتَ بِهَا وَٱسْتَكْبَرْتَ وَكُنتَ مِنَ ٱلْكَٰفِرِينَ', NULL, 24, 186, 6, 465, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 60, 'وَيَوْمَ ٱلْقِيَٰمَةِ تَرَى ٱلَّذِينَ كَذَبُوا۟ عَلَى ٱللَّهِ وُجُوهُهُم مُّسْوَدَّةٌ ۚ أَلَيْسَ فِى جَهَنَّمَ مَثْوًۭى لِّلْمُتَكَبِّرِينَ', NULL, 24, 186, 6, 465, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 61, 'وَيُنَجِّى ٱللَّهُ ٱلَّذِينَ ٱتَّقَوْا۟ بِمَفَازَتِهِمْ لَا يَمَسُّهُمُ ٱلسُّوٓءُ وَلَا هُمْ يَحْزَنُونَ', NULL, 24, 186, 6, 465, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 62, 'ٱللَّهُ خَٰلِقُ كُلِّ شَىْءٍۢ ۖ وَهُوَ عَلَىٰ كُلِّ شَىْءٍۢ وَكِيلٌۭ', NULL, 24, 186, 6, 465, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 63, 'لَّهُۥ مَقَالِيدُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۗ وَٱلَّذِينَ كَفَرُوا۟ بِـَٔايَٰتِ ٱللَّهِ أُو۟لَٰٓئِكَ هُمُ ٱلْخَٰسِرُونَ', NULL, 24, 186, 6, 465, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 64, 'قُلْ أَفَغَيْرَ ٱللَّهِ تَأْمُرُوٓنِّىٓ أَعْبُدُ أَيُّهَا ٱلْجَٰهِلُونَ', NULL, 24, 186, 6, 465, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 65, 'وَلَقَدْ أُوحِىَ إِلَيْكَ وَإِلَى ٱلَّذِينَ مِن قَبْلِكَ لَئِنْ أَشْرَكْتَ لَيَحْبَطَنَّ عَمَلُكَ وَلَتَكُونَنَّ مِنَ ٱلْخَٰسِرِينَ', NULL, 24, 186, 6, 465, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 66, 'بَلِ ٱللَّهَ فَٱعْبُدْ وَكُن مِّنَ ٱلشَّٰكِرِينَ', NULL, 24, 186, 6, 465, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 67, 'وَمَا قَدَرُوا۟ ٱللَّهَ حَقَّ قَدْرِهِۦ وَٱلْأَرْضُ جَمِيعًۭا قَبْضَتُهُۥ يَوْمَ ٱلْقِيَٰمَةِ وَٱلسَّمَٰوَٰتُ مَطْوِيَّٰتٌۢ بِيَمِينِهِۦ ۚ سُبْحَٰنَهُۥ وَتَعَٰلَىٰ عَمَّا يُشْرِكُونَ', NULL, 24, 186, 6, 465, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 68, 'وَنُفِخَ فِى ٱلصُّورِ فَصَعِقَ مَن فِى ٱلسَّمَٰوَٰتِ وَمَن فِى ٱلْأَرْضِ إِلَّا مَن شَآءَ ٱللَّهُ ۖ ثُمَّ نُفِخَ فِيهِ أُخْرَىٰ فَإِذَا هُمْ قِيَامٌۭ يَنظُرُونَ', NULL, 24, 186, 6, 466, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 69, 'وَأَشْرَقَتِ ٱلْأَرْضُ بِنُورِ رَبِّهَا وَوُضِعَ ٱلْكِتَٰبُ وَجِا۟ىٓءَ بِٱلنَّبِيِّۦنَ وَٱلشُّهَدَآءِ وَقُضِىَ بَيْنَهُم بِٱلْحَقِّ وَهُمْ لَا يُظْلَمُونَ', NULL, 24, 186, 6, 466, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 70, 'وَوُفِّيَتْ كُلُّ نَفْسٍۢ مَّا عَمِلَتْ وَهُوَ أَعْلَمُ بِمَا يَفْعَلُونَ', NULL, 24, 186, 6, 466, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 71, 'وَسِيقَ ٱلَّذِينَ كَفَرُوٓا۟ إِلَىٰ جَهَنَّمَ زُمَرًا ۖ حَتَّىٰٓ إِذَا جَآءُوهَا فُتِحَتْ أَبْوَٰبُهَا وَقَالَ لَهُمْ خَزَنَتُهَآ أَلَمْ يَأْتِكُمْ رُسُلٌۭ مِّنكُمْ يَتْلُونَ عَلَيْكُمْ ءَايَٰتِ رَبِّكُمْ وَيُنذِرُونَكُمْ لِقَآءَ يَوْمِكُمْ هَٰذَا ۚ قَالُوا۟ بَلَىٰ وَلَٰكِنْ حَقَّتْ كَلِمَةُ ٱلْعَذَابِ عَلَى ٱلْكَٰفِرِينَ', NULL, 24, 186, 6, 466, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 72, 'قِيلَ ٱدْخُلُوٓا۟ أَبْوَٰبَ جَهَنَّمَ خَٰلِدِينَ فِيهَا ۖ فَبِئْسَ مَثْوَى ٱلْمُتَكَبِّرِينَ', NULL, 24, 186, 6, 466, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 73, 'وَسِيقَ ٱلَّذِينَ ٱتَّقَوْا۟ رَبَّهُمْ إِلَى ٱلْجَنَّةِ زُمَرًا ۖ حَتَّىٰٓ إِذَا جَآءُوهَا وَفُتِحَتْ أَبْوَٰبُهَا وَقَالَ لَهُمْ خَزَنَتُهَا سَلَٰمٌ عَلَيْكُمْ طِبْتُمْ فَٱدْخُلُوهَا خَٰلِدِينَ', NULL, 24, 186, 6, 466, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 74, 'وَقَالُوا۟ ٱلْحَمْدُ لِلَّهِ ٱلَّذِى صَدَقَنَا وَعْدَهُۥ وَأَوْرَثَنَا ٱلْأَرْضَ نَتَبَوَّأُ مِنَ ٱلْجَنَّةِ حَيْثُ نَشَآءُ ۖ فَنِعْمَ أَجْرُ ٱلْعَٰمِلِينَ', NULL, 24, 186, 6, 466, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 39), 75, 'وَتَرَى ٱلْمَلَٰٓئِكَةَ حَآفِّينَ مِنْ حَوْلِ ٱلْعَرْشِ يُسَبِّحُونَ بِحَمْدِ رَبِّهِمْ ۖ وَقُضِىَ بَيْنَهُم بِٱلْحَقِّ وَقِيلَ ٱلْحَمْدُ لِلَّهِ رَبِّ ٱلْعَٰلَمِينَ', NULL, 24, 186, 6, 467, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ حمٓ', NULL, 24, 187, 6, 467, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 2, 'تَنزِيلُ ٱلْكِتَٰبِ مِنَ ٱللَّهِ ٱلْعَزِيزِ ٱلْعَلِيمِ', NULL, 24, 187, 6, 467, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 3, 'غَافِرِ ٱلذَّنۢبِ وَقَابِلِ ٱلتَّوْبِ شَدِيدِ ٱلْعِقَابِ ذِى ٱلطَّوْلِ ۖ لَآ إِلَٰهَ إِلَّا هُوَ ۖ إِلَيْهِ ٱلْمَصِيرُ', NULL, 24, 187, 6, 467, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 4, 'مَا يُجَٰدِلُ فِىٓ ءَايَٰتِ ٱللَّهِ إِلَّا ٱلَّذِينَ كَفَرُوا۟ فَلَا يَغْرُرْكَ تَقَلُّبُهُمْ فِى ٱلْبِلَٰدِ', NULL, 24, 187, 6, 467, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 5, 'كَذَّبَتْ قَبْلَهُمْ قَوْمُ نُوحٍۢ وَٱلْأَحْزَابُ مِنۢ بَعْدِهِمْ ۖ وَهَمَّتْ كُلُّ أُمَّةٍۭ بِرَسُولِهِمْ لِيَأْخُذُوهُ ۖ وَجَٰدَلُوا۟ بِٱلْبَٰطِلِ لِيُدْحِضُوا۟ بِهِ ٱلْحَقَّ فَأَخَذْتُهُمْ ۖ فَكَيْفَ كَانَ عِقَابِ', NULL, 24, 187, 6, 467, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 6, 'وَكَذَٰلِكَ حَقَّتْ كَلِمَتُ رَبِّكَ عَلَى ٱلَّذِينَ كَفَرُوٓا۟ أَنَّهُمْ أَصْحَٰبُ ٱلنَّارِ', NULL, 24, 187, 6, 467, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 7, 'ٱلَّذِينَ يَحْمِلُونَ ٱلْعَرْشَ وَمَنْ حَوْلَهُۥ يُسَبِّحُونَ بِحَمْدِ رَبِّهِمْ وَيُؤْمِنُونَ بِهِۦ وَيَسْتَغْفِرُونَ لِلَّذِينَ ءَامَنُوا۟ رَبَّنَا وَسِعْتَ كُلَّ شَىْءٍۢ رَّحْمَةًۭ وَعِلْمًۭا فَٱغْفِرْ لِلَّذِينَ تَابُوا۟ وَٱتَّبَعُوا۟ سَبِيلَكَ وَقِهِمْ عَذَابَ ٱلْجَحِيمِ', NULL, 24, 187, 6, 467, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 8, 'رَبَّنَا وَأَدْخِلْهُمْ جَنَّٰتِ عَدْنٍ ٱلَّتِى وَعَدتَّهُمْ وَمَن صَلَحَ مِنْ ءَابَآئِهِمْ وَأَزْوَٰجِهِمْ وَذُرِّيَّٰتِهِمْ ۚ إِنَّكَ أَنتَ ٱلْعَزِيزُ ٱلْحَكِيمُ', NULL, 24, 187, 6, 468, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 9, 'وَقِهِمُ ٱلسَّيِّـَٔاتِ ۚ وَمَن تَقِ ٱلسَّيِّـَٔاتِ يَوْمَئِذٍۢ فَقَدْ رَحِمْتَهُۥ ۚ وَذَٰلِكَ هُوَ ٱلْفَوْزُ ٱلْعَظِيمُ', NULL, 24, 187, 6, 468, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 10, 'إِنَّ ٱلَّذِينَ كَفَرُوا۟ يُنَادَوْنَ لَمَقْتُ ٱللَّهِ أَكْبَرُ مِن مَّقْتِكُمْ أَنفُسَكُمْ إِذْ تُدْعَوْنَ إِلَى ٱلْإِيمَٰنِ فَتَكْفُرُونَ', NULL, 24, 187, 6, 468, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 11, 'قَالُوا۟ رَبَّنَآ أَمَتَّنَا ٱثْنَتَيْنِ وَأَحْيَيْتَنَا ٱثْنَتَيْنِ فَٱعْتَرَفْنَا بِذُنُوبِنَا فَهَلْ إِلَىٰ خُرُوجٍۢ مِّن سَبِيلٍۢ', NULL, 24, 187, 6, 468, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 12, 'ذَٰلِكُم بِأَنَّهُۥٓ إِذَا دُعِىَ ٱللَّهُ وَحْدَهُۥ كَفَرْتُمْ ۖ وَإِن يُشْرَكْ بِهِۦ تُؤْمِنُوا۟ ۚ فَٱلْحُكْمُ لِلَّهِ ٱلْعَلِىِّ ٱلْكَبِيرِ', NULL, 24, 187, 6, 468, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 13, 'هُوَ ٱلَّذِى يُرِيكُمْ ءَايَٰتِهِۦ وَيُنَزِّلُ لَكُم مِّنَ ٱلسَّمَآءِ رِزْقًۭا ۚ وَمَا يَتَذَكَّرُ إِلَّا مَن يُنِيبُ', NULL, 24, 187, 6, 468, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 14, 'فَٱدْعُوا۟ ٱللَّهَ مُخْلِصِينَ لَهُ ٱلدِّينَ وَلَوْ كَرِهَ ٱلْكَٰفِرُونَ', NULL, 24, 187, 6, 468, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 15, 'رَفِيعُ ٱلدَّرَجَٰتِ ذُو ٱلْعَرْشِ يُلْقِى ٱلرُّوحَ مِنْ أَمْرِهِۦ عَلَىٰ مَن يَشَآءُ مِنْ عِبَادِهِۦ لِيُنذِرَ يَوْمَ ٱلتَّلَاقِ', NULL, 24, 187, 6, 468, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 16, 'يَوْمَ هُم بَٰرِزُونَ ۖ لَا يَخْفَىٰ عَلَى ٱللَّهِ مِنْهُمْ شَىْءٌۭ ۚ لِّمَنِ ٱلْمُلْكُ ٱلْيَوْمَ ۖ لِلَّهِ ٱلْوَٰحِدِ ٱلْقَهَّارِ', NULL, 24, 187, 6, 468, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 17, 'ٱلْيَوْمَ تُجْزَىٰ كُلُّ نَفْسٍۭ بِمَا كَسَبَتْ ۚ لَا ظُلْمَ ٱلْيَوْمَ ۚ إِنَّ ٱللَّهَ سَرِيعُ ٱلْحِسَابِ', NULL, 24, 187, 6, 469, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 18, 'وَأَنذِرْهُمْ يَوْمَ ٱلْءَازِفَةِ إِذِ ٱلْقُلُوبُ لَدَى ٱلْحَنَاجِرِ كَٰظِمِينَ ۚ مَا لِلظَّٰلِمِينَ مِنْ حَمِيمٍۢ وَلَا شَفِيعٍۢ يُطَاعُ', NULL, 24, 187, 6, 469, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 19, 'يَعْلَمُ خَآئِنَةَ ٱلْأَعْيُنِ وَمَا تُخْفِى ٱلصُّدُورُ', NULL, 24, 187, 6, 469, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 20, 'وَٱللَّهُ يَقْضِى بِٱلْحَقِّ ۖ وَٱلَّذِينَ يَدْعُونَ مِن دُونِهِۦ لَا يَقْضُونَ بِشَىْءٍ ۗ إِنَّ ٱللَّهَ هُوَ ٱلسَّمِيعُ ٱلْبَصِيرُ', NULL, 24, 187, 6, 469, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 21, '۞ أَوَلَمْ يَسِيرُوا۟ فِى ٱلْأَرْضِ فَيَنظُرُوا۟ كَيْفَ كَانَ عَٰقِبَةُ ٱلَّذِينَ كَانُوا۟ مِن قَبْلِهِمْ ۚ كَانُوا۟ هُمْ أَشَدَّ مِنْهُمْ قُوَّةًۭ وَءَاثَارًۭا فِى ٱلْأَرْضِ فَأَخَذَهُمُ ٱللَّهُ بِذُنُوبِهِمْ وَمَا كَانَ لَهُم مِّنَ ٱللَّهِ مِن وَاقٍۢ', NULL, 24, 188, 6, 469, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 22, 'ذَٰلِكَ بِأَنَّهُمْ كَانَت تَّأْتِيهِمْ رُسُلُهُم بِٱلْبَيِّنَٰتِ فَكَفَرُوا۟ فَأَخَذَهُمُ ٱللَّهُ ۚ إِنَّهُۥ قَوِىٌّۭ شَدِيدُ ٱلْعِقَابِ', NULL, 24, 188, 6, 469, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 23, 'وَلَقَدْ أَرْسَلْنَا مُوسَىٰ بِـَٔايَٰتِنَا وَسُلْطَٰنٍۢ مُّبِينٍ', NULL, 24, 188, 6, 469, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 24, 'إِلَىٰ فِرْعَوْنَ وَهَٰمَٰنَ وَقَٰرُونَ فَقَالُوا۟ سَٰحِرٌۭ كَذَّابٌۭ', NULL, 24, 188, 6, 469, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 25, 'فَلَمَّا جَآءَهُم بِٱلْحَقِّ مِنْ عِندِنَا قَالُوا۟ ٱقْتُلُوٓا۟ أَبْنَآءَ ٱلَّذِينَ ءَامَنُوا۟ مَعَهُۥ وَٱسْتَحْيُوا۟ نِسَآءَهُمْ ۚ وَمَا كَيْدُ ٱلْكَٰفِرِينَ إِلَّا فِى ضَلَٰلٍۢ', NULL, 24, 188, 6, 469, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 26, 'وَقَالَ فِرْعَوْنُ ذَرُونِىٓ أَقْتُلْ مُوسَىٰ وَلْيَدْعُ رَبَّهُۥٓ ۖ إِنِّىٓ أَخَافُ أَن يُبَدِّلَ دِينَكُمْ أَوْ أَن يُظْهِرَ فِى ٱلْأَرْضِ ٱلْفَسَادَ', NULL, 24, 188, 6, 470, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 27, 'وَقَالَ مُوسَىٰٓ إِنِّى عُذْتُ بِرَبِّى وَرَبِّكُم مِّن كُلِّ مُتَكَبِّرٍۢ لَّا يُؤْمِنُ بِيَوْمِ ٱلْحِسَابِ', NULL, 24, 188, 6, 470, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 28, 'وَقَالَ رَجُلٌۭ مُّؤْمِنٌۭ مِّنْ ءَالِ فِرْعَوْنَ يَكْتُمُ إِيمَٰنَهُۥٓ أَتَقْتُلُونَ رَجُلًا أَن يَقُولَ رَبِّىَ ٱللَّهُ وَقَدْ جَآءَكُم بِٱلْبَيِّنَٰتِ مِن رَّبِّكُمْ ۖ وَإِن يَكُ كَٰذِبًۭا فَعَلَيْهِ كَذِبُهُۥ ۖ وَإِن يَكُ صَادِقًۭا يُصِبْكُم بَعْضُ ٱلَّذِى يَعِدُكُمْ ۖ إِنَّ ٱللَّهَ لَا يَهْدِى مَنْ هُوَ مُسْرِفٌۭ كَذَّابٌۭ', NULL, 24, 188, 6, 470, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 29, 'يَٰقَوْمِ لَكُمُ ٱلْمُلْكُ ٱلْيَوْمَ ظَٰهِرِينَ فِى ٱلْأَرْضِ فَمَن يَنصُرُنَا مِنۢ بَأْسِ ٱللَّهِ إِن جَآءَنَا ۚ قَالَ فِرْعَوْنُ مَآ أُرِيكُمْ إِلَّا مَآ أَرَىٰ وَمَآ أَهْدِيكُمْ إِلَّا سَبِيلَ ٱلرَّشَادِ', NULL, 24, 188, 6, 470, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 30, 'وَقَالَ ٱلَّذِىٓ ءَامَنَ يَٰقَوْمِ إِنِّىٓ أَخَافُ عَلَيْكُم مِّثْلَ يَوْمِ ٱلْأَحْزَابِ', NULL, 24, 188, 6, 470, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 31, 'مِثْلَ دَأْبِ قَوْمِ نُوحٍۢ وَعَادٍۢ وَثَمُودَ وَٱلَّذِينَ مِنۢ بَعْدِهِمْ ۚ وَمَا ٱللَّهُ يُرِيدُ ظُلْمًۭا لِّلْعِبَادِ', NULL, 24, 188, 6, 470, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 32, 'وَيَٰقَوْمِ إِنِّىٓ أَخَافُ عَلَيْكُمْ يَوْمَ ٱلتَّنَادِ', NULL, 24, 188, 6, 470, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 33, 'يَوْمَ تُوَلُّونَ مُدْبِرِينَ مَا لَكُم مِّنَ ٱللَّهِ مِنْ عَاصِمٍۢ ۗ وَمَن يُضْلِلِ ٱللَّهُ فَمَا لَهُۥ مِنْ هَادٍۢ', NULL, 24, 188, 6, 470, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 34, 'وَلَقَدْ جَآءَكُمْ يُوسُفُ مِن قَبْلُ بِٱلْبَيِّنَٰتِ فَمَا زِلْتُمْ فِى شَكٍّۢ مِّمَّا جَآءَكُم بِهِۦ ۖ حَتَّىٰٓ إِذَا هَلَكَ قُلْتُمْ لَن يَبْعَثَ ٱللَّهُ مِنۢ بَعْدِهِۦ رَسُولًۭا ۚ كَذَٰلِكَ يُضِلُّ ٱللَّهُ مَنْ هُوَ مُسْرِفٌۭ مُّرْتَابٌ', NULL, 24, 188, 6, 471, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 35, 'ٱلَّذِينَ يُجَٰدِلُونَ فِىٓ ءَايَٰتِ ٱللَّهِ بِغَيْرِ سُلْطَٰنٍ أَتَىٰهُمْ ۖ كَبُرَ مَقْتًا عِندَ ٱللَّهِ وَعِندَ ٱلَّذِينَ ءَامَنُوا۟ ۚ كَذَٰلِكَ يَطْبَعُ ٱللَّهُ عَلَىٰ كُلِّ قَلْبِ مُتَكَبِّرٍۢ جَبَّارٍۢ', NULL, 24, 188, 6, 471, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 36, 'وَقَالَ فِرْعَوْنُ يَٰهَٰمَٰنُ ٱبْنِ لِى صَرْحًۭا لَّعَلِّىٓ أَبْلُغُ ٱلْأَسْبَٰبَ', NULL, 24, 188, 6, 471, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 37, 'أَسْبَٰبَ ٱلسَّمَٰوَٰتِ فَأَطَّلِعَ إِلَىٰٓ إِلَٰهِ مُوسَىٰ وَإِنِّى لَأَظُنُّهُۥ كَٰذِبًۭا ۚ وَكَذَٰلِكَ زُيِّنَ لِفِرْعَوْنَ سُوٓءُ عَمَلِهِۦ وَصُدَّ عَنِ ٱلسَّبِيلِ ۚ وَمَا كَيْدُ فِرْعَوْنَ إِلَّا فِى تَبَابٍۢ', NULL, 24, 188, 6, 471, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 38, 'وَقَالَ ٱلَّذِىٓ ءَامَنَ يَٰقَوْمِ ٱتَّبِعُونِ أَهْدِكُمْ سَبِيلَ ٱلرَّشَادِ', NULL, 24, 188, 6, 471, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 39, 'يَٰقَوْمِ إِنَّمَا هَٰذِهِ ٱلْحَيَوٰةُ ٱلدُّنْيَا مَتَٰعٌۭ وَإِنَّ ٱلْءَاخِرَةَ هِىَ دَارُ ٱلْقَرَارِ', NULL, 24, 188, 6, 471, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 40, 'مَنْ عَمِلَ سَيِّئَةًۭ فَلَا يُجْزَىٰٓ إِلَّا مِثْلَهَا ۖ وَمَنْ عَمِلَ صَٰلِحًۭا مِّن ذَكَرٍ أَوْ أُنثَىٰ وَهُوَ مُؤْمِنٌۭ فَأُو۟لَٰٓئِكَ يَدْخُلُونَ ٱلْجَنَّةَ يُرْزَقُونَ فِيهَا بِغَيْرِ حِسَابٍۢ', NULL, 24, 188, 6, 471, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 41, '۞ وَيَٰقَوْمِ مَا لِىٓ أَدْعُوكُمْ إِلَى ٱلنَّجَوٰةِ وَتَدْعُونَنِىٓ إِلَى ٱلنَّارِ', NULL, 24, 189, 6, 472, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 42, 'تَدْعُونَنِى لِأَكْفُرَ بِٱللَّهِ وَأُشْرِكَ بِهِۦ مَا لَيْسَ لِى بِهِۦ عِلْمٌۭ وَأَنَا۠ أَدْعُوكُمْ إِلَى ٱلْعَزِيزِ ٱلْغَفَّٰرِ', NULL, 24, 189, 6, 472, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 43, 'لَا جَرَمَ أَنَّمَا تَدْعُونَنِىٓ إِلَيْهِ لَيْسَ لَهُۥ دَعْوَةٌۭ فِى ٱلدُّنْيَا وَلَا فِى ٱلْءَاخِرَةِ وَأَنَّ مَرَدَّنَآ إِلَى ٱللَّهِ وَأَنَّ ٱلْمُسْرِفِينَ هُمْ أَصْحَٰبُ ٱلنَّارِ', NULL, 24, 189, 6, 472, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 44, 'فَسَتَذْكُرُونَ مَآ أَقُولُ لَكُمْ ۚ وَأُفَوِّضُ أَمْرِىٓ إِلَى ٱللَّهِ ۚ إِنَّ ٱللَّهَ بَصِيرٌۢ بِٱلْعِبَادِ', NULL, 24, 189, 6, 472, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 45, 'فَوَقَىٰهُ ٱللَّهُ سَيِّـَٔاتِ مَا مَكَرُوا۟ ۖ وَحَاقَ بِـَٔالِ فِرْعَوْنَ سُوٓءُ ٱلْعَذَابِ', NULL, 24, 189, 6, 472, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 46, 'ٱلنَّارُ يُعْرَضُونَ عَلَيْهَا غُدُوًّۭا وَعَشِيًّۭا ۖ وَيَوْمَ تَقُومُ ٱلسَّاعَةُ أَدْخِلُوٓا۟ ءَالَ فِرْعَوْنَ أَشَدَّ ٱلْعَذَابِ', NULL, 24, 189, 6, 472, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 47, 'وَإِذْ يَتَحَآجُّونَ فِى ٱلنَّارِ فَيَقُولُ ٱلضُّعَفَٰٓؤُا۟ لِلَّذِينَ ٱسْتَكْبَرُوٓا۟ إِنَّا كُنَّا لَكُمْ تَبَعًۭا فَهَلْ أَنتُم مُّغْنُونَ عَنَّا نَصِيبًۭا مِّنَ ٱلنَّارِ', NULL, 24, 189, 6, 472, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 48, 'قَالَ ٱلَّذِينَ ٱسْتَكْبَرُوٓا۟ إِنَّا كُلٌّۭ فِيهَآ إِنَّ ٱللَّهَ قَدْ حَكَمَ بَيْنَ ٱلْعِبَادِ', NULL, 24, 189, 6, 472, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 49, 'وَقَالَ ٱلَّذِينَ فِى ٱلنَّارِ لِخَزَنَةِ جَهَنَّمَ ٱدْعُوا۟ رَبَّكُمْ يُخَفِّفْ عَنَّا يَوْمًۭا مِّنَ ٱلْعَذَابِ', NULL, 24, 189, 6, 472, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 50, 'قَالُوٓا۟ أَوَلَمْ تَكُ تَأْتِيكُمْ رُسُلُكُم بِٱلْبَيِّنَٰتِ ۖ قَالُوا۟ بَلَىٰ ۚ قَالُوا۟ فَٱدْعُوا۟ ۗ وَمَا دُعَٰٓؤُا۟ ٱلْكَٰفِرِينَ إِلَّا فِى ضَلَٰلٍ', NULL, 24, 189, 6, 473, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 51, 'إِنَّا لَنَنصُرُ رُسُلَنَا وَٱلَّذِينَ ءَامَنُوا۟ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا وَيَوْمَ يَقُومُ ٱلْأَشْهَٰدُ', NULL, 24, 189, 6, 473, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 52, 'يَوْمَ لَا يَنفَعُ ٱلظَّٰلِمِينَ مَعْذِرَتُهُمْ ۖ وَلَهُمُ ٱللَّعْنَةُ وَلَهُمْ سُوٓءُ ٱلدَّارِ', NULL, 24, 189, 6, 473, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 53, 'وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْهُدَىٰ وَأَوْرَثْنَا بَنِىٓ إِسْرَٰٓءِيلَ ٱلْكِتَٰبَ', NULL, 24, 189, 6, 473, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 54, 'هُدًۭى وَذِكْرَىٰ لِأُو۟لِى ٱلْأَلْبَٰبِ', NULL, 24, 189, 6, 473, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 55, 'فَٱصْبِرْ إِنَّ وَعْدَ ٱللَّهِ حَقٌّۭ وَٱسْتَغْفِرْ لِذَنۢبِكَ وَسَبِّحْ بِحَمْدِ رَبِّكَ بِٱلْعَشِىِّ وَٱلْإِبْكَٰرِ', NULL, 24, 189, 6, 473, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 56, 'إِنَّ ٱلَّذِينَ يُجَٰدِلُونَ فِىٓ ءَايَٰتِ ٱللَّهِ بِغَيْرِ سُلْطَٰنٍ أَتَىٰهُمْ ۙ إِن فِى صُدُورِهِمْ إِلَّا كِبْرٌۭ مَّا هُم بِبَٰلِغِيهِ ۚ فَٱسْتَعِذْ بِٱللَّهِ ۖ إِنَّهُۥ هُوَ ٱلسَّمِيعُ ٱلْبَصِيرُ', NULL, 24, 189, 6, 473, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 57, 'لَخَلْقُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ أَكْبَرُ مِنْ خَلْقِ ٱلنَّاسِ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ', NULL, 24, 189, 6, 473, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 58, 'وَمَا يَسْتَوِى ٱلْأَعْمَىٰ وَٱلْبَصِيرُ وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ وَلَا ٱلْمُسِىٓءُ ۚ قَلِيلًۭا مَّا تَتَذَكَّرُونَ', NULL, 24, 189, 6, 473, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 59, 'إِنَّ ٱلسَّاعَةَ لَءَاتِيَةٌۭ لَّا رَيْبَ فِيهَا وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يُؤْمِنُونَ', NULL, 24, 189, 6, 474, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 60, 'وَقَالَ رَبُّكُمُ ٱدْعُونِىٓ أَسْتَجِبْ لَكُمْ ۚ إِنَّ ٱلَّذِينَ يَسْتَكْبِرُونَ عَنْ عِبَادَتِى سَيَدْخُلُونَ جَهَنَّمَ دَاخِرِينَ', NULL, 24, 189, 6, 474, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 61, 'ٱللَّهُ ٱلَّذِى جَعَلَ لَكُمُ ٱلَّيْلَ لِتَسْكُنُوا۟ فِيهِ وَٱلنَّهَارَ مُبْصِرًا ۚ إِنَّ ٱللَّهَ لَذُو فَضْلٍ عَلَى ٱلنَّاسِ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَشْكُرُونَ', NULL, 24, 189, 6, 474, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 62, 'ذَٰلِكُمُ ٱللَّهُ رَبُّكُمْ خَٰلِقُ كُلِّ شَىْءٍۢ لَّآ إِلَٰهَ إِلَّا هُوَ ۖ فَأَنَّىٰ تُؤْفَكُونَ', NULL, 24, 189, 6, 474, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 63, 'كَذَٰلِكَ يُؤْفَكُ ٱلَّذِينَ كَانُوا۟ بِـَٔايَٰتِ ٱللَّهِ يَجْحَدُونَ', NULL, 24, 189, 6, 474, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 64, 'ٱللَّهُ ٱلَّذِى جَعَلَ لَكُمُ ٱلْأَرْضَ قَرَارًۭا وَٱلسَّمَآءَ بِنَآءًۭ وَصَوَّرَكُمْ فَأَحْسَنَ صُوَرَكُمْ وَرَزَقَكُم مِّنَ ٱلطَّيِّبَٰتِ ۚ ذَٰلِكُمُ ٱللَّهُ رَبُّكُمْ ۖ فَتَبَارَكَ ٱللَّهُ رَبُّ ٱلْعَٰلَمِينَ', NULL, 24, 189, 6, 474, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 65, 'هُوَ ٱلْحَىُّ لَآ إِلَٰهَ إِلَّا هُوَ فَٱدْعُوهُ مُخْلِصِينَ لَهُ ٱلدِّينَ ۗ ٱلْحَمْدُ لِلَّهِ رَبِّ ٱلْعَٰلَمِينَ', NULL, 24, 189, 6, 474, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 66, '۞ قُلْ إِنِّى نُهِيتُ أَنْ أَعْبُدَ ٱلَّذِينَ تَدْعُونَ مِن دُونِ ٱللَّهِ لَمَّا جَآءَنِىَ ٱلْبَيِّنَٰتُ مِن رَّبِّى وَأُمِرْتُ أَنْ أُسْلِمَ لِرَبِّ ٱلْعَٰلَمِينَ', NULL, 24, 190, 6, 474, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 67, 'هُوَ ٱلَّذِى خَلَقَكُم مِّن تُرَابٍۢ ثُمَّ مِن نُّطْفَةٍۢ ثُمَّ مِنْ عَلَقَةٍۢ ثُمَّ يُخْرِجُكُمْ طِفْلًۭا ثُمَّ لِتَبْلُغُوٓا۟ أَشُدَّكُمْ ثُمَّ لِتَكُونُوا۟ شُيُوخًۭا ۚ وَمِنكُم مَّن يُتَوَفَّىٰ مِن قَبْلُ ۖ وَلِتَبْلُغُوٓا۟ أَجَلًۭا مُّسَمًّۭى وَلَعَلَّكُمْ تَعْقِلُونَ', NULL, 24, 190, 6, 475, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 68, 'هُوَ ٱلَّذِى يُحْىِۦ وَيُمِيتُ ۖ فَإِذَا قَضَىٰٓ أَمْرًۭا فَإِنَّمَا يَقُولُ لَهُۥ كُن فَيَكُونُ', NULL, 24, 190, 6, 475, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 69, 'أَلَمْ تَرَ إِلَى ٱلَّذِينَ يُجَٰدِلُونَ فِىٓ ءَايَٰتِ ٱللَّهِ أَنَّىٰ يُصْرَفُونَ', NULL, 24, 190, 6, 475, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 70, 'ٱلَّذِينَ كَذَّبُوا۟ بِٱلْكِتَٰبِ وَبِمَآ أَرْسَلْنَا بِهِۦ رُسُلَنَا ۖ فَسَوْفَ يَعْلَمُونَ', NULL, 24, 190, 6, 475, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 71, 'إِذِ ٱلْأَغْلَٰلُ فِىٓ أَعْنَٰقِهِمْ وَٱلسَّلَٰسِلُ يُسْحَبُونَ', NULL, 24, 190, 6, 475, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 72, 'فِى ٱلْحَمِيمِ ثُمَّ فِى ٱلنَّارِ يُسْجَرُونَ', NULL, 24, 190, 6, 475, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 73, 'ثُمَّ قِيلَ لَهُمْ أَيْنَ مَا كُنتُمْ تُشْرِكُونَ', NULL, 24, 190, 6, 475, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 74, 'مِن دُونِ ٱللَّهِ ۖ قَالُوا۟ ضَلُّوا۟ عَنَّا بَل لَّمْ نَكُن نَّدْعُوا۟ مِن قَبْلُ شَيْـًۭٔا ۚ كَذَٰلِكَ يُضِلُّ ٱللَّهُ ٱلْكَٰفِرِينَ', NULL, 24, 190, 6, 475, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 75, 'ذَٰلِكُم بِمَا كُنتُمْ تَفْرَحُونَ فِى ٱلْأَرْضِ بِغَيْرِ ٱلْحَقِّ وَبِمَا كُنتُمْ تَمْرَحُونَ', NULL, 24, 190, 6, 475, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 76, 'ٱدْخُلُوٓا۟ أَبْوَٰبَ جَهَنَّمَ خَٰلِدِينَ فِيهَا ۖ فَبِئْسَ مَثْوَى ٱلْمُتَكَبِّرِينَ', NULL, 24, 190, 6, 475, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 77, 'فَٱصْبِرْ إِنَّ وَعْدَ ٱللَّهِ حَقٌّۭ ۚ فَإِمَّا نُرِيَنَّكَ بَعْضَ ٱلَّذِى نَعِدُهُمْ أَوْ نَتَوَفَّيَنَّكَ فَإِلَيْنَا يُرْجَعُونَ', NULL, 24, 190, 6, 475, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 78, 'وَلَقَدْ أَرْسَلْنَا رُسُلًۭا مِّن قَبْلِكَ مِنْهُم مَّن قَصَصْنَا عَلَيْكَ وَمِنْهُم مَّن لَّمْ نَقْصُصْ عَلَيْكَ ۗ وَمَا كَانَ لِرَسُولٍ أَن يَأْتِىَ بِـَٔايَةٍ إِلَّا بِإِذْنِ ٱللَّهِ ۚ فَإِذَا جَآءَ أَمْرُ ٱللَّهِ قُضِىَ بِٱلْحَقِّ وَخَسِرَ هُنَالِكَ ٱلْمُبْطِلُونَ', NULL, 24, 190, 6, 476, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 79, 'ٱللَّهُ ٱلَّذِى جَعَلَ لَكُمُ ٱلْأَنْعَٰمَ لِتَرْكَبُوا۟ مِنْهَا وَمِنْهَا تَأْكُلُونَ', NULL, 24, 190, 6, 476, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 80, 'وَلَكُمْ فِيهَا مَنَٰفِعُ وَلِتَبْلُغُوا۟ عَلَيْهَا حَاجَةًۭ فِى صُدُورِكُمْ وَعَلَيْهَا وَعَلَى ٱلْفُلْكِ تُحْمَلُونَ', NULL, 24, 190, 6, 476, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 81, 'وَيُرِيكُمْ ءَايَٰتِهِۦ فَأَىَّ ءَايَٰتِ ٱللَّهِ تُنكِرُونَ', NULL, 24, 190, 6, 476, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 82, 'أَفَلَمْ يَسِيرُوا۟ فِى ٱلْأَرْضِ فَيَنظُرُوا۟ كَيْفَ كَانَ عَٰقِبَةُ ٱلَّذِينَ مِن قَبْلِهِمْ ۚ كَانُوٓا۟ أَكْثَرَ مِنْهُمْ وَأَشَدَّ قُوَّةًۭ وَءَاثَارًۭا فِى ٱلْأَرْضِ فَمَآ أَغْنَىٰ عَنْهُم مَّا كَانُوا۟ يَكْسِبُونَ', NULL, 24, 190, 6, 476, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 83, 'فَلَمَّا جَآءَتْهُمْ رُسُلُهُم بِٱلْبَيِّنَٰتِ فَرِحُوا۟ بِمَا عِندَهُم مِّنَ ٱلْعِلْمِ وَحَاقَ بِهِم مَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ', NULL, 24, 190, 6, 476, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 84, 'فَلَمَّا رَأَوْا۟ بَأْسَنَا قَالُوٓا۟ ءَامَنَّا بِٱللَّهِ وَحْدَهُۥ وَكَفَرْنَا بِمَا كُنَّا بِهِۦ مُشْرِكِينَ', NULL, 24, 190, 6, 476, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 40), 85, 'فَلَمْ يَكُ يَنفَعُهُمْ إِيمَٰنُهُمْ لَمَّا رَأَوْا۟ بَأْسَنَا ۖ سُنَّتَ ٱللَّهِ ٱلَّتِى قَدْ خَلَتْ فِى عِبَادِهِۦ ۖ وَخَسِرَ هُنَالِكَ ٱلْكَٰفِرُونَ', NULL, 24, 190, 6, 476, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ حمٓ', NULL, 24, 190, 6, 477, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 2, 'تَنزِيلٌۭ مِّنَ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ', NULL, 24, 190, 6, 477, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 3, 'كِتَٰبٌۭ فُصِّلَتْ ءَايَٰتُهُۥ قُرْءَانًا عَرَبِيًّۭا لِّقَوْمٍۢ يَعْلَمُونَ', NULL, 24, 190, 6, 477, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 4, 'بَشِيرًۭا وَنَذِيرًۭا فَأَعْرَضَ أَكْثَرُهُمْ فَهُمْ لَا يَسْمَعُونَ', NULL, 24, 190, 6, 477, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 5, 'وَقَالُوا۟ قُلُوبُنَا فِىٓ أَكِنَّةٍۢ مِّمَّا تَدْعُونَآ إِلَيْهِ وَفِىٓ ءَاذَانِنَا وَقْرٌۭ وَمِنۢ بَيْنِنَا وَبَيْنِكَ حِجَابٌۭ فَٱعْمَلْ إِنَّنَا عَٰمِلُونَ', NULL, 24, 190, 6, 477, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 6, 'قُلْ إِنَّمَآ أَنَا۠ بَشَرٌۭ مِّثْلُكُمْ يُوحَىٰٓ إِلَىَّ أَنَّمَآ إِلَٰهُكُمْ إِلَٰهٌۭ وَٰحِدٌۭ فَٱسْتَقِيمُوٓا۟ إِلَيْهِ وَٱسْتَغْفِرُوهُ ۗ وَوَيْلٌۭ لِّلْمُشْرِكِينَ', NULL, 24, 190, 6, 477, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 7, 'ٱلَّذِينَ لَا يُؤْتُونَ ٱلزَّكَوٰةَ وَهُم بِٱلْءَاخِرَةِ هُمْ كَٰفِرُونَ', NULL, 24, 190, 6, 477, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 8, 'إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ لَهُمْ أَجْرٌ غَيْرُ مَمْنُونٍۢ', NULL, 24, 190, 6, 477, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 9, '۞ قُلْ أَئِنَّكُمْ لَتَكْفُرُونَ بِٱلَّذِى خَلَقَ ٱلْأَرْضَ فِى يَوْمَيْنِ وَتَجْعَلُونَ لَهُۥٓ أَندَادًۭا ۚ ذَٰلِكَ رَبُّ ٱلْعَٰلَمِينَ', NULL, 24, 191, 6, 477, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 10, 'وَجَعَلَ فِيهَا رَوَٰسِىَ مِن فَوْقِهَا وَبَٰرَكَ فِيهَا وَقَدَّرَ فِيهَآ أَقْوَٰتَهَا فِىٓ أَرْبَعَةِ أَيَّامٍۢ سَوَآءًۭ لِّلسَّآئِلِينَ', NULL, 24, 191, 6, 477, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 11, 'ثُمَّ ٱسْتَوَىٰٓ إِلَى ٱلسَّمَآءِ وَهِىَ دُخَانٌۭ فَقَالَ لَهَا وَلِلْأَرْضِ ٱئْتِيَا طَوْعًا أَوْ كَرْهًۭا قَالَتَآ أَتَيْنَا طَآئِعِينَ', NULL, 24, 191, 6, 477, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 12, 'فَقَضَىٰهُنَّ سَبْعَ سَمَٰوَاتٍۢ فِى يَوْمَيْنِ وَأَوْحَىٰ فِى كُلِّ سَمَآءٍ أَمْرَهَا ۚ وَزَيَّنَّا ٱلسَّمَآءَ ٱلدُّنْيَا بِمَصَٰبِيحَ وَحِفْظًۭا ۚ ذَٰلِكَ تَقْدِيرُ ٱلْعَزِيزِ ٱلْعَلِيمِ', NULL, 24, 191, 6, 478, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 13, 'فَإِنْ أَعْرَضُوا۟ فَقُلْ أَنذَرْتُكُمْ صَٰعِقَةًۭ مِّثْلَ صَٰعِقَةِ عَادٍۢ وَثَمُودَ', NULL, 24, 191, 6, 478, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 14, 'إِذْ جَآءَتْهُمُ ٱلرُّسُلُ مِنۢ بَيْنِ أَيْدِيهِمْ وَمِنْ خَلْفِهِمْ أَلَّا تَعْبُدُوٓا۟ إِلَّا ٱللَّهَ ۖ قَالُوا۟ لَوْ شَآءَ رَبُّنَا لَأَنزَلَ مَلَٰٓئِكَةًۭ فَإِنَّا بِمَآ أُرْسِلْتُم بِهِۦ كَٰفِرُونَ', NULL, 24, 191, 6, 478, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 15, 'فَأَمَّا عَادٌۭ فَٱسْتَكْبَرُوا۟ فِى ٱلْأَرْضِ بِغَيْرِ ٱلْحَقِّ وَقَالُوا۟ مَنْ أَشَدُّ مِنَّا قُوَّةً ۖ أَوَلَمْ يَرَوْا۟ أَنَّ ٱللَّهَ ٱلَّذِى خَلَقَهُمْ هُوَ أَشَدُّ مِنْهُمْ قُوَّةًۭ ۖ وَكَانُوا۟ بِـَٔايَٰتِنَا يَجْحَدُونَ', NULL, 24, 191, 6, 478, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 16, 'فَأَرْسَلْنَا عَلَيْهِمْ رِيحًۭا صَرْصَرًۭا فِىٓ أَيَّامٍۢ نَّحِسَاتٍۢ لِّنُذِيقَهُمْ عَذَابَ ٱلْخِزْىِ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا ۖ وَلَعَذَابُ ٱلْءَاخِرَةِ أَخْزَىٰ ۖ وَهُمْ لَا يُنصَرُونَ', NULL, 24, 191, 6, 478, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 17, 'وَأَمَّا ثَمُودُ فَهَدَيْنَٰهُمْ فَٱسْتَحَبُّوا۟ ٱلْعَمَىٰ عَلَى ٱلْهُدَىٰ فَأَخَذَتْهُمْ صَٰعِقَةُ ٱلْعَذَابِ ٱلْهُونِ بِمَا كَانُوا۟ يَكْسِبُونَ', NULL, 24, 191, 6, 478, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 18, 'وَنَجَّيْنَا ٱلَّذِينَ ءَامَنُوا۟ وَكَانُوا۟ يَتَّقُونَ', NULL, 24, 191, 6, 478, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 19, 'وَيَوْمَ يُحْشَرُ أَعْدَآءُ ٱللَّهِ إِلَى ٱلنَّارِ فَهُمْ يُوزَعُونَ', NULL, 24, 191, 6, 478, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 20, 'حَتَّىٰٓ إِذَا مَا جَآءُوهَا شَهِدَ عَلَيْهِمْ سَمْعُهُمْ وَأَبْصَٰرُهُمْ وَجُلُودُهُم بِمَا كَانُوا۟ يَعْمَلُونَ', NULL, 24, 191, 6, 478, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 21, 'وَقَالُوا۟ لِجُلُودِهِمْ لِمَ شَهِدتُّمْ عَلَيْنَا ۖ قَالُوٓا۟ أَنطَقَنَا ٱللَّهُ ٱلَّذِىٓ أَنطَقَ كُلَّ شَىْءٍۢ وَهُوَ خَلَقَكُمْ أَوَّلَ مَرَّةٍۢ وَإِلَيْهِ تُرْجَعُونَ', NULL, 24, 191, 6, 479, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 22, 'وَمَا كُنتُمْ تَسْتَتِرُونَ أَن يَشْهَدَ عَلَيْكُمْ سَمْعُكُمْ وَلَآ أَبْصَٰرُكُمْ وَلَا جُلُودُكُمْ وَلَٰكِن ظَنَنتُمْ أَنَّ ٱللَّهَ لَا يَعْلَمُ كَثِيرًۭا مِّمَّا تَعْمَلُونَ', NULL, 24, 191, 6, 479, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 23, 'وَذَٰلِكُمْ ظَنُّكُمُ ٱلَّذِى ظَنَنتُم بِرَبِّكُمْ أَرْدَىٰكُمْ فَأَصْبَحْتُم مِّنَ ٱلْخَٰسِرِينَ', NULL, 24, 191, 6, 479, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 24, 'فَإِن يَصْبِرُوا۟ فَٱلنَّارُ مَثْوًۭى لَّهُمْ ۖ وَإِن يَسْتَعْتِبُوا۟ فَمَا هُم مِّنَ ٱلْمُعْتَبِينَ', NULL, 24, 191, 6, 479, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 25, '۞ وَقَيَّضْنَا لَهُمْ قُرَنَآءَ فَزَيَّنُوا۟ لَهُم مَّا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُمْ وَحَقَّ عَلَيْهِمُ ٱلْقَوْلُ فِىٓ أُمَمٍۢ قَدْ خَلَتْ مِن قَبْلِهِم مِّنَ ٱلْجِنِّ وَٱلْإِنسِ ۖ إِنَّهُمْ كَانُوا۟ خَٰسِرِينَ', NULL, 24, 192, 6, 479, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 26, 'وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لَا تَسْمَعُوا۟ لِهَٰذَا ٱلْقُرْءَانِ وَٱلْغَوْا۟ فِيهِ لَعَلَّكُمْ تَغْلِبُونَ', NULL, 24, 192, 6, 479, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 27, 'فَلَنُذِيقَنَّ ٱلَّذِينَ كَفَرُوا۟ عَذَابًۭا شَدِيدًۭا وَلَنَجْزِيَنَّهُمْ أَسْوَأَ ٱلَّذِى كَانُوا۟ يَعْمَلُونَ', NULL, 24, 192, 6, 479, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 28, 'ذَٰلِكَ جَزَآءُ أَعْدَآءِ ٱللَّهِ ٱلنَّارُ ۖ لَهُمْ فِيهَا دَارُ ٱلْخُلْدِ ۖ جَزَآءًۢ بِمَا كَانُوا۟ بِـَٔايَٰتِنَا يَجْحَدُونَ', NULL, 24, 192, 6, 479, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 29, 'وَقَالَ ٱلَّذِينَ كَفَرُوا۟ رَبَّنَآ أَرِنَا ٱلَّذَيْنِ أَضَلَّانَا مِنَ ٱلْجِنِّ وَٱلْإِنسِ نَجْعَلْهُمَا تَحْتَ أَقْدَامِنَا لِيَكُونَا مِنَ ٱلْأَسْفَلِينَ', NULL, 24, 192, 6, 479, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 30, 'إِنَّ ٱلَّذِينَ قَالُوا۟ رَبُّنَا ٱللَّهُ ثُمَّ ٱسْتَقَٰمُوا۟ تَتَنَزَّلُ عَلَيْهِمُ ٱلْمَلَٰٓئِكَةُ أَلَّا تَخَافُوا۟ وَلَا تَحْزَنُوا۟ وَأَبْشِرُوا۟ بِٱلْجَنَّةِ ٱلَّتِى كُنتُمْ تُوعَدُونَ', NULL, 24, 192, 6, 480, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 31, 'نَحْنُ أَوْلِيَآؤُكُمْ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا وَفِى ٱلْءَاخِرَةِ ۖ وَلَكُمْ فِيهَا مَا تَشْتَهِىٓ أَنفُسُكُمْ وَلَكُمْ فِيهَا مَا تَدَّعُونَ', NULL, 24, 192, 6, 480, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 32, 'نُزُلًۭا مِّنْ غَفُورٍۢ رَّحِيمٍۢ', NULL, 24, 192, 6, 480, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 33, 'وَمَنْ أَحْسَنُ قَوْلًۭا مِّمَّن دَعَآ إِلَى ٱللَّهِ وَعَمِلَ صَٰلِحًۭا وَقَالَ إِنَّنِى مِنَ ٱلْمُسْلِمِينَ', NULL, 24, 192, 6, 480, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 34, 'وَلَا تَسْتَوِى ٱلْحَسَنَةُ وَلَا ٱلسَّيِّئَةُ ۚ ٱدْفَعْ بِٱلَّتِى هِىَ أَحْسَنُ فَإِذَا ٱلَّذِى بَيْنَكَ وَبَيْنَهُۥ عَدَٰوَةٌۭ كَأَنَّهُۥ وَلِىٌّ حَمِيمٌۭ', NULL, 24, 192, 6, 480, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 35, 'وَمَا يُلَقَّىٰهَآ إِلَّا ٱلَّذِينَ صَبَرُوا۟ وَمَا يُلَقَّىٰهَآ إِلَّا ذُو حَظٍّ عَظِيمٍۢ', NULL, 24, 192, 6, 480, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 36, 'وَإِمَّا يَنزَغَنَّكَ مِنَ ٱلشَّيْطَٰنِ نَزْغٌۭ فَٱسْتَعِذْ بِٱللَّهِ ۖ إِنَّهُۥ هُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ', NULL, 24, 192, 6, 480, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 37, 'وَمِنْ ءَايَٰتِهِ ٱلَّيْلُ وَٱلنَّهَارُ وَٱلشَّمْسُ وَٱلْقَمَرُ ۚ لَا تَسْجُدُوا۟ لِلشَّمْسِ وَلَا لِلْقَمَرِ وَٱسْجُدُوا۟ لِلَّهِ ٱلَّذِى خَلَقَهُنَّ إِن كُنتُمْ إِيَّاهُ تَعْبُدُونَ', NULL, 24, 192, 6, 480, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 38, 'فَإِنِ ٱسْتَكْبَرُوا۟ فَٱلَّذِينَ عِندَ رَبِّكَ يُسَبِّحُونَ لَهُۥ بِٱلَّيْلِ وَٱلنَّهَارِ وَهُمْ لَا يَسْـَٔمُونَ ۩', NULL, 24, 192, 6, 480, true, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 39, 'وَمِنْ ءَايَٰتِهِۦٓ أَنَّكَ تَرَى ٱلْأَرْضَ خَٰشِعَةًۭ فَإِذَآ أَنزَلْنَا عَلَيْهَا ٱلْمَآءَ ٱهْتَزَّتْ وَرَبَتْ ۚ إِنَّ ٱلَّذِىٓ أَحْيَاهَا لَمُحْىِ ٱلْمَوْتَىٰٓ ۚ إِنَّهُۥ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌ', NULL, 24, 192, 6, 481, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 40, 'إِنَّ ٱلَّذِينَ يُلْحِدُونَ فِىٓ ءَايَٰتِنَا لَا يَخْفَوْنَ عَلَيْنَآ ۗ أَفَمَن يُلْقَىٰ فِى ٱلنَّارِ خَيْرٌ أَم مَّن يَأْتِىٓ ءَامِنًۭا يَوْمَ ٱلْقِيَٰمَةِ ۚ ٱعْمَلُوا۟ مَا شِئْتُمْ ۖ إِنَّهُۥ بِمَا تَعْمَلُونَ بَصِيرٌ', NULL, 24, 192, 6, 481, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 41, 'إِنَّ ٱلَّذِينَ كَفَرُوا۟ بِٱلذِّكْرِ لَمَّا جَآءَهُمْ ۖ وَإِنَّهُۥ لَكِتَٰبٌ عَزِيزٌۭ', NULL, 24, 192, 6, 481, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 42, 'لَّا يَأْتِيهِ ٱلْبَٰطِلُ مِنۢ بَيْنِ يَدَيْهِ وَلَا مِنْ خَلْفِهِۦ ۖ تَنزِيلٌۭ مِّنْ حَكِيمٍ حَمِيدٍۢ', NULL, 24, 192, 6, 481, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 43, 'مَّا يُقَالُ لَكَ إِلَّا مَا قَدْ قِيلَ لِلرُّسُلِ مِن قَبْلِكَ ۚ إِنَّ رَبَّكَ لَذُو مَغْفِرَةٍۢ وَذُو عِقَابٍ أَلِيمٍۢ', NULL, 24, 192, 6, 481, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 44, 'وَلَوْ جَعَلْنَٰهُ قُرْءَانًا أَعْجَمِيًّۭا لَّقَالُوا۟ لَوْلَا فُصِّلَتْ ءَايَٰتُهُۥٓ ۖ ءَا۬عْجَمِىٌّۭ وَعَرَبِىٌّۭ ۗ قُلْ هُوَ لِلَّذِينَ ءَامَنُوا۟ هُدًۭى وَشِفَآءٌۭ ۖ وَٱلَّذِينَ لَا يُؤْمِنُونَ فِىٓ ءَاذَانِهِمْ وَقْرٌۭ وَهُوَ عَلَيْهِمْ عَمًى ۚ أُو۟لَٰٓئِكَ يُنَادَوْنَ مِن مَّكَانٍۭ بَعِيدٍۢ', NULL, 24, 192, 6, 481, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 45, 'وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْكِتَٰبَ فَٱخْتُلِفَ فِيهِ ۗ وَلَوْلَا كَلِمَةٌۭ سَبَقَتْ مِن رَّبِّكَ لَقُضِىَ بَيْنَهُمْ ۚ وَإِنَّهُمْ لَفِى شَكٍّۢ مِّنْهُ مُرِيبٍۢ', NULL, 24, 192, 6, 481, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 46, 'مَّنْ عَمِلَ صَٰلِحًۭا فَلِنَفْسِهِۦ ۖ وَمَنْ أَسَآءَ فَعَلَيْهَا ۗ وَمَا رَبُّكَ بِظَلَّٰمٍۢ لِّلْعَبِيدِ', NULL, 24, 192, 6, 481, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 47, '۞ إِلَيْهِ يُرَدُّ عِلْمُ ٱلسَّاعَةِ ۚ وَمَا تَخْرُجُ مِن ثَمَرَٰتٍۢ مِّنْ أَكْمَامِهَا وَمَا تَحْمِلُ مِنْ أُنثَىٰ وَلَا تَضَعُ إِلَّا بِعِلْمِهِۦ ۚ وَيَوْمَ يُنَادِيهِمْ أَيْنَ شُرَكَآءِى قَالُوٓا۟ ءَاذَنَّٰكَ مَا مِنَّا مِن شَهِيدٍۢ', NULL, 25, 193, 6, 482, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 48, 'وَضَلَّ عَنْهُم مَّا كَانُوا۟ يَدْعُونَ مِن قَبْلُ ۖ وَظَنُّوا۟ مَا لَهُم مِّن مَّحِيصٍۢ', NULL, 25, 193, 6, 482, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 49, 'لَّا يَسْـَٔمُ ٱلْإِنسَٰنُ مِن دُعَآءِ ٱلْخَيْرِ وَإِن مَّسَّهُ ٱلشَّرُّ فَيَـُٔوسٌۭ قَنُوطٌۭ', NULL, 25, 193, 6, 482, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 50, 'وَلَئِنْ أَذَقْنَٰهُ رَحْمَةًۭ مِّنَّا مِنۢ بَعْدِ ضَرَّآءَ مَسَّتْهُ لَيَقُولَنَّ هَٰذَا لِى وَمَآ أَظُنُّ ٱلسَّاعَةَ قَآئِمَةًۭ وَلَئِن رُّجِعْتُ إِلَىٰ رَبِّىٓ إِنَّ لِى عِندَهُۥ لَلْحُسْنَىٰ ۚ فَلَنُنَبِّئَنَّ ٱلَّذِينَ كَفَرُوا۟ بِمَا عَمِلُوا۟ وَلَنُذِيقَنَّهُم مِّنْ عَذَابٍ غَلِيظٍۢ', NULL, 25, 193, 6, 482, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 51, 'وَإِذَآ أَنْعَمْنَا عَلَى ٱلْإِنسَٰنِ أَعْرَضَ وَنَـَٔا بِجَانِبِهِۦ وَإِذَا مَسَّهُ ٱلشَّرُّ فَذُو دُعَآءٍ عَرِيضٍۢ', NULL, 25, 193, 6, 482, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 52, 'قُلْ أَرَءَيْتُمْ إِن كَانَ مِنْ عِندِ ٱللَّهِ ثُمَّ كَفَرْتُم بِهِۦ مَنْ أَضَلُّ مِمَّنْ هُوَ فِى شِقَاقٍۭ بَعِيدٍۢ', NULL, 25, 193, 6, 482, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 53, 'سَنُرِيهِمْ ءَايَٰتِنَا فِى ٱلْءَافَاقِ وَفِىٓ أَنفُسِهِمْ حَتَّىٰ يَتَبَيَّنَ لَهُمْ أَنَّهُ ٱلْحَقُّ ۗ أَوَلَمْ يَكْفِ بِرَبِّكَ أَنَّهُۥ عَلَىٰ كُلِّ شَىْءٍۢ شَهِيدٌ', NULL, 25, 193, 6, 482, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 41), 54, 'أَلَآ إِنَّهُمْ فِى مِرْيَةٍۢ مِّن لِّقَآءِ رَبِّهِمْ ۗ أَلَآ إِنَّهُۥ بِكُلِّ شَىْءٍۢ مُّحِيطٌۢ', NULL, 25, 193, 6, 482, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ حمٓ', NULL, 25, 193, 6, 483, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 2, 'عٓسٓقٓ', NULL, 25, 193, 6, 483, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 3, 'كَذَٰلِكَ يُوحِىٓ إِلَيْكَ وَإِلَى ٱلَّذِينَ مِن قَبْلِكَ ٱللَّهُ ٱلْعَزِيزُ ٱلْحَكِيمُ', NULL, 25, 193, 6, 483, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 4, 'لَهُۥ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۖ وَهُوَ ٱلْعَلِىُّ ٱلْعَظِيمُ', NULL, 25, 193, 6, 483, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 5, 'تَكَادُ ٱلسَّمَٰوَٰتُ يَتَفَطَّرْنَ مِن فَوْقِهِنَّ ۚ وَٱلْمَلَٰٓئِكَةُ يُسَبِّحُونَ بِحَمْدِ رَبِّهِمْ وَيَسْتَغْفِرُونَ لِمَن فِى ٱلْأَرْضِ ۗ أَلَآ إِنَّ ٱللَّهَ هُوَ ٱلْغَفُورُ ٱلرَّحِيمُ', NULL, 25, 193, 6, 483, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 6, 'وَٱلَّذِينَ ٱتَّخَذُوا۟ مِن دُونِهِۦٓ أَوْلِيَآءَ ٱللَّهُ حَفِيظٌ عَلَيْهِمْ وَمَآ أَنتَ عَلَيْهِم بِوَكِيلٍۢ', NULL, 25, 193, 6, 483, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 7, 'وَكَذَٰلِكَ أَوْحَيْنَآ إِلَيْكَ قُرْءَانًا عَرَبِيًّۭا لِّتُنذِرَ أُمَّ ٱلْقُرَىٰ وَمَنْ حَوْلَهَا وَتُنذِرَ يَوْمَ ٱلْجَمْعِ لَا رَيْبَ فِيهِ ۚ فَرِيقٌۭ فِى ٱلْجَنَّةِ وَفَرِيقٌۭ فِى ٱلسَّعِيرِ', NULL, 25, 193, 6, 483, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 8, 'وَلَوْ شَآءَ ٱللَّهُ لَجَعَلَهُمْ أُمَّةًۭ وَٰحِدَةًۭ وَلَٰكِن يُدْخِلُ مَن يَشَآءُ فِى رَحْمَتِهِۦ ۚ وَٱلظَّٰلِمُونَ مَا لَهُم مِّن وَلِىٍّۢ وَلَا نَصِيرٍ', NULL, 25, 193, 6, 483, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 9, 'أَمِ ٱتَّخَذُوا۟ مِن دُونِهِۦٓ أَوْلِيَآءَ ۖ فَٱللَّهُ هُوَ ٱلْوَلِىُّ وَهُوَ يُحْىِ ٱلْمَوْتَىٰ وَهُوَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ', NULL, 25, 193, 6, 483, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 10, 'وَمَا ٱخْتَلَفْتُمْ فِيهِ مِن شَىْءٍۢ فَحُكْمُهُۥٓ إِلَى ٱللَّهِ ۚ ذَٰلِكُمُ ٱللَّهُ رَبِّى عَلَيْهِ تَوَكَّلْتُ وَإِلَيْهِ أُنِيبُ', NULL, 25, 193, 6, 483, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 11, 'فَاطِرُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ جَعَلَ لَكُم مِّنْ أَنفُسِكُمْ أَزْوَٰجًۭا وَمِنَ ٱلْأَنْعَٰمِ أَزْوَٰجًۭا ۖ يَذْرَؤُكُمْ فِيهِ ۚ لَيْسَ كَمِثْلِهِۦ شَىْءٌۭ ۖ وَهُوَ ٱلسَّمِيعُ ٱلْبَصِيرُ', NULL, 25, 193, 6, 484, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 12, 'لَهُۥ مَقَالِيدُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ وَيَقْدِرُ ۚ إِنَّهُۥ بِكُلِّ شَىْءٍ عَلِيمٌۭ', NULL, 25, 193, 6, 484, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 13, '۞ شَرَعَ لَكُم مِّنَ ٱلدِّينِ مَا وَصَّىٰ بِهِۦ نُوحًۭا وَٱلَّذِىٓ أَوْحَيْنَآ إِلَيْكَ وَمَا وَصَّيْنَا بِهِۦٓ إِبْرَٰهِيمَ وَمُوسَىٰ وَعِيسَىٰٓ ۖ أَنْ أَقِيمُوا۟ ٱلدِّينَ وَلَا تَتَفَرَّقُوا۟ فِيهِ ۚ كَبُرَ عَلَى ٱلْمُشْرِكِينَ مَا تَدْعُوهُمْ إِلَيْهِ ۚ ٱللَّهُ يَجْتَبِىٓ إِلَيْهِ مَن يَشَآءُ وَيَهْدِىٓ إِلَيْهِ مَن يُنِيبُ', NULL, 25, 194, 6, 484, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 14, 'وَمَا تَفَرَّقُوٓا۟ إِلَّا مِنۢ بَعْدِ مَا جَآءَهُمُ ٱلْعِلْمُ بَغْيًۢا بَيْنَهُمْ ۚ وَلَوْلَا كَلِمَةٌۭ سَبَقَتْ مِن رَّبِّكَ إِلَىٰٓ أَجَلٍۢ مُّسَمًّۭى لَّقُضِىَ بَيْنَهُمْ ۚ وَإِنَّ ٱلَّذِينَ أُورِثُوا۟ ٱلْكِتَٰبَ مِنۢ بَعْدِهِمْ لَفِى شَكٍّۢ مِّنْهُ مُرِيبٍۢ', NULL, 25, 194, 6, 484, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 15, 'فَلِذَٰلِكَ فَٱدْعُ ۖ وَٱسْتَقِمْ كَمَآ أُمِرْتَ ۖ وَلَا تَتَّبِعْ أَهْوَآءَهُمْ ۖ وَقُلْ ءَامَنتُ بِمَآ أَنزَلَ ٱللَّهُ مِن كِتَٰبٍۢ ۖ وَأُمِرْتُ لِأَعْدِلَ بَيْنَكُمُ ۖ ٱللَّهُ رَبُّنَا وَرَبُّكُمْ ۖ لَنَآ أَعْمَٰلُنَا وَلَكُمْ أَعْمَٰلُكُمْ ۖ لَا حُجَّةَ بَيْنَنَا وَبَيْنَكُمُ ۖ ٱللَّهُ يَجْمَعُ بَيْنَنَا ۖ وَإِلَيْهِ ٱلْمَصِيرُ', NULL, 25, 194, 6, 484, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 16, 'وَٱلَّذِينَ يُحَآجُّونَ فِى ٱللَّهِ مِنۢ بَعْدِ مَا ٱسْتُجِيبَ لَهُۥ حُجَّتُهُمْ دَاحِضَةٌ عِندَ رَبِّهِمْ وَعَلَيْهِمْ غَضَبٌۭ وَلَهُمْ عَذَابٌۭ شَدِيدٌ', NULL, 25, 194, 6, 485, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 17, 'ٱللَّهُ ٱلَّذِىٓ أَنزَلَ ٱلْكِتَٰبَ بِٱلْحَقِّ وَٱلْمِيزَانَ ۗ وَمَا يُدْرِيكَ لَعَلَّ ٱلسَّاعَةَ قَرِيبٌۭ', NULL, 25, 194, 6, 485, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 18, 'يَسْتَعْجِلُ بِهَا ٱلَّذِينَ لَا يُؤْمِنُونَ بِهَا ۖ وَٱلَّذِينَ ءَامَنُوا۟ مُشْفِقُونَ مِنْهَا وَيَعْلَمُونَ أَنَّهَا ٱلْحَقُّ ۗ أَلَآ إِنَّ ٱلَّذِينَ يُمَارُونَ فِى ٱلسَّاعَةِ لَفِى ضَلَٰلٍۭ بَعِيدٍ', NULL, 25, 194, 6, 485, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 19, 'ٱللَّهُ لَطِيفٌۢ بِعِبَادِهِۦ يَرْزُقُ مَن يَشَآءُ ۖ وَهُوَ ٱلْقَوِىُّ ٱلْعَزِيزُ', NULL, 25, 194, 6, 485, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 20, 'مَن كَانَ يُرِيدُ حَرْثَ ٱلْءَاخِرَةِ نَزِدْ لَهُۥ فِى حَرْثِهِۦ ۖ وَمَن كَانَ يُرِيدُ حَرْثَ ٱلدُّنْيَا نُؤْتِهِۦ مِنْهَا وَمَا لَهُۥ فِى ٱلْءَاخِرَةِ مِن نَّصِيبٍ', NULL, 25, 194, 6, 485, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 21, 'أَمْ لَهُمْ شُرَكَٰٓؤُا۟ شَرَعُوا۟ لَهُم مِّنَ ٱلدِّينِ مَا لَمْ يَأْذَنۢ بِهِ ٱللَّهُ ۚ وَلَوْلَا كَلِمَةُ ٱلْفَصْلِ لَقُضِىَ بَيْنَهُمْ ۗ وَإِنَّ ٱلظَّٰلِمِينَ لَهُمْ عَذَابٌ أَلِيمٌۭ', NULL, 25, 194, 6, 485, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 22, 'تَرَى ٱلظَّٰلِمِينَ مُشْفِقِينَ مِمَّا كَسَبُوا۟ وَهُوَ وَاقِعٌۢ بِهِمْ ۗ وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ فِى رَوْضَاتِ ٱلْجَنَّاتِ ۖ لَهُم مَّا يَشَآءُونَ عِندَ رَبِّهِمْ ۚ ذَٰلِكَ هُوَ ٱلْفَضْلُ ٱلْكَبِيرُ', NULL, 25, 194, 6, 485, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 23, 'ذَٰلِكَ ٱلَّذِى يُبَشِّرُ ٱللَّهُ عِبَادَهُ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ ۗ قُل لَّآ أَسْـَٔلُكُمْ عَلَيْهِ أَجْرًا إِلَّا ٱلْمَوَدَّةَ فِى ٱلْقُرْبَىٰ ۗ وَمَن يَقْتَرِفْ حَسَنَةًۭ نَّزِدْ لَهُۥ فِيهَا حُسْنًا ۚ إِنَّ ٱللَّهَ غَفُورٌۭ شَكُورٌ', NULL, 25, 194, 6, 486, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 24, 'أَمْ يَقُولُونَ ٱفْتَرَىٰ عَلَى ٱللَّهِ كَذِبًۭا ۖ فَإِن يَشَإِ ٱللَّهُ يَخْتِمْ عَلَىٰ قَلْبِكَ ۗ وَيَمْحُ ٱللَّهُ ٱلْبَٰطِلَ وَيُحِقُّ ٱلْحَقَّ بِكَلِمَٰتِهِۦٓ ۚ إِنَّهُۥ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ', NULL, 25, 194, 6, 486, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 25, 'وَهُوَ ٱلَّذِى يَقْبَلُ ٱلتَّوْبَةَ عَنْ عِبَادِهِۦ وَيَعْفُوا۟ عَنِ ٱلسَّيِّـَٔاتِ وَيَعْلَمُ مَا تَفْعَلُونَ', NULL, 25, 194, 6, 486, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 26, 'وَيَسْتَجِيبُ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ وَيَزِيدُهُم مِّن فَضْلِهِۦ ۚ وَٱلْكَٰفِرُونَ لَهُمْ عَذَابٌۭ شَدِيدٌۭ', NULL, 25, 194, 6, 486, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 27, '۞ وَلَوْ بَسَطَ ٱللَّهُ ٱلرِّزْقَ لِعِبَادِهِۦ لَبَغَوْا۟ فِى ٱلْأَرْضِ وَلَٰكِن يُنَزِّلُ بِقَدَرٍۢ مَّا يَشَآءُ ۚ إِنَّهُۥ بِعِبَادِهِۦ خَبِيرٌۢ بَصِيرٌۭ', NULL, 25, 195, 6, 486, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 28, 'وَهُوَ ٱلَّذِى يُنَزِّلُ ٱلْغَيْثَ مِنۢ بَعْدِ مَا قَنَطُوا۟ وَيَنشُرُ رَحْمَتَهُۥ ۚ وَهُوَ ٱلْوَلِىُّ ٱلْحَمِيدُ', NULL, 25, 195, 6, 486, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 29, 'وَمِنْ ءَايَٰتِهِۦ خَلْقُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَمَا بَثَّ فِيهِمَا مِن دَآبَّةٍۢ ۚ وَهُوَ عَلَىٰ جَمْعِهِمْ إِذَا يَشَآءُ قَدِيرٌۭ', NULL, 25, 195, 6, 486, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 30, 'وَمَآ أَصَٰبَكُم مِّن مُّصِيبَةٍۢ فَبِمَا كَسَبَتْ أَيْدِيكُمْ وَيَعْفُوا۟ عَن كَثِيرٍۢ', NULL, 25, 195, 6, 486, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 31, 'وَمَآ أَنتُم بِمُعْجِزِينَ فِى ٱلْأَرْضِ ۖ وَمَا لَكُم مِّن دُونِ ٱللَّهِ مِن وَلِىٍّۢ وَلَا نَصِيرٍۢ', NULL, 25, 195, 6, 486, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 32, 'وَمِنْ ءَايَٰتِهِ ٱلْجَوَارِ فِى ٱلْبَحْرِ كَٱلْأَعْلَٰمِ', NULL, 25, 195, 6, 487, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 33, 'إِن يَشَأْ يُسْكِنِ ٱلرِّيحَ فَيَظْلَلْنَ رَوَاكِدَ عَلَىٰ ظَهْرِهِۦٓ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّكُلِّ صَبَّارٍۢ شَكُورٍ', NULL, 25, 195, 6, 487, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 34, 'أَوْ يُوبِقْهُنَّ بِمَا كَسَبُوا۟ وَيَعْفُ عَن كَثِيرٍۢ', NULL, 25, 195, 6, 487, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 35, 'وَيَعْلَمَ ٱلَّذِينَ يُجَٰدِلُونَ فِىٓ ءَايَٰتِنَا مَا لَهُم مِّن مَّحِيصٍۢ', NULL, 25, 195, 6, 487, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 36, 'فَمَآ أُوتِيتُم مِّن شَىْءٍۢ فَمَتَٰعُ ٱلْحَيَوٰةِ ٱلدُّنْيَا ۖ وَمَا عِندَ ٱللَّهِ خَيْرٌۭ وَأَبْقَىٰ لِلَّذِينَ ءَامَنُوا۟ وَعَلَىٰ رَبِّهِمْ يَتَوَكَّلُونَ', NULL, 25, 195, 6, 487, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 37, 'وَٱلَّذِينَ يَجْتَنِبُونَ كَبَٰٓئِرَ ٱلْإِثْمِ وَٱلْفَوَٰحِشَ وَإِذَا مَا غَضِبُوا۟ هُمْ يَغْفِرُونَ', NULL, 25, 195, 6, 487, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 38, 'وَٱلَّذِينَ ٱسْتَجَابُوا۟ لِرَبِّهِمْ وَأَقَامُوا۟ ٱلصَّلَوٰةَ وَأَمْرُهُمْ شُورَىٰ بَيْنَهُمْ وَمِمَّا رَزَقْنَٰهُمْ يُنفِقُونَ', NULL, 25, 195, 6, 487, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 39, 'وَٱلَّذِينَ إِذَآ أَصَابَهُمُ ٱلْبَغْىُ هُمْ يَنتَصِرُونَ', NULL, 25, 195, 6, 487, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 40, 'وَجَزَٰٓؤُا۟ سَيِّئَةٍۢ سَيِّئَةٌۭ مِّثْلُهَا ۖ فَمَنْ عَفَا وَأَصْلَحَ فَأَجْرُهُۥ عَلَى ٱللَّهِ ۚ إِنَّهُۥ لَا يُحِبُّ ٱلظَّٰلِمِينَ', NULL, 25, 195, 6, 487, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 41, 'وَلَمَنِ ٱنتَصَرَ بَعْدَ ظُلْمِهِۦ فَأُو۟لَٰٓئِكَ مَا عَلَيْهِم مِّن سَبِيلٍ', NULL, 25, 195, 6, 487, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 42, 'إِنَّمَا ٱلسَّبِيلُ عَلَى ٱلَّذِينَ يَظْلِمُونَ ٱلنَّاسَ وَيَبْغُونَ فِى ٱلْأَرْضِ بِغَيْرِ ٱلْحَقِّ ۚ أُو۟لَٰٓئِكَ لَهُمْ عَذَابٌ أَلِيمٌۭ', NULL, 25, 195, 6, 487, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 43, 'وَلَمَن صَبَرَ وَغَفَرَ إِنَّ ذَٰلِكَ لَمِنْ عَزْمِ ٱلْأُمُورِ', NULL, 25, 195, 6, 487, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 44, 'وَمَن يُضْلِلِ ٱللَّهُ فَمَا لَهُۥ مِن وَلِىٍّۢ مِّنۢ بَعْدِهِۦ ۗ وَتَرَى ٱلظَّٰلِمِينَ لَمَّا رَأَوُا۟ ٱلْعَذَابَ يَقُولُونَ هَلْ إِلَىٰ مَرَدٍّۢ مِّن سَبِيلٍۢ', NULL, 25, 195, 6, 487, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 45, 'وَتَرَىٰهُمْ يُعْرَضُونَ عَلَيْهَا خَٰشِعِينَ مِنَ ٱلذُّلِّ يَنظُرُونَ مِن طَرْفٍ خَفِىٍّۢ ۗ وَقَالَ ٱلَّذِينَ ءَامَنُوٓا۟ إِنَّ ٱلْخَٰسِرِينَ ٱلَّذِينَ خَسِرُوٓا۟ أَنفُسَهُمْ وَأَهْلِيهِمْ يَوْمَ ٱلْقِيَٰمَةِ ۗ أَلَآ إِنَّ ٱلظَّٰلِمِينَ فِى عَذَابٍۢ مُّقِيمٍۢ', NULL, 25, 195, 6, 488, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 46, 'وَمَا كَانَ لَهُم مِّنْ أَوْلِيَآءَ يَنصُرُونَهُم مِّن دُونِ ٱللَّهِ ۗ وَمَن يُضْلِلِ ٱللَّهُ فَمَا لَهُۥ مِن سَبِيلٍ', NULL, 25, 195, 6, 488, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 47, 'ٱسْتَجِيبُوا۟ لِرَبِّكُم مِّن قَبْلِ أَن يَأْتِىَ يَوْمٌۭ لَّا مَرَدَّ لَهُۥ مِنَ ٱللَّهِ ۚ مَا لَكُم مِّن مَّلْجَإٍۢ يَوْمَئِذٍۢ وَمَا لَكُم مِّن نَّكِيرٍۢ', NULL, 25, 195, 6, 488, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 48, 'فَإِنْ أَعْرَضُوا۟ فَمَآ أَرْسَلْنَٰكَ عَلَيْهِمْ حَفِيظًا ۖ إِنْ عَلَيْكَ إِلَّا ٱلْبَلَٰغُ ۗ وَإِنَّآ إِذَآ أَذَقْنَا ٱلْإِنسَٰنَ مِنَّا رَحْمَةًۭ فَرِحَ بِهَا ۖ وَإِن تُصِبْهُمْ سَيِّئَةٌۢ بِمَا قَدَّمَتْ أَيْدِيهِمْ فَإِنَّ ٱلْإِنسَٰنَ كَفُورٌۭ', NULL, 25, 195, 6, 488, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 49, 'لِّلَّهِ مُلْكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ يَخْلُقُ مَا يَشَآءُ ۚ يَهَبُ لِمَن يَشَآءُ إِنَٰثًۭا وَيَهَبُ لِمَن يَشَآءُ ٱلذُّكُورَ', NULL, 25, 195, 6, 488, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 50, 'أَوْ يُزَوِّجُهُمْ ذُكْرَانًۭا وَإِنَٰثًۭا ۖ وَيَجْعَلُ مَن يَشَآءُ عَقِيمًا ۚ إِنَّهُۥ عَلِيمٌۭ قَدِيرٌۭ', NULL, 25, 195, 6, 488, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 51, '۞ وَمَا كَانَ لِبَشَرٍ أَن يُكَلِّمَهُ ٱللَّهُ إِلَّا وَحْيًا أَوْ مِن وَرَآئِ حِجَابٍ أَوْ يُرْسِلَ رَسُولًۭا فَيُوحِىَ بِإِذْنِهِۦ مَا يَشَآءُ ۚ إِنَّهُۥ عَلِىٌّ حَكِيمٌۭ', NULL, 25, 196, 6, 488, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 52, 'وَكَذَٰلِكَ أَوْحَيْنَآ إِلَيْكَ رُوحًۭا مِّنْ أَمْرِنَا ۚ مَا كُنتَ تَدْرِى مَا ٱلْكِتَٰبُ وَلَا ٱلْإِيمَٰنُ وَلَٰكِن جَعَلْنَٰهُ نُورًۭا نَّهْدِى بِهِۦ مَن نَّشَآءُ مِنْ عِبَادِنَا ۚ وَإِنَّكَ لَتَهْدِىٓ إِلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍۢ', NULL, 25, 196, 6, 489, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 42), 53, 'صِرَٰطِ ٱللَّهِ ٱلَّذِى لَهُۥ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۗ أَلَآ إِلَى ٱللَّهِ تَصِيرُ ٱلْأُمُورُ', NULL, 25, 196, 6, 489, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ حمٓ', NULL, 25, 196, 6, 489, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 2, 'وَٱلْكِتَٰبِ ٱلْمُبِينِ', NULL, 25, 196, 6, 489, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 3, 'إِنَّا جَعَلْنَٰهُ قُرْءَٰنًا عَرَبِيًّۭا لَّعَلَّكُمْ تَعْقِلُونَ', NULL, 25, 196, 6, 489, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 4, 'وَإِنَّهُۥ فِىٓ أُمِّ ٱلْكِتَٰبِ لَدَيْنَا لَعَلِىٌّ حَكِيمٌ', NULL, 25, 196, 6, 489, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 5, 'أَفَنَضْرِبُ عَنكُمُ ٱلذِّكْرَ صَفْحًا أَن كُنتُمْ قَوْمًۭا مُّسْرِفِينَ', NULL, 25, 196, 6, 489, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 6, 'وَكَمْ أَرْسَلْنَا مِن نَّبِىٍّۢ فِى ٱلْأَوَّلِينَ', NULL, 25, 196, 6, 489, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 7, 'وَمَا يَأْتِيهِم مِّن نَّبِىٍّ إِلَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ', NULL, 25, 196, 6, 489, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 8, 'فَأَهْلَكْنَآ أَشَدَّ مِنْهُم بَطْشًۭا وَمَضَىٰ مَثَلُ ٱلْأَوَّلِينَ', NULL, 25, 196, 6, 489, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 9, 'وَلَئِن سَأَلْتَهُم مَّنْ خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ لَيَقُولُنَّ خَلَقَهُنَّ ٱلْعَزِيزُ ٱلْعَلِيمُ', NULL, 25, 196, 6, 489, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 10, 'ٱلَّذِى جَعَلَ لَكُمُ ٱلْأَرْضَ مَهْدًۭا وَجَعَلَ لَكُمْ فِيهَا سُبُلًۭا لَّعَلَّكُمْ تَهْتَدُونَ', NULL, 25, 196, 6, 489, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 11, 'وَٱلَّذِى نَزَّلَ مِنَ ٱلسَّمَآءِ مَآءًۢ بِقَدَرٍۢ فَأَنشَرْنَا بِهِۦ بَلْدَةًۭ مَّيْتًۭا ۚ كَذَٰلِكَ تُخْرَجُونَ', NULL, 25, 196, 6, 490, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 12, 'وَٱلَّذِى خَلَقَ ٱلْأَزْوَٰجَ كُلَّهَا وَجَعَلَ لَكُم مِّنَ ٱلْفُلْكِ وَٱلْأَنْعَٰمِ مَا تَرْكَبُونَ', NULL, 25, 196, 6, 490, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 13, 'لِتَسْتَوُۥا۟ عَلَىٰ ظُهُورِهِۦ ثُمَّ تَذْكُرُوا۟ نِعْمَةَ رَبِّكُمْ إِذَا ٱسْتَوَيْتُمْ عَلَيْهِ وَتَقُولُوا۟ سُبْحَٰنَ ٱلَّذِى سَخَّرَ لَنَا هَٰذَا وَمَا كُنَّا لَهُۥ مُقْرِنِينَ', NULL, 25, 196, 6, 490, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 14, 'وَإِنَّآ إِلَىٰ رَبِّنَا لَمُنقَلِبُونَ', NULL, 25, 196, 6, 490, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 15, 'وَجَعَلُوا۟ لَهُۥ مِنْ عِبَادِهِۦ جُزْءًا ۚ إِنَّ ٱلْإِنسَٰنَ لَكَفُورٌۭ مُّبِينٌ', NULL, 25, 196, 6, 490, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 16, 'أَمِ ٱتَّخَذَ مِمَّا يَخْلُقُ بَنَاتٍۢ وَأَصْفَىٰكُم بِٱلْبَنِينَ', NULL, 25, 196, 6, 490, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 17, 'وَإِذَا بُشِّرَ أَحَدُهُم بِمَا ضَرَبَ لِلرَّحْمَٰنِ مَثَلًۭا ظَلَّ وَجْهُهُۥ مُسْوَدًّۭا وَهُوَ كَظِيمٌ', NULL, 25, 196, 6, 490, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 18, 'أَوَمَن يُنَشَّؤُا۟ فِى ٱلْحِلْيَةِ وَهُوَ فِى ٱلْخِصَامِ غَيْرُ مُبِينٍۢ', NULL, 25, 196, 6, 490, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 19, 'وَجَعَلُوا۟ ٱلْمَلَٰٓئِكَةَ ٱلَّذِينَ هُمْ عِبَٰدُ ٱلرَّحْمَٰنِ إِنَٰثًا ۚ أَشَهِدُوا۟ خَلْقَهُمْ ۚ سَتُكْتَبُ شَهَٰدَتُهُمْ وَيُسْـَٔلُونَ', NULL, 25, 196, 6, 490, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 20, 'وَقَالُوا۟ لَوْ شَآءَ ٱلرَّحْمَٰنُ مَا عَبَدْنَٰهُم ۗ مَّا لَهُم بِذَٰلِكَ مِنْ عِلْمٍ ۖ إِنْ هُمْ إِلَّا يَخْرُصُونَ', NULL, 25, 196, 6, 490, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 21, 'أَمْ ءَاتَيْنَٰهُمْ كِتَٰبًۭا مِّن قَبْلِهِۦ فَهُم بِهِۦ مُسْتَمْسِكُونَ', NULL, 25, 196, 6, 490, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 22, 'بَلْ قَالُوٓا۟ إِنَّا وَجَدْنَآ ءَابَآءَنَا عَلَىٰٓ أُمَّةٍۢ وَإِنَّا عَلَىٰٓ ءَاثَٰرِهِم مُّهْتَدُونَ', NULL, 25, 196, 6, 490, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 23, 'وَكَذَٰلِكَ مَآ أَرْسَلْنَا مِن قَبْلِكَ فِى قَرْيَةٍۢ مِّن نَّذِيرٍ إِلَّا قَالَ مُتْرَفُوهَآ إِنَّا وَجَدْنَآ ءَابَآءَنَا عَلَىٰٓ أُمَّةٍۢ وَإِنَّا عَلَىٰٓ ءَاثَٰرِهِم مُّقْتَدُونَ', NULL, 25, 196, 6, 491, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 24, '۞ قَٰلَ أَوَلَوْ جِئْتُكُم بِأَهْدَىٰ مِمَّا وَجَدتُّمْ عَلَيْهِ ءَابَآءَكُمْ ۖ قَالُوٓا۟ إِنَّا بِمَآ أُرْسِلْتُم بِهِۦ كَٰفِرُونَ', NULL, 25, 197, 6, 491, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 25, 'فَٱنتَقَمْنَا مِنْهُمْ ۖ فَٱنظُرْ كَيْفَ كَانَ عَٰقِبَةُ ٱلْمُكَذِّبِينَ', NULL, 25, 197, 6, 491, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 26, 'وَإِذْ قَالَ إِبْرَٰهِيمُ لِأَبِيهِ وَقَوْمِهِۦٓ إِنَّنِى بَرَآءٌۭ مِّمَّا تَعْبُدُونَ', NULL, 25, 197, 6, 491, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 27, 'إِلَّا ٱلَّذِى فَطَرَنِى فَإِنَّهُۥ سَيَهْدِينِ', NULL, 25, 197, 6, 491, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 28, 'وَجَعَلَهَا كَلِمَةًۢ بَاقِيَةًۭ فِى عَقِبِهِۦ لَعَلَّهُمْ يَرْجِعُونَ', NULL, 25, 197, 6, 491, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 29, 'بَلْ مَتَّعْتُ هَٰٓؤُلَآءِ وَءَابَآءَهُمْ حَتَّىٰ جَآءَهُمُ ٱلْحَقُّ وَرَسُولٌۭ مُّبِينٌۭ', NULL, 25, 197, 6, 491, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 30, 'وَلَمَّا جَآءَهُمُ ٱلْحَقُّ قَالُوا۟ هَٰذَا سِحْرٌۭ وَإِنَّا بِهِۦ كَٰفِرُونَ', NULL, 25, 197, 6, 491, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 31, 'وَقَالُوا۟ لَوْلَا نُزِّلَ هَٰذَا ٱلْقُرْءَانُ عَلَىٰ رَجُلٍۢ مِّنَ ٱلْقَرْيَتَيْنِ عَظِيمٍ', NULL, 25, 197, 6, 491, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 32, 'أَهُمْ يَقْسِمُونَ رَحْمَتَ رَبِّكَ ۚ نَحْنُ قَسَمْنَا بَيْنَهُم مَّعِيشَتَهُمْ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا ۚ وَرَفَعْنَا بَعْضَهُمْ فَوْقَ بَعْضٍۢ دَرَجَٰتٍۢ لِّيَتَّخِذَ بَعْضُهُم بَعْضًۭا سُخْرِيًّۭا ۗ وَرَحْمَتُ رَبِّكَ خَيْرٌۭ مِّمَّا يَجْمَعُونَ', NULL, 25, 197, 6, 491, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 33, 'وَلَوْلَآ أَن يَكُونَ ٱلنَّاسُ أُمَّةًۭ وَٰحِدَةًۭ لَّجَعَلْنَا لِمَن يَكْفُرُ بِٱلرَّحْمَٰنِ لِبُيُوتِهِمْ سُقُفًۭا مِّن فِضَّةٍۢ وَمَعَارِجَ عَلَيْهَا يَظْهَرُونَ', NULL, 25, 197, 6, 491, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 34, 'وَلِبُيُوتِهِمْ أَبْوَٰبًۭا وَسُرُرًا عَلَيْهَا يَتَّكِـُٔونَ', NULL, 25, 197, 6, 492, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 35, 'وَزُخْرُفًۭا ۚ وَإِن كُلُّ ذَٰلِكَ لَمَّا مَتَٰعُ ٱلْحَيَوٰةِ ٱلدُّنْيَا ۚ وَٱلْءَاخِرَةُ عِندَ رَبِّكَ لِلْمُتَّقِينَ', NULL, 25, 197, 6, 492, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 36, 'وَمَن يَعْشُ عَن ذِكْرِ ٱلرَّحْمَٰنِ نُقَيِّضْ لَهُۥ شَيْطَٰنًۭا فَهُوَ لَهُۥ قَرِينٌۭ', NULL, 25, 197, 6, 492, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 37, 'وَإِنَّهُمْ لَيَصُدُّونَهُمْ عَنِ ٱلسَّبِيلِ وَيَحْسَبُونَ أَنَّهُم مُّهْتَدُونَ', NULL, 25, 197, 6, 492, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 38, 'حَتَّىٰٓ إِذَا جَآءَنَا قَالَ يَٰلَيْتَ بَيْنِى وَبَيْنَكَ بُعْدَ ٱلْمَشْرِقَيْنِ فَبِئْسَ ٱلْقَرِينُ', NULL, 25, 197, 6, 492, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 39, 'وَلَن يَنفَعَكُمُ ٱلْيَوْمَ إِذ ظَّلَمْتُمْ أَنَّكُمْ فِى ٱلْعَذَابِ مُشْتَرِكُونَ', NULL, 25, 197, 6, 492, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 40, 'أَفَأَنتَ تُسْمِعُ ٱلصُّمَّ أَوْ تَهْدِى ٱلْعُمْىَ وَمَن كَانَ فِى ضَلَٰلٍۢ مُّبِينٍۢ', NULL, 25, 197, 6, 492, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 41, 'فَإِمَّا نَذْهَبَنَّ بِكَ فَإِنَّا مِنْهُم مُّنتَقِمُونَ', NULL, 25, 197, 6, 492, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 42, 'أَوْ نُرِيَنَّكَ ٱلَّذِى وَعَدْنَٰهُمْ فَإِنَّا عَلَيْهِم مُّقْتَدِرُونَ', NULL, 25, 197, 6, 492, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 43, 'فَٱسْتَمْسِكْ بِٱلَّذِىٓ أُوحِىَ إِلَيْكَ ۖ إِنَّكَ عَلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍۢ', NULL, 25, 197, 6, 492, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 44, 'وَإِنَّهُۥ لَذِكْرٌۭ لَّكَ وَلِقَوْمِكَ ۖ وَسَوْفَ تُسْـَٔلُونَ', NULL, 25, 197, 6, 492, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 45, 'وَسْـَٔلْ مَنْ أَرْسَلْنَا مِن قَبْلِكَ مِن رُّسُلِنَآ أَجَعَلْنَا مِن دُونِ ٱلرَّحْمَٰنِ ءَالِهَةًۭ يُعْبَدُونَ', NULL, 25, 197, 6, 492, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 46, 'وَلَقَدْ أَرْسَلْنَا مُوسَىٰ بِـَٔايَٰتِنَآ إِلَىٰ فِرْعَوْنَ وَمَلَإِي۟هِۦ فَقَالَ إِنِّى رَسُولُ رَبِّ ٱلْعَٰلَمِينَ', NULL, 25, 197, 6, 492, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 47, 'فَلَمَّا جَآءَهُم بِـَٔايَٰتِنَآ إِذَا هُم مِّنْهَا يَضْحَكُونَ', NULL, 25, 197, 6, 492, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 48, 'وَمَا نُرِيهِم مِّنْ ءَايَةٍ إِلَّا هِىَ أَكْبَرُ مِنْ أُخْتِهَا ۖ وَأَخَذْنَٰهُم بِٱلْعَذَابِ لَعَلَّهُمْ يَرْجِعُونَ', NULL, 25, 197, 6, 493, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 49, 'وَقَالُوا۟ يَٰٓأَيُّهَ ٱلسَّاحِرُ ٱدْعُ لَنَا رَبَّكَ بِمَا عَهِدَ عِندَكَ إِنَّنَا لَمُهْتَدُونَ', NULL, 25, 197, 6, 493, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 50, 'فَلَمَّا كَشَفْنَا عَنْهُمُ ٱلْعَذَابَ إِذَا هُمْ يَنكُثُونَ', NULL, 25, 197, 6, 493, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 51, 'وَنَادَىٰ فِرْعَوْنُ فِى قَوْمِهِۦ قَالَ يَٰقَوْمِ أَلَيْسَ لِى مُلْكُ مِصْرَ وَهَٰذِهِ ٱلْأَنْهَٰرُ تَجْرِى مِن تَحْتِىٓ ۖ أَفَلَا تُبْصِرُونَ', NULL, 25, 197, 6, 493, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 52, 'أَمْ أَنَا۠ خَيْرٌۭ مِّنْ هَٰذَا ٱلَّذِى هُوَ مَهِينٌۭ وَلَا يَكَادُ يُبِينُ', NULL, 25, 197, 6, 493, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 53, 'فَلَوْلَآ أُلْقِىَ عَلَيْهِ أَسْوِرَةٌۭ مِّن ذَهَبٍ أَوْ جَآءَ مَعَهُ ٱلْمَلَٰٓئِكَةُ مُقْتَرِنِينَ', NULL, 25, 197, 6, 493, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 54, 'فَٱسْتَخَفَّ قَوْمَهُۥ فَأَطَاعُوهُ ۚ إِنَّهُمْ كَانُوا۟ قَوْمًۭا فَٰسِقِينَ', NULL, 25, 197, 6, 493, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 55, 'فَلَمَّآ ءَاسَفُونَا ٱنتَقَمْنَا مِنْهُمْ فَأَغْرَقْنَٰهُمْ أَجْمَعِينَ', NULL, 25, 197, 6, 493, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 56, 'فَجَعَلْنَٰهُمْ سَلَفًۭا وَمَثَلًۭا لِّلْءَاخِرِينَ', NULL, 25, 197, 6, 493, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 57, '۞ وَلَمَّا ضُرِبَ ٱبْنُ مَرْيَمَ مَثَلًا إِذَا قَوْمُكَ مِنْهُ يَصِدُّونَ', NULL, 25, 198, 6, 493, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 58, 'وَقَالُوٓا۟ ءَأَٰلِهَتُنَا خَيْرٌ أَمْ هُوَ ۚ مَا ضَرَبُوهُ لَكَ إِلَّا جَدَلًۢا ۚ بَلْ هُمْ قَوْمٌ خَصِمُونَ', NULL, 25, 198, 6, 493, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 59, 'إِنْ هُوَ إِلَّا عَبْدٌ أَنْعَمْنَا عَلَيْهِ وَجَعَلْنَٰهُ مَثَلًۭا لِّبَنِىٓ إِسْرَٰٓءِيلَ', NULL, 25, 198, 6, 493, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 60, 'وَلَوْ نَشَآءُ لَجَعَلْنَا مِنكُم مَّلَٰٓئِكَةًۭ فِى ٱلْأَرْضِ يَخْلُفُونَ', NULL, 25, 198, 6, 493, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 61, 'وَإِنَّهُۥ لَعِلْمٌۭ لِّلسَّاعَةِ فَلَا تَمْتَرُنَّ بِهَا وَٱتَّبِعُونِ ۚ هَٰذَا صِرَٰطٌۭ مُّسْتَقِيمٌۭ', NULL, 25, 198, 6, 494, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 62, 'وَلَا يَصُدَّنَّكُمُ ٱلشَّيْطَٰنُ ۖ إِنَّهُۥ لَكُمْ عَدُوٌّۭ مُّبِينٌۭ', NULL, 25, 198, 6, 494, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 63, 'وَلَمَّا جَآءَ عِيسَىٰ بِٱلْبَيِّنَٰتِ قَالَ قَدْ جِئْتُكُم بِٱلْحِكْمَةِ وَلِأُبَيِّنَ لَكُم بَعْضَ ٱلَّذِى تَخْتَلِفُونَ فِيهِ ۖ فَٱتَّقُوا۟ ٱللَّهَ وَأَطِيعُونِ', NULL, 25, 198, 6, 494, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 64, 'إِنَّ ٱللَّهَ هُوَ رَبِّى وَرَبُّكُمْ فَٱعْبُدُوهُ ۚ هَٰذَا صِرَٰطٌۭ مُّسْتَقِيمٌۭ', NULL, 25, 198, 6, 494, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 65, 'فَٱخْتَلَفَ ٱلْأَحْزَابُ مِنۢ بَيْنِهِمْ ۖ فَوَيْلٌۭ لِّلَّذِينَ ظَلَمُوا۟ مِنْ عَذَابِ يَوْمٍ أَلِيمٍ', NULL, 25, 198, 6, 494, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 66, 'هَلْ يَنظُرُونَ إِلَّا ٱلسَّاعَةَ أَن تَأْتِيَهُم بَغْتَةًۭ وَهُمْ لَا يَشْعُرُونَ', NULL, 25, 198, 6, 494, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 67, 'ٱلْأَخِلَّآءُ يَوْمَئِذٍۭ بَعْضُهُمْ لِبَعْضٍ عَدُوٌّ إِلَّا ٱلْمُتَّقِينَ', NULL, 25, 198, 6, 494, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 68, 'يَٰعِبَادِ لَا خَوْفٌ عَلَيْكُمُ ٱلْيَوْمَ وَلَآ أَنتُمْ تَحْزَنُونَ', NULL, 25, 198, 6, 494, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 69, 'ٱلَّذِينَ ءَامَنُوا۟ بِـَٔايَٰتِنَا وَكَانُوا۟ مُسْلِمِينَ', NULL, 25, 198, 6, 494, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 70, 'ٱدْخُلُوا۟ ٱلْجَنَّةَ أَنتُمْ وَأَزْوَٰجُكُمْ تُحْبَرُونَ', NULL, 25, 198, 6, 494, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 71, 'يُطَافُ عَلَيْهِم بِصِحَافٍۢ مِّن ذَهَبٍۢ وَأَكْوَابٍۢ ۖ وَفِيهَا مَا تَشْتَهِيهِ ٱلْأَنفُسُ وَتَلَذُّ ٱلْأَعْيُنُ ۖ وَأَنتُمْ فِيهَا خَٰلِدُونَ', NULL, 25, 198, 6, 494, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 72, 'وَتِلْكَ ٱلْجَنَّةُ ٱلَّتِىٓ أُورِثْتُمُوهَا بِمَا كُنتُمْ تَعْمَلُونَ', NULL, 25, 198, 6, 494, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 73, 'لَكُمْ فِيهَا فَٰكِهَةٌۭ كَثِيرَةٌۭ مِّنْهَا تَأْكُلُونَ', NULL, 25, 198, 6, 494, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 74, 'إِنَّ ٱلْمُجْرِمِينَ فِى عَذَابِ جَهَنَّمَ خَٰلِدُونَ', NULL, 25, 198, 6, 495, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 75, 'لَا يُفَتَّرُ عَنْهُمْ وَهُمْ فِيهِ مُبْلِسُونَ', NULL, 25, 198, 6, 495, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 76, 'وَمَا ظَلَمْنَٰهُمْ وَلَٰكِن كَانُوا۟ هُمُ ٱلظَّٰلِمِينَ', NULL, 25, 198, 6, 495, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 77, 'وَنَادَوْا۟ يَٰمَٰلِكُ لِيَقْضِ عَلَيْنَا رَبُّكَ ۖ قَالَ إِنَّكُم مَّٰكِثُونَ', NULL, 25, 198, 6, 495, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 78, 'لَقَدْ جِئْنَٰكُم بِٱلْحَقِّ وَلَٰكِنَّ أَكْثَرَكُمْ لِلْحَقِّ كَٰرِهُونَ', NULL, 25, 198, 6, 495, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 79, 'أَمْ أَبْرَمُوٓا۟ أَمْرًۭا فَإِنَّا مُبْرِمُونَ', NULL, 25, 198, 6, 495, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 80, 'أَمْ يَحْسَبُونَ أَنَّا لَا نَسْمَعُ سِرَّهُمْ وَنَجْوَىٰهُم ۚ بَلَىٰ وَرُسُلُنَا لَدَيْهِمْ يَكْتُبُونَ', NULL, 25, 198, 6, 495, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 81, 'قُلْ إِن كَانَ لِلرَّحْمَٰنِ وَلَدٌۭ فَأَنَا۠ أَوَّلُ ٱلْعَٰبِدِينَ', NULL, 25, 198, 6, 495, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 82, 'سُبْحَٰنَ رَبِّ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ رَبِّ ٱلْعَرْشِ عَمَّا يَصِفُونَ', NULL, 25, 198, 6, 495, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 83, 'فَذَرْهُمْ يَخُوضُوا۟ وَيَلْعَبُوا۟ حَتَّىٰ يُلَٰقُوا۟ يَوْمَهُمُ ٱلَّذِى يُوعَدُونَ', NULL, 25, 198, 6, 495, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 84, 'وَهُوَ ٱلَّذِى فِى ٱلسَّمَآءِ إِلَٰهٌۭ وَفِى ٱلْأَرْضِ إِلَٰهٌۭ ۚ وَهُوَ ٱلْحَكِيمُ ٱلْعَلِيمُ', NULL, 25, 198, 6, 495, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 85, 'وَتَبَارَكَ ٱلَّذِى لَهُۥ مُلْكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَمَا بَيْنَهُمَا وَعِندَهُۥ عِلْمُ ٱلسَّاعَةِ وَإِلَيْهِ تُرْجَعُونَ', NULL, 25, 198, 6, 495, false, NOW(), NOW()),
