((SELECT id FROM mst_surah WHERE surah_number = 43), 88, 'وَقِيلِهِۦ يَٰرَبِّ إِنَّ هَٰٓؤُلَآءِ قَوْمٌۭ لَّا يُؤْمِنُونَ', NULL, 25, 198, 6, 495, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 43), 89, 'فَٱصْفَحْ عَنْهُمْ وَقُلْ سَلَٰمٌۭ ۚ فَسَوْفَ يَعْلَمُونَ', NULL, 25, 198, 6, 495, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 44), 1, 'بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ حمٓ', NULL, 25, 198, 6, 496, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 44), 2, 'وَٱلْكِتَٰبِ ٱلْمُبِينِ', NULL, 25, 198, 6, 496, false, NOW(), NOW()),
