((SELECT id FROM mst_surah WHERE surah_number = 44), 18, 'أَنْ أَدُّوٓا۟ إِلَىَّ عِبَادَ ٱللَّهِ ۖ إِنِّى لَكُمْ رَسُولٌ أَمِينٌۭ', NULL, 25, 199, 6, 496, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 44), 19, 'وَأَن لَّا تَعْلُوا۟ عَلَى ٱللَّهِ ۖ إِنِّىٓ ءَاتِيكُم بِسُلْطَٰنٍۢ مُّبِينٍۢ', NULL, 25, 199, 6, 497, false, NOW(), NOW()),
