((SELECT id FROM mst_surah WHERE surah_number = 44), 23, 'فَأَسْرِ بِعِبَادِى لَيْلًا إِنَّكُم مُّتَّبَعُونَ', NULL, 25, 199, 6, 497, false, NOW(), NOW()),
