((SELECT id FROM mst_surah WHERE surah_number = 44), 54, 'كَذَٰلِكَ وَزَوَّجْنَٰهُم بِحُورٍ عِينٍۢ', NULL, 25, 199, 6, 498, false, NOW(), NOW()),
