((SELECT id FROM mst_surah WHERE surah_number = 45), 4, 'وَفِى خَلْقِكُمْ وَمَا يَبُثُّ مِن دَآبَّةٍ ءَايَٰتٌۭ لِّقَوْمٍۢ يُوقِنُونَ', NULL, 25, 199, 6, 499, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 5, 'وَٱخْتِلَٰفِ ٱلَّيْلِ وَٱلنَّهَارِ وَمَآ أَنزَلَ ٱللَّهُ مِنَ ٱلسَّمَآءِ مِن رِّزْقٍۢ فَأَحْيَا بِهِ ٱلْأَرْضَ بَعْدَ مَوْتِهَا وَتَصْرِيفِ ٱلرِّيَٰحِ ءَايَٰتٌۭ لِّقَوْمٍۢ يَعْقِلُونَ', NULL, 25, 199, 6, 499, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 6, 'تِلْكَ ءَايَٰتُ ٱللَّهِ نَتْلُوهَا عَلَيْكَ بِٱلْحَقِّ ۖ فَبِأَىِّ حَدِيثٍۭ بَعْدَ ٱللَّهِ وَءَايَٰتِهِۦ يُؤْمِنُونَ', NULL, 25, 199, 6, 499, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 7, 'وَيْلٌۭ لِّكُلِّ أَفَّاكٍ أَثِيمٍۢ', NULL, 25, 199, 6, 499, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 8, 'يَسْمَعُ ءَايَٰتِ ٱللَّهِ تُتْلَىٰ عَلَيْهِ ثُمَّ يُصِرُّ مُسْتَكْبِرًۭا كَأَن لَّمْ يَسْمَعْهَا ۖ فَبَشِّرْهُ بِعَذَابٍ أَلِيمٍۢ', NULL, 25, 199, 6, 499, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 9, 'وَإِذَا عَلِمَ مِنْ ءَايَٰتِنَا شَيْـًٔا ٱتَّخَذَهَا هُزُوًا ۚ أُو۟لَٰٓئِكَ لَهُمْ عَذَابٌۭ مُّهِينٌۭ', NULL, 25, 199, 6, 499, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 10, 'مِّن وَرَآئِهِمْ جَهَنَّمُ ۖ وَلَا يُغْنِى عَنْهُم مَّا كَسَبُوا۟ شَيْـًۭٔا وَلَا مَا ٱتَّخَذُوا۟ مِن دُونِ ٱللَّهِ أَوْلِيَآءَ ۖ وَلَهُمْ عَذَابٌ عَظِيمٌ', NULL, 25, 199, 6, 499, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 11, 'هَٰذَا هُدًۭى ۖ وَٱلَّذِينَ كَفَرُوا۟ بِـَٔايَٰتِ رَبِّهِمْ لَهُمْ عَذَابٌۭ مِّن رِّجْزٍ أَلِيمٌ', NULL, 25, 199, 6, 499, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 12, '۞ ٱللَّهُ ٱلَّذِى سَخَّرَ لَكُمُ ٱلْبَحْرَ لِتَجْرِىَ ٱلْفُلْكُ فِيهِ بِأَمْرِهِۦ وَلِتَبْتَغُوا۟ مِن فَضْلِهِۦ وَلَعَلَّكُمْ تَشْكُرُونَ', NULL, 25, 200, 6, 499, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 13, 'وَسَخَّرَ لَكُم مَّا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ جَمِيعًۭا مِّنْهُ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّقَوْمٍۢ يَتَفَكَّرُونَ', NULL, 25, 200, 6, 499, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 14, 'قُل لِّلَّذِينَ ءَامَنُوا۟ يَغْفِرُوا۟ لِلَّذِينَ لَا يَرْجُونَ أَيَّامَ ٱللَّهِ لِيَجْزِىَ قَوْمًۢا بِمَا كَانُوا۟ يَكْسِبُونَ', NULL, 25, 200, 6, 500, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 15, 'مَنْ عَمِلَ صَٰلِحًۭا فَلِنَفْسِهِۦ ۖ وَمَنْ أَسَآءَ فَعَلَيْهَا ۖ ثُمَّ إِلَىٰ رَبِّكُمْ تُرْجَعُونَ', NULL, 25, 200, 6, 500, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 16, 'وَلَقَدْ ءَاتَيْنَا بَنِىٓ إِسْرَٰٓءِيلَ ٱلْكِتَٰبَ وَٱلْحُكْمَ وَٱلنُّبُوَّةَ وَرَزَقْنَٰهُم مِّنَ ٱلطَّيِّبَٰتِ وَفَضَّلْنَٰهُمْ عَلَى ٱلْعَٰلَمِينَ', NULL, 25, 200, 6, 500, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 17, 'وَءَاتَيْنَٰهُم بَيِّنَٰتٍۢ مِّنَ ٱلْأَمْرِ ۖ فَمَا ٱخْتَلَفُوٓا۟ إِلَّا مِنۢ بَعْدِ مَا جَآءَهُمُ ٱلْعِلْمُ بَغْيًۢا بَيْنَهُمْ ۚ إِنَّ رَبَّكَ يَقْضِى بَيْنَهُمْ يَوْمَ ٱلْقِيَٰمَةِ فِيمَا كَانُوا۟ فِيهِ يَخْتَلِفُونَ', NULL, 25, 200, 6, 500, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 18, 'ثُمَّ جَعَلْنَٰكَ عَلَىٰ شَرِيعَةٍۢ مِّنَ ٱلْأَمْرِ فَٱتَّبِعْهَا وَلَا تَتَّبِعْ أَهْوَآءَ ٱلَّذِينَ لَا يَعْلَمُونَ', NULL, 25, 200, 6, 500, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 19, 'إِنَّهُمْ لَن يُغْنُوا۟ عَنكَ مِنَ ٱللَّهِ شَيْـًۭٔا ۚ وَإِنَّ ٱلظَّٰلِمِينَ بَعْضُهُمْ أَوْلِيَآءُ بَعْضٍۢ ۖ وَٱللَّهُ وَلِىُّ ٱلْمُتَّقِينَ', NULL, 25, 200, 6, 500, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 20, 'هَٰذَا بَصَٰٓئِرُ لِلنَّاسِ وَهُدًۭى وَرَحْمَةٌۭ لِّقَوْمٍۢ يُوقِنُونَ', NULL, 25, 200, 6, 500, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 21, 'أَمْ حَسِبَ ٱلَّذِينَ ٱجْتَرَحُوا۟ ٱلسَّيِّـَٔاتِ أَن نَّجْعَلَهُمْ كَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ سَوَآءًۭ مَّحْيَاهُمْ وَمَمَاتُهُمْ ۚ سَآءَ مَا يَحْكُمُونَ', NULL, 25, 200, 6, 500, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 22, 'وَخَلَقَ ٱللَّهُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ بِٱلْحَقِّ وَلِتُجْزَىٰ كُلُّ نَفْسٍۭ بِمَا كَسَبَتْ وَهُمْ لَا يُظْلَمُونَ', NULL, 25, 200, 6, 500, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 23, 'أَفَرَءَيْتَ مَنِ ٱتَّخَذَ إِلَٰهَهُۥ هَوَىٰهُ وَأَضَلَّهُ ٱللَّهُ عَلَىٰ عِلْمٍۢ وَخَتَمَ عَلَىٰ سَمْعِهِۦ وَقَلْبِهِۦ وَجَعَلَ عَلَىٰ بَصَرِهِۦ غِشَٰوَةًۭ فَمَن يَهْدِيهِ مِنۢ بَعْدِ ٱللَّهِ ۚ أَفَلَا تَذَكَّرُونَ', NULL, 25, 200, 6, 501, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 24, 'وَقَالُوا۟ مَا هِىَ إِلَّا حَيَاتُنَا ٱلدُّنْيَا نَمُوتُ وَنَحْيَا وَمَا يُهْلِكُنَآ إِلَّا ٱلدَّهْرُ ۚ وَمَا لَهُم بِذَٰلِكَ مِنْ عِلْمٍ ۖ إِنْ هُمْ إِلَّا يَظُنُّونَ', NULL, 25, 200, 6, 501, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 25, 'وَإِذَا تُتْلَىٰ عَلَيْهِمْ ءَايَٰتُنَا بَيِّنَٰتٍۢ مَّا كَانَ حُجَّتَهُمْ إِلَّآ أَن قَالُوا۟ ٱئْتُوا۟ بِـَٔابَآئِنَآ إِن كُنتُمْ صَٰدِقِينَ', NULL, 25, 200, 6, 501, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 26, 'قُلِ ٱللَّهُ يُحْيِيكُمْ ثُمَّ يُمِيتُكُمْ ثُمَّ يَجْمَعُكُمْ إِلَىٰ يَوْمِ ٱلْقِيَٰمَةِ لَا رَيْبَ فِيهِ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ', NULL, 25, 200, 6, 501, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 27, 'وَلِلَّهِ مُلْكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ وَيَوْمَ تَقُومُ ٱلسَّاعَةُ يَوْمَئِذٍۢ يَخْسَرُ ٱلْمُبْطِلُونَ', NULL, 25, 200, 6, 501, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 28, 'وَتَرَىٰ كُلَّ أُمَّةٍۢ جَاثِيَةًۭ ۚ كُلُّ أُمَّةٍۢ تُدْعَىٰٓ إِلَىٰ كِتَٰبِهَا ٱلْيَوْمَ تُجْزَوْنَ مَا كُنتُمْ تَعْمَلُونَ', NULL, 25, 200, 6, 501, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 29, 'هَٰذَا كِتَٰبُنَا يَنطِقُ عَلَيْكُم بِٱلْحَقِّ ۚ إِنَّا كُنَّا نَسْتَنسِخُ مَا كُنتُمْ تَعْمَلُونَ', NULL, 25, 200, 6, 501, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 30, 'فَأَمَّا ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ فَيُدْخِلُهُمْ رَبُّهُمْ فِى رَحْمَتِهِۦ ۚ ذَٰلِكَ هُوَ ٱلْفَوْزُ ٱلْمُبِينُ', NULL, 25, 200, 6, 501, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 31, 'وَأَمَّا ٱلَّذِينَ كَفَرُوٓا۟ أَفَلَمْ تَكُنْ ءَايَٰتِى تُتْلَىٰ عَلَيْكُمْ فَٱسْتَكْبَرْتُمْ وَكُنتُمْ قَوْمًۭا مُّجْرِمِينَ', NULL, 25, 200, 6, 501, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 32, 'وَإِذَا قِيلَ إِنَّ وَعْدَ ٱللَّهِ حَقٌّۭ وَٱلسَّاعَةُ لَا رَيْبَ فِيهَا قُلْتُم مَّا نَدْرِى مَا ٱلسَّاعَةُ إِن نَّظُنُّ إِلَّا ظَنًّۭا وَمَا نَحْنُ بِمُسْتَيْقِنِينَ', NULL, 25, 200, 6, 501, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 33, 'وَبَدَا لَهُمْ سَيِّـَٔاتُ مَا عَمِلُوا۟ وَحَاقَ بِهِم مَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ', NULL, 25, 200, 6, 502, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 34, 'وَقِيلَ ٱلْيَوْمَ نَنسَىٰكُمْ كَمَا نَسِيتُمْ لِقَآءَ يَوْمِكُمْ هَٰذَا وَمَأْوَىٰكُمُ ٱلنَّارُ وَمَا لَكُم مِّن نَّٰصِرِينَ', NULL, 25, 200, 6, 502, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 35, 'ذَٰلِكُم بِأَنَّكُمُ ٱتَّخَذْتُمْ ءَايَٰتِ ٱللَّهِ هُزُوًۭا وَغَرَّتْكُمُ ٱلْحَيَوٰةُ ٱلدُّنْيَا ۚ فَٱلْيَوْمَ لَا يُخْرَجُونَ مِنْهَا وَلَا هُمْ يُسْتَعْتَبُونَ', NULL, 25, 200, 6, 502, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 36, 'فَلِلَّهِ ٱلْحَمْدُ رَبِّ ٱلسَّمَٰوَٰتِ وَرَبِّ ٱلْأَرْضِ رَبِّ ٱلْعَٰلَمِينَ', NULL, 25, 200, 6, 502, false, NOW(), NOW()),
((SELECT id FROM mst_surah WHERE surah_number = 45), 37, 'وَلَهُ ٱلْكِبْرِيَآءُ فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ', NULL, 25, 200, 6, 502, false, NOW(), NOW());
